fn select_env_api_key(canonical: Option<String>, legacy: Option<String>) -> Option<String> {
    canonical
        .filter(|value| !value.is_empty())
        .or_else(|| legacy.filter(|value| !value.is_empty()))
}

impl AppState {
    #[must_use]
    pub fn with_api_key(mut self, api_key: impl Into<String>) -> Self {
        self.api_key = Some(Arc::new(api_key.into()));
        self
    }

    #[must_use]
    pub fn env_api_key() -> Option<String> {
        select_env_api_key(
            std::env::var("RTH_API_KEY").ok(),
            std::env::var("RCH_API_KEY").ok(),
        )
    }

    #[must_use]
    pub fn with_optional_api_key(self, api_key: Option<String>) -> Self {
        if let Some(value) = api_key {
            self.with_api_key(value)
        } else {
            self
        }
    }

    #[must_use]
    pub fn with_system_status_fanout_mode(mut self, mode: impl AsRef<str>) -> Self {
        self.system_status_fanout_mode = SystemStatusFanoutMode::from_config(mode.as_ref());
        self
    }

    #[must_use]
    pub fn env_system_status_fanout_mode() -> Option<String> {
        std::env::var("RTH_WS_STATUS_FANOUT_MODE")
            .ok()
            .filter(|value| !value.trim().is_empty())
            .or_else(|| {
                std::env::var("RCH_WS_STATUS_FANOUT_MODE")
                    .ok()
                    .filter(|value| !value.trim().is_empty())
            })
    }

    #[must_use]
    pub fn with_optional_system_status_fanout_mode(self, mode: Option<String>) -> Self {
        if let Some(value) = mode {
            self.with_system_status_fanout_mode(value)
        } else {
            self
        }
    }

    #[must_use]
    pub fn with_config_path(mut self, path: impl AsRef<FsPath>) -> Self {
        self.config_path = Some(Arc::new(path.as_ref().to_path_buf()));
        self
    }

    #[must_use]
    pub fn with_reticulum_config_path(mut self, path: impl AsRef<FsPath>) -> Self {
        self.reticulum_config_path = Some(Arc::new(path.as_ref().to_path_buf()));
        self
    }

    pub fn with_ui_dist_path(mut self, path: impl AsRef<FsPath>) -> Self {
        self.ui_dist_path = Some(Arc::new(path.as_ref().to_path_buf()));
        self
    }

    #[must_use]
    pub fn with_reticulumd_rpc(
        mut self,
        endpoint: impl Into<String>,
        source: impl Into<String>,
    ) -> Self {
        self.reticulumd_rpc_endpoint = Some(Arc::new(endpoint.into()));
        self.reticulumd_source = Some(Arc::new(source.into()));
        self
    }

    #[must_use]
    pub fn with_outbound_identity_allowlist<I, S>(mut self, identities: I) -> Self
    where
        I: IntoIterator<Item = S>,
        S: AsRef<str>,
    {
        let identities = identities
            .into_iter()
            .filter_map(|identity| normalize_identity_key(identity.as_ref()))
            .collect::<HashSet<_>>();
        self.outbound_identity_allowlist = if identities.is_empty() {
            None
        } else {
            Some(Arc::new(identities))
        };
        self
    }

    #[must_use]
    pub fn with_managed_reticulumd(
        self,
        exe_path: impl AsRef<FsPath>,
        endpoint: impl Into<String>,
        db_path: Option<impl Into<String>>,
        config_path: Option<impl AsRef<FsPath>>,
    ) -> Self {
        if let Ok(mut managed) = self.managed_reticulumd.write() {
            managed.configured = true;
            managed.exe_path = Some(exe_path.as_ref().to_path_buf());
            managed.config_path = config_path.map(|path| path.as_ref().to_path_buf());
            managed.endpoint = Some(endpoint.into());
            managed.zmq_command_endpoint = None;
            managed.db_path = db_path.map(Into::into);
            managed.transport = None;
            managed.running = false;
            managed.pid = None;
            managed.started_ts_ms = None;
            managed.stopped_ts_ms = None;
        }
        self
    }

    #[must_use]
    pub fn with_managed_reticulumd_transport(self, transport: Option<impl Into<String>>) -> Self {
        if let Ok(mut managed) = self.managed_reticulumd.write() {
            managed.transport = transport.map(Into::into);
        }
        self
    }

    #[must_use]
    pub fn with_lxmf_zmq_sdk(
        mut self,
        command_endpoint: impl Into<String>,
        response_endpoint: impl Into<String>,
        source: impl Into<String>,
    ) -> Self {
        self.lxmf_zmq_command_endpoint = Some(Arc::new(command_endpoint.into()));
        self.lxmf_zmq_response_endpoint = Some(Arc::new(response_endpoint.into()));
        self.reticulumd_source = Some(Arc::new(source.into()));
        self
    }

    #[must_use]
    pub fn with_managed_reticulumd_zmq(
        self,
        exe_path: impl AsRef<FsPath>,
        command_endpoint: impl Into<String>,
        db_path: Option<impl Into<String>>,
        config_path: Option<impl AsRef<FsPath>>,
    ) -> Self {
        if let Ok(mut managed) = self.managed_reticulumd.write() {
            managed.configured = true;
            managed.exe_path = Some(exe_path.as_ref().to_path_buf());
            managed.config_path = config_path.map(|path| path.as_ref().to_path_buf());
            managed.endpoint = None;
            managed.zmq_command_endpoint = Some(command_endpoint.into());
            managed.db_path = db_path.map(Into::into);
            managed.transport = None;
            managed.running = false;
            managed.pid = None;
            managed.started_ts_ms = None;
            managed.stopped_ts_ms = None;
        }
        self
    }

    pub fn start_managed_reticulumd(&self) -> Result<Option<u32>, String> {
        let launch = self
            .managed_reticulumd
            .read()
            .map_err(|error| error.to_string())?
            .clone();
        if !launch.configured {
            return Ok(None);
        }
        let exe_path = launch
            .exe_path
            .as_ref()
            .ok_or_else(|| "managed reticulumd executable path missing".to_string())?;
        let endpoint = launch.endpoint.as_deref();
        let zmq_command_endpoint = launch.zmq_command_endpoint.as_deref();
        if endpoint.is_none() && zmq_command_endpoint.is_none() {
            return Err("managed reticulumd endpoint missing".to_string());
        }
        let mut process = self
            .managed_reticulumd_process
            .lock()
            .map_err(|error| error.to_string())?;
        if let Some(child) = process.as_mut() {
            match child.try_wait() {
                Ok(Some(_status)) => {
                    *process = None;
                }
                Ok(None) => {
                    self.mark_managed_reticulumd_started(child.id());
                    return Ok(Some(child.id()));
                }
                Err(error) => return Err(error.to_string()),
            }
        }
        let mut command = Command::new(exe_path);
        if let Some(zmq_command_endpoint) = zmq_command_endpoint {
            command.arg("--zmq-rpc-command").arg(zmq_command_endpoint);
        } else if let Some(endpoint) = endpoint {
            command.arg("--rpc").arg(endpoint);
        }
        command
            .stdin(Stdio::null())
            .stdout(Stdio::null())
            .stderr(Stdio::null());
        if std::env::var_os("LXMF_DISPLAY_NAME").is_none() {
            command.env("LXMF_DISPLAY_NAME", "RCH Rust");
        }
        if std::env::var_os("LXMF_RCH_ANNOUNCE_CAPABILITIES").is_none() {
            command.env(
                "LXMF_RCH_ANNOUNCE_CAPABILITIES",
                "r3akt,topic_broker,group_chat,attachments,telemetry_relay,tak_bridge",
            );
        }
        if let Some(path) = &launch.db_path {
            command.arg("--db").arg(path);
        }
        if let Some(path) = &launch.config_path {
            command.arg("--config").arg(path);
        }
        if let Some(transport) = &launch.transport {
            command.arg("--transport").arg(transport);
        }
        let child = command.spawn().map_err(|error| error.to_string())?;
        let pid = child.id();
        *process = Some(child);
        self.mark_managed_reticulumd_started(pid);
        Ok(Some(pid))
    }

    pub fn stop_managed_reticulumd(&self) -> Result<(), String> {
        let mut process = self
            .managed_reticulumd_process
            .lock()
            .map_err(|error| error.to_string())?;
        if let Some(child) = process.as_mut() {
            match child.try_wait() {
                Ok(Some(_status)) => {}
                Ok(None) => {
                    child.kill().map_err(|error| error.to_string())?;
                    let _ = child.wait();
                }
                Err(error) => return Err(error.to_string()),
            }
        }
        *process = None;
        self.mark_managed_reticulumd_stopped();
        Ok(())
    }

    fn mark_managed_reticulumd_started(&self, pid: u32) {
        if let Ok(mut managed) = self.managed_reticulumd.write() {
            managed.configured = true;
            managed.pid = Some(pid);
            managed.running = true;
            managed.started_ts_ms = Some(unix_now_ms());
            managed.stopped_ts_ms = None;
        }
    }

    fn mark_managed_reticulumd_stopped(&self) {
        if let Ok(mut managed) = self.managed_reticulumd.write() {
            managed.running = false;
            managed.stopped_ts_ms = Some(unix_now_ms());
        }
    }

    pub fn from_sqlite_path(
        path: impl AsRef<FsPath>,
    ) -> Result<Self, r3akt_rch_core::RchCoreError> {
        let path = path.as_ref().to_path_buf();
        let store = RchSqliteStore::open(&path)?;
        let snapshot = store.load_snapshot()?;
        let mut state = Self {
            messages: Arc::default(),
            sqlite_path: Some(Arc::new(path)),
            ..Self::default()
        };
        if let Some(snapshot) = snapshot {
            state.topics = Arc::new(RwLock::new(
                snapshot
                    .topics
                    .into_iter()
                    .map(|topic| {
                        let record = TopicRecord::from(topic);
                        (record.topic_id.clone(), record)
                    })
                    .collect(),
            ));
            state.subscribers = Arc::new(RwLock::new(
                snapshot
                    .subscribers
                    .into_iter()
                    .map(|subscriber| {
                        let record = SubscriberRecord::from(subscriber);
                        (record.subscriber_id.clone(), record)
                    })
                    .collect(),
            ));
            state.clients = Arc::new(RwLock::new(
                snapshot
                    .clients
                    .into_iter()
                    .map(|client| {
                        let record = ClientRecord::from(client);
                        (record.identity.clone(), record)
                    })
                    .collect(),
            ));
            state.identity_states = Arc::new(RwLock::new(
                snapshot
                    .identity_states
                    .into_iter()
                    .map(|identity_state| {
                        let record = IdentityStatusRecord::from(identity_state);
                        (record.identity_key(), record)
                    })
                    .collect(),
            ));
            state.markers = Arc::new(RwLock::new(
                snapshot
                    .markers
                    .into_iter()
                    .map(|marker| {
                        let record = MarkerRecord::from(marker);
                        (record.object_destination_hash.clone(), record)
                    })
                    .collect(),
            ));
            state.zones = Arc::new(RwLock::new(
                snapshot
                    .zones
                    .into_iter()
                    .map(|zone| {
                        let record = ZoneRecord::from(zone);
                        (record.zone_id.clone(), record)
                    })
                    .collect(),
            ));
            state.messages = Arc::new(RwLock::new(
                snapshot
                    .messages
                    .into_iter()
                    .map(OutboundMessageRecord::from)
                    .collect(),
            ));
            state.system_events = Arc::new(RwLock::new(snapshot.system_events));
            state.telemetry_records = Arc::new(RwLock::new(snapshot.telemetry_records));
        }
        Ok(state)
    }

    #[cfg(test)]
    fn persist(&self) -> Result<(), ApiError> {
        let Some(path) = &self.sqlite_path else {
            return Ok(());
        };
        let topics = self
            .topics
            .read()
            .map_err(|error| ApiError::Internal(error.to_string()))?
            .values()
            .cloned()
            .collect::<Vec<_>>();
        let subscribers = self
            .subscribers
            .read()
            .map_err(|error| ApiError::Internal(error.to_string()))?
            .values()
            .cloned()
            .collect::<Vec<_>>();
        let clients = self
            .clients
            .read()
            .map_err(|error| ApiError::Internal(error.to_string()))?
            .values()
            .cloned()
            .collect::<Vec<_>>();
        let identity_states = self
            .identity_states
            .read()
            .map_err(|error| ApiError::Internal(error.to_string()))?
            .values()
            .cloned()
            .collect::<Vec<_>>();
        let markers = self
            .markers
            .read()
            .map_err(|error| ApiError::Internal(error.to_string()))?
            .values()
            .cloned()
            .collect::<Vec<_>>();
        let zones = self
            .zones
            .read()
            .map_err(|error| ApiError::Internal(error.to_string()))?
            .values()
            .cloned()
            .collect::<Vec<_>>();
        let messages = self
            .messages
            .read()
            .map_err(|error| ApiError::Internal(error.to_string()))?
            .clone();
        let system_events = self
            .system_events
            .read()
            .map_err(|error| ApiError::Internal(error.to_string()))?
            .clone();
        let telemetry_records = self
            .telemetry_records
            .read()
            .map_err(|error| ApiError::Internal(error.to_string()))?
            .clone();
        let _sqlite_guard = lock_rch_sqlite_snapshot(self)?;
        let mut store = RchSqliteStore::open_admin(path.as_ref())
            .map_err(|error| ApiError::Internal(error.to_string()))?;
        let mut snapshot = store
            .load_snapshot_without_identity_announces()
            .map_err(|error| ApiError::Internal(error.to_string()))?
            .unwrap_or_else(|| RchCore::new().snapshot());
        snapshot.topics = topics.into_iter().map(CoreTopicRecord::from).collect();
        snapshot.subscribers = subscribers
            .into_iter()
            .map(CoreSubscriberRecord::from)
            .collect();
        snapshot.clients = clients.into_iter().map(CoreClientRecord::from).collect();
        snapshot.identity_states = identity_states
            .into_iter()
            .map(CoreIdentityStateRecord::from)
            .collect();
        snapshot.markers = markers.into_iter().map(CoreMarkerRecord::from).collect();
        snapshot.zones = zones.into_iter().map(CoreZoneRecord::from).collect();
        snapshot.messages = messages.into_iter().map(CoreMessageRecord::from).collect();
        snapshot.system_events = system_events;
        snapshot.telemetry_records = telemetry_records;
        store
            .save_snapshot_preserving_identity_announces(&snapshot)
            .map_err(|error| ApiError::Internal(error.to_string()))
    }

    pub fn record_telemetry(
        &self,
        peer_destination: impl Into<String>,
        telemetry: Value,
        timestamp_s: i64,
        display_name: Option<String>,
    ) -> Result<TelemetryRecord, ApiError> {
        let display_name = normalize_optional_text(display_name);
        let record = TelemetryRecord {
            peer_destination: peer_destination.into(),
            timestamp_s,
            telemetry,
            identity_label: display_name.clone(),
            display_name,
        };
        let mut records = self
            .telemetry_records
            .write()
            .map_err(|error| ApiError::Internal(error.to_string()))?;
        records.push(record.clone());
        if records.len() > 1000 {
            let overflow = records.len() - 1000;
            records.drain(0..overflow);
        }
        drop(records);
        persist_telemetry_record_row(self, &record)?;
        broadcast_telemetry_event(self, &record);
        Ok(record)
    }

    fn attachment_storage_path(&self, category: &str) -> Result<PathBuf, ApiError> {
        let dirname = match category {
            "file" => "files",
            "image" => "images",
            _ => return Err(ApiError::BadRequest("unsupported category".to_string())),
        };
        if let Ok(storage_dir) = std::env::var("RTH_STORAGE_DIR") {
            let storage_dir = storage_dir.trim();
            if !storage_dir.is_empty() {
                return Ok(PathBuf::from(storage_dir).join(dirname));
            }
        }
        if let Some(path) = &self.sqlite_path {
            if let Some(parent) = path.parent() {
                return Ok(parent.join(dirname));
            }
        }
        std::env::current_dir()
            .map(|path| path.join("RTH_Store").join(dirname))
            .map_err(|error| ApiError::Internal(error.to_string()))
    }

    fn validate_http_headers(&self, headers: &HeaderMap, client_addr: Option<SocketAddr>) -> bool {
        if is_local_client_addr(client_addr) {
            return true;
        }
        let Some(expected) = &self.api_key else {
            return client_addr.is_none();
        };
        let api_key = headers
            .get("X-API-Key")
            .and_then(|value| value.to_str().ok());
        if api_key == Some(expected.as_str()) {
            return true;
        }
        bearer_token(headers) == Some(expected.as_str())
    }

    fn http_auth_failure_detail(&self, client_addr: Option<SocketAddr>) -> &'static str {
        if self.api_key.is_none() && !is_local_client_addr(client_addr) {
            "Remote access requires authentication; set RTH_API_KEY (RCH_API_KEY is also supported)."
        } else {
            "Unauthorized"
        }
    }

    fn validate_ws_credentials(
        &self,
        api_key: Option<&str>,
        token: Option<&str>,
        client_addr: Option<SocketAddr>,
    ) -> bool {
        if is_local_client_addr(client_addr) {
            return true;
        }
        let Some(expected) = &self.api_key else {
            return client_addr.is_none();
        };
        api_key == Some(expected.as_str()) || token == Some(expected.as_str())
    }

    fn ws_auth_failure_detail(&self, client_addr: Option<SocketAddr>) -> &'static str {
        self.http_auth_failure_detail(client_addr)
    }
}

