#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
pub struct ClientRecord {
    pub identity: String,
    pub last_seen: String,
    pub display_name: Option<String>,
    pub metadata: Value,
    pub client_type: String,
    pub announce_capabilities: Vec<String>,
    pub rem_mode: Option<String>,
    pub is_rem_capable: bool,
}

impl ClientRecord {
    fn new(identity: String, last_seen_ts_ms: i64) -> Self {
        Self {
            identity,
            last_seen: iso8601_from_unix_ms(last_seen_ts_ms),
            display_name: None,
            metadata: json!({}),
            client_type: "generic_lxmf".to_string(),
            announce_capabilities: Vec::new(),
            rem_mode: None,
            is_rem_capable: false,
        }
    }

    fn apply_rem_annotation(&mut self, annotation: &RemIdentityAnnotation) {
        self.last_seen = iso8601_from_unix_ms(annotation.last_seen_ts_ms);
        self.display_name.clone_from(&annotation.display_name);
        self.client_type.clone_from(&annotation.client_type);
        self.announce_capabilities
            .clone_from(&annotation.announce_capabilities);
        self.rem_mode.clone_from(&annotation.rem_mode);
        self.is_rem_capable = annotation.is_rem_capable;
        self.metadata = json!({
            "announce": {
                "destination_hash": annotation.destination_hash.clone(),
                "announced_identity_hash": annotation.announced_identity_hash.clone(),
                "source_interface": annotation.source_interface.clone(),
                "first_seen": iso8601_from_unix_ms(annotation.first_seen_ts_ms),
                "last_seen": iso8601_from_unix_ms(annotation.last_seen_ts_ms),
            }
        });
    }
}

impl From<CoreClientRecord> for ClientRecord {
    fn from(client: CoreClientRecord) -> Self {
        Self::new(client.identity, client.last_seen_ts_ms)
    }
}

impl From<ClientRecord> for CoreClientRecord {
    fn from(client: ClientRecord) -> Self {
        let last_seen_ts_ms = unix_ms_from_iso8601(&client.last_seen).unwrap_or_else(unix_now_ms);
        Self {
            identity: client.identity,
            first_seen_ts_ms: last_seen_ts_ms,
            last_seen_ts_ms,
        }
    }
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct IdentityStatusRecord {
    identity: String,
    is_banned: bool,
    is_blackholed: bool,
    updated_ts_ms: i64,
}

impl IdentityStatusRecord {
    fn identity_key(&self) -> String {
        normalize_identity_key(&self.identity).unwrap_or_else(|| self.identity.clone())
    }

    fn status(&self, is_announced: bool) -> &'static str {
        if self.is_blackholed {
            "blackholed"
        } else if self.is_banned {
            "banned"
        } else if is_announced {
            "active"
        } else {
            "inactive"
        }
    }

    fn to_python_value(&self, annotation: Option<&RemIdentityAnnotation>) -> Value {
        let display_name = annotation.and_then(|value| value.display_name.clone());
        let client_type = annotation
            .map(|value| value.client_type.clone())
            .unwrap_or_else(|| "generic_lxmf".to_string());
        let announce_capabilities = annotation
            .map(|value| value.announce_capabilities.clone())
            .unwrap_or_default();
        let rem_mode = annotation.and_then(|value| value.rem_mode.clone());
        let is_rem_capable = annotation.is_some_and(|value| value.is_rem_capable);
        let is_announced = annotation.is_some();
        let announce_first_seen =
            annotation.map(|value| iso8601_from_unix_ms(value.first_seen_ts_ms));
        let announce_last_seen =
            annotation.map(|value| iso8601_from_unix_ms(value.last_seen_ts_ms));
        let announce_destination_hash = annotation.map(|value| value.destination_hash.clone());
        let announced_identity_hash =
            annotation.and_then(|value| value.announced_identity_hash.clone());
        let announce_source = annotation.and_then(|value| value.source_interface.clone());
        let metadata = annotation
            .map(|value| {
                json!({
                    "announce": {
                        "destination_hash": value.destination_hash.clone(),
                        "announced_identity_hash": value.announced_identity_hash.clone(),
                        "source_interface": value.source_interface.clone(),
                        "first_seen": iso8601_from_unix_ms(value.first_seen_ts_ms),
                        "last_seen": iso8601_from_unix_ms(value.last_seen_ts_ms),
                    }
                })
            })
            .unwrap_or_else(|| json!({}));
        json!({
            "Identity": self.identity,
            "DisplayName": display_name,
            "Status": self.status(is_announced),
            "LastSeen": announce_last_seen.clone(),
            "Metadata": metadata,
            "IsBanned": self.is_banned,
            "IsBlackholed": self.is_blackholed,
            "ClientType": client_type,
            "AnnounceCapabilities": announce_capabilities,
            "RemMode": rem_mode,
            "IsRemCapable": is_rem_capable,
            "IsAnnounced": is_announced,
            "AnnounceDestinationHash": announce_destination_hash,
            "AnnouncedIdentityHash": announced_identity_hash,
            "AnnounceSource": announce_source,
            "AnnounceFirstSeen": announce_first_seen,
            "AnnounceLastSeen": announce_last_seen
        })
    }
}

