#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
pub struct OutboundMessageRecord {
    pub message_id: String,
    pub topic_id: Option<String>,
    pub destination: Option<String>,
    pub sender: String,
    pub content: String,
    pub delivery_mode: DeliveryMode,
    #[serde(default)]
    pub delivery_method: String,
    #[serde(default)]
    pub delivery_policy_reason: String,
    #[serde(default)]
    pub delivery_state: String,
    #[serde(default)]
    pub delivery_metadata: Value,
    pub created_ts_ms: i64,
    #[serde(default)]
    pub attachments: Vec<ChatAttachmentRecord>,
}

impl From<CoreMessageRecord> for OutboundMessageRecord {
    fn from(message: CoreMessageRecord) -> Self {
        Self {
            message_id: message.message_id,
            topic_id: message.topic_id,
            destination: message.destination,
            sender: message.sender,
            content: message.content,
            delivery_mode: message.delivery_mode,
            delivery_method: if message.delivery_method.is_empty() {
                "direct".to_string()
            } else {
                message.delivery_method
            },
            delivery_policy_reason: if message.delivery_policy_reason.is_empty() {
                "default_direct".to_string()
            } else {
                message.delivery_policy_reason
            },
            delivery_state: if message.delivery_state.is_empty() {
                "queued".to_string()
            } else {
                message.delivery_state
            },
            delivery_metadata: message.delivery_metadata,
            created_ts_ms: message.created_ts_ms,
            attachments: message.attachments,
        }
    }
}

impl From<OutboundMessageRecord> for CoreMessageRecord {
    fn from(message: OutboundMessageRecord) -> Self {
        Self {
            message_id: message.message_id,
            topic_id: message.topic_id,
            destination: message.destination,
            sender: message.sender,
            content: message.content,
            delivery_mode: message.delivery_mode,
            delivery_method: message.delivery_method,
            delivery_policy_reason: message.delivery_policy_reason,
            delivery_state: message.delivery_state,
            delivery_metadata: message.delivery_metadata,
            created_ts_ms: message.created_ts_ms,
            attachments: message.attachments,
        }
    }
}

