#[derive(Debug, thiserror::Error)]
pub enum ApiError {
    #[error("{0}")]
    BadRequest(String),
    #[error("{0}")]
    Unprocessable(String),
    #[error("validation error")]
    PydanticValidation(Value),
    #[error("{0}")]
    NotFound(String),
    #[error("{0}")]
    PayloadTooLarge(String),
    #[error("{0}")]
    ServiceUnavailable(String),
    #[error("Unauthorized")]
    Unauthorized,
    #[error("{0}")]
    UnauthorizedWithDetail(String),
    #[error("{0}")]
    Internal(String),
}

impl IntoResponse for ApiError {
    fn into_response(self) -> Response {
        let status = match &self {
            Self::BadRequest(_) => StatusCode::BAD_REQUEST,
            Self::Unprocessable(_) | Self::PydanticValidation(_) => {
                StatusCode::UNPROCESSABLE_ENTITY
            }
            Self::NotFound(_) => StatusCode::NOT_FOUND,
            Self::PayloadTooLarge(_) => StatusCode::PAYLOAD_TOO_LARGE,
            Self::ServiceUnavailable(_) => StatusCode::SERVICE_UNAVAILABLE,
            Self::Unauthorized | Self::UnauthorizedWithDetail(_) => StatusCode::UNAUTHORIZED,
            Self::Internal(_) => StatusCode::INTERNAL_SERVER_ERROR,
        };
        if let Self::PydanticValidation(payload) = self {
            return (status, Json(payload)).into_response();
        }
        (
            status,
            Json(ErrorBody {
                detail: self.to_string(),
            }),
        )
            .into_response()
    }
}

#[must_use]
pub fn create_app() -> Router {
    create_app_with_state(AppState::default())
}

#[must_use]
pub fn create_app_with_state(state: AppState) -> Router {
    create_app_router(state)
}

#[must_use]
pub fn create_app_with_state_and_ui_dist_path(state: AppState, ui_dist_path: PathBuf) -> Router {
    let fallback_ui_dist_path = ui_dist_path.clone();
    create_app_router(state.with_ui_dist_path(&ui_dist_path))
        .nest_service("/assets", ServeDir::new(ui_dist_path.join("assets")))
        .nest_service("/help", ServeDir::new(ui_dist_path.join("help")))
        .nest_service("/icons", ServeDir::new(ui_dist_path.join("icons")))
        .route_service(
            "/favicon.ico",
            ServeFile::new(ui_dist_path.join("favicon.ico")),
        )
        .route_service("/RCH.png", ServeFile::new(ui_dist_path.join("RCH.png")))
        .route_service(
            "/RCH_small.png",
            ServeFile::new(ui_dist_path.join("RCH_small.png")),
        )
        .route_service(
            "/RCH_vector.svg",
            ServeFile::new(ui_dist_path.join("RCH_vector.svg")),
        )
        .fallback(move || {
            let ui_dist_path = fallback_ui_dist_path.clone();
            async move { ui_index_response_from_path(&ui_dist_path) }
        })
}

