fn cors_layer() -> CorsLayer {
    CorsLayer::new()
        .allow_origin(Any)
        .allow_methods(Any)
        .allow_headers(Any)
        .max_age(Duration::from_secs(86_400))
}

async fn require_http_auth(
    State(state): State<AppState>,
    request: Request,
    next: Next,
) -> Response {
    if is_ui_html_navigation(&state, &request) {
        return next.run(request).await;
    }
    if request.method() == axum::http::Method::GET
        && method_not_allowed_allowed_methods(request.uri().path()).is_some()
    {
        let query_string = request.uri().query().map(ToString::to_string);
        return normalize_framework_rejection(next.run(request).await, query_string.as_deref())
            .await;
    }
    let client_addr = request_client_addr(&request);
    if state.validate_http_headers(request.headers(), client_addr) {
        let query_string = request.uri().query().map(ToString::to_string);
        return normalize_framework_rejection(next.run(request).await, query_string.as_deref())
            .await;
    }
    ApiError::UnauthorizedWithDetail(state.http_auth_failure_detail(client_addr).to_string())
        .into_response()
}

async fn normalize_framework_rejection(response: Response, query_string: Option<&str>) -> Response {
    if response.status() == StatusCode::UNSUPPORTED_MEDIA_TYPE {
        return python_model_attributes_rejection(json!({}));
    }
    if response.status() == StatusCode::UNPROCESSABLE_ENTITY && !is_json_response(&response) {
        let body_text = rejection_body_text(response).await;
        if body_text.contains("invalid type: null") {
            return python_missing_body_rejection();
        }
        return python_model_attributes_rejection(json!({}));
    }
    if response.status() != StatusCode::BAD_REQUEST || is_json_response(&response) {
        return response;
    }
    let body_text = rejection_body_text(response).await;
    if body_text.contains("Failed to deserialize query string") {
        return python_query_parse_rejection(&body_text, query_string);
    }
    (
        StatusCode::UNPROCESSABLE_ENTITY,
        Json(json!({
            "detail": [{
                "type": "json_invalid",
                "loc": ["body", 1],
                "msg": "JSON decode error",
                "input": {},
                "ctx": {"error": "Invalid JSON"}
            }]
        })),
    )
        .into_response()
}

async fn rejection_body_text(response: Response) -> String {
    let body = response.into_body();
    let bytes = to_bytes(body, 64 * 1024).await.unwrap_or_default();
    String::from_utf8_lossy(&bytes).to_string()
}

fn python_model_attributes_rejection(input: Value) -> Response {
    (
        StatusCode::UNPROCESSABLE_ENTITY,
        Json(python_model_attributes_body(input)),
    )
        .into_response()
}

fn python_model_attributes_body(input: Value) -> Value {
    json!({
        "detail": [{
            "type": "model_attributes_type",
            "loc": ["body"],
            "msg": "Input should be a valid dictionary or object to extract fields from",
            "input": input
        }]
    })
}

fn python_missing_body_rejection() -> Response {
    (
        StatusCode::UNPROCESSABLE_ENTITY,
        Json(python_missing_body_body()),
    )
        .into_response()
}

fn python_missing_body_body() -> Value {
    json!({
        "detail": [{
            "type": "missing",
            "loc": ["body"],
            "msg": "Field required",
            "input": null
        }]
    })
}

