fn python_int_parsing_body(field: &str, input: Value) -> Value {
    json!({
        "detail": [{
            "type": "int_parsing",
            "loc": ["body", field],
            "msg": "Input should be a valid integer, unable to parse string as an integer",
            "input": input
        }]
    })
}

fn python_query_parse_rejection(body_text: &str, query_string: Option<&str>) -> Response {
    let field = body_text
        .split_once('`')
        .and_then(|(_, rest)| rest.split_once('`').map(|(field, _)| field))
        .or_else(|| first_query_field(query_string))
        .unwrap_or("query");
    (
        StatusCode::UNPROCESSABLE_ENTITY,
        Json(json!({
            "detail": [{
                "type": "int_parsing",
                "loc": ["query", field],
                "msg": "Input should be a valid integer, unable to parse string as an integer",
                "input": ""
            }]
        })),
    )
        .into_response()
}

fn first_query_field(query_string: Option<&str>) -> Option<&str> {
    query_string?
        .split('&')
        .find_map(|part| part.split_once('=').map(|(field, _)| field).or(Some(part)))
        .filter(|field| !field.is_empty())
}

fn is_json_response(response: &Response) -> bool {
    response
        .headers()
        .get(header::CONTENT_TYPE)
        .and_then(|value| value.to_str().ok())
        .is_some_and(|value| value.starts_with("application/json"))
}

fn request_client_addr(request: &Request) -> Option<SocketAddr> {
    request
        .extensions()
        .get::<ConnectInfo<SocketAddr>>()
        .map(|ConnectInfo(addr)| *addr)
}

fn is_local_client_addr(client_addr: Option<SocketAddr>) -> bool {
    match client_addr.map(|addr| addr.ip()) {
        Some(IpAddr::V4(addr)) => addr.is_loopback(),
        Some(IpAddr::V6(addr)) => {
            addr.is_loopback()
                || addr
                    .to_ipv4_mapped()
                    .is_some_and(|mapped| mapped.is_loopback())
        }
        None => false,
    }
}

fn is_ui_html_navigation(state: &AppState, request: &Request) -> bool {
    state.ui_dist_path.is_some()
        && request.method() == axum::http::Method::GET
        && request.uri().path() == "/checklists"
        && accepts_html(request.headers())
}

