fn openapi_websocket_operation(
    scope: &str,
    summary: &str,
    description: &str,
    protected: bool,
    server_messages: &[&str],
    client_messages: &[&str],
) -> Value {
    let mut operation = json!({
        "x-scope": scope,
        "x-websocket": true,
        "tags": ["WebSocket"],
        "summary": summary,
        "description": description,
        "x-ws-protocol": "rch-ws-v1",
        "x-ws-server-messages": openapi_schema_refs(server_messages),
        "x-ws-client-messages": openapi_schema_refs(client_messages),
        "responses": {
            "101": {
                "description": "Switching Protocols (WebSocket upgrade)."
            }
        }
    });
    if protected {
        operation["security"] = json!([
            { "bearerAuth": [] },
            { "apiKeyAuth": [] }
        ]);
    }
    operation
}

