fn command_help_text() -> String {
    let mut lines = vec![
        "# Command list".to_string(),
        String::new(),
        "Use the `Command` field (`0`) for legacy/plugin payloads or `command_type` in mission-style envelopes carried in `FIELD_COMMANDS` (`0x09`).".to_string(),
        "Tip: tag file/image attachments with a `TopicID` or send `AssociateTopicID` to link them to a topic.".to_string(),
        String::new(),
    ];
    push_command_section(
        &mut lines,
        "Legacy/plugin commands",
        LEGACY_SOUTHBOUND_COMMANDS,
    );
    push_command_section(
        &mut lines,
        "R3AKT mission-sync commands",
        MISSION_SYNC_COMMANDS,
    );
    push_command_section(
        &mut lines,
        "R3AKT checklist commands",
        CHECKLIST_SYNC_COMMANDS,
    );
    push_command_section(&mut lines, "REM registry commands", REM_REGISTRY_COMMANDS);
    lines.push("- `TelemetryRequest` (`1`)".to_string());
    lines.push(String::new());
    lines.join("\n")
}

fn supported_commands_document() -> String {
    let mut lines = vec![
        "# Supported LXMF Southbound Commands".to_string(),
        String::new(),
        "This document lists command families accepted by RCH over the LXMF southbound interface.".to_string(),
        String::new(),
        "Legacy/plugin commands use `FIELD_COMMANDS` (`0x09`) with a `Command` value.".to_string(),
        "Mission-sync, checklist, and REM registry commands use the mission envelope schema and select behavior with `command_type`.".to_string(),
        String::new(),
        "## Transport formats".to_string(),
        String::new(),
        "Legacy/plugin example:".to_string(),
        String::new(),
        "```json".to_string(),
        r#"[{"Command":"ListTopic"}]"#.to_string(),
        "```".to_string(),
        String::new(),
        "Mission-style envelope example:".to_string(),
        String::new(),
        "```json".to_string(),
        r#"[{"command_id":"cmd-123","source":{"rns_identity":"<sender identity>"},"timestamp":"2026-03-06T12:00:00Z","command_type":"mission.registry.mission.list","args":{},"topics":[]}]"#.to_string(),
        "```".to_string(),
        String::new(),
        "Telemetry request example:".to_string(),
        String::new(),
        "```json".to_string(),
        r#"[{"1":1700000000,"TopicID":"<optional topic id>"}]"#.to_string(),
        "```".to_string(),
        String::new(),
        "## Command inventory".to_string(),
        String::new(),
    ];
    push_command_section(
        &mut lines,
        "Legacy/plugin commands",
        LEGACY_SOUTHBOUND_COMMANDS,
    );
    push_command_section(
        &mut lines,
        "R3AKT mission-sync LXMF commands",
        MISSION_SYNC_COMMANDS,
    );
    push_command_section(
        &mut lines,
        "R3AKT checklist LXMF commands",
        CHECKLIST_SYNC_COMMANDS,
    );
    push_command_section(
        &mut lines,
        "REM peer registry and mode control",
        REM_REGISTRY_COMMANDS,
    );
    lines.extend([
        "- `TelemetryRequest` (`1`)".to_string(),
        String::new(),
        "REM registry commands require announce capabilities `r3akt` and `emergencymessages`."
            .to_string(),
        "`rem.registry.mode.set` accepts `autonomous`, `semi_autonomous`, or `connected`."
            .to_string(),
        "`rem.registry.peers.list` returns active REM peers and `effective_connected_mode`."
            .to_string(),
        String::new(),
    ]);
    lines.join("\n")
}

fn push_command_section(lines: &mut Vec<String>, title: &str, commands: &[&str]) {
    lines.push(format!("## {title}"));
    lines.push(String::new());
    for command in commands {
        lines.push(format!("- `{command}`"));
    }
    lines.push(String::new());
}

async fn app_info(State(state): State<AppState>) -> Json<Value> {
    Json(app_info_payload(&state))
}

fn app_info_payload(state: &AppState) -> Value {
    let database_path = state
        .sqlite_path
        .as_ref()
        .map_or_else(String::new, |path| path.display().to_string());
    let storage_root = app_info_storage_root(state);
    let storage_path = storage_root.display().to_string();
    let reticulum_config_path = state
        .reticulum_config_path
        .as_ref()
        .map_or_else(String::new, |path| path.display().to_string());
    let file_storage_path = state.config_path.as_ref().map_or_else(
        || storage_root.join("files"),
        |path| {
            config_section_value(path.as_ref(), "files", &["path", "directory"])
                .map_or_else(|| storage_root.join("files"), PathBuf::from)
        },
    );
    let image_storage_path = state.config_path.as_ref().map_or_else(
        || storage_root.join("images"),
        |path| {
            config_section_value(path.as_ref(), "images", &["path", "directory"])
                .map_or_else(|| storage_root.join("images"), PathBuf::from)
        },
    );
    let file_storage_path = file_storage_path.display().to_string();
    let image_storage_path = image_storage_path.display().to_string();
    let reticulum_destination = state
        .reticulumd_source
        .as_deref()
        .and_then(|value| normalize_reticulum_destination_for_app_info(value));
    let hub_display_name = resolve_hub_display_name_for_app_info(
        state
            .config_path
            .as_ref()
            .and_then(|path| config_section_value(path.as_ref(), "hub", &["display_name"])),
        reticulum_destination.as_deref(),
    );
    let has_reticulum_runtime = state.reticulumd_rpc_endpoint.is_some();
    json!({
        "is_transport_enabled": has_reticulum_runtime,
        "is_connected_to_shared_instance": has_reticulum_runtime,
        "reticulum_config_path": reticulum_config_path,
        "database_path": database_path,
        "storage_path": storage_path,
        "file_storage_path": file_storage_path,
        "image_storage_path": image_storage_path,
        "app_name": "ReticulumCommunityHub",
        "rns_version": "",
        "lxmf_version": "",
        "app_version": "northbound",
        "app_description": "Rust UI-facing Reticulum Community Hub runtime",
        "hub_display_name": hub_display_name,
        "reticulum_destination": reticulum_destination,
        "name": "ReticulumCommunityHub",
        "version": "northbound",
        "description": "Rust UI-facing Reticulum Community Hub runtime",
        "display_name": hub_display_name,
        "storage_paths": {
            "storage": storage_path,
            "database": database_path,
            "reticulum_config": reticulum_config_path,
            "files": file_storage_path,
            "images": image_storage_path
        }
    })
}

fn resolve_hub_display_name_for_app_info(
    configured: Option<String>,
    reticulum_destination: Option<&str>,
) -> String {
    normalize_optional_text(configured).unwrap_or_else(|| {
        format!(
            "RCH_northbound_{}",
            reticulum_destination.unwrap_or("unknown")
        )
    })
}

fn normalize_reticulum_destination_for_app_info(value: &str) -> Option<String> {
    let candidate = value.trim().trim_start_matches("0x").to_ascii_lowercase();
    if candidate.is_empty()
        || candidate.len() % 2 != 0
        || !candidate.chars().all(|ch| ch.is_ascii_hexdigit())
    {
        return None;
    }
    Some(candidate)
}

fn app_info_storage_root(state: &AppState) -> PathBuf {
    state.config_path.as_ref().map_or_else(
        || std::env::current_dir().unwrap_or_else(|_| PathBuf::new()),
        |path| path.parent().map_or_else(PathBuf::new, FsPath::to_path_buf),
    )
}

fn config_section_value(path: &FsPath, section: &str, keys: &[&str]) -> Option<String> {
    let content = std::fs::read_to_string(path).ok()?;
    let mut in_section = false;
    for line in content.lines() {
        let line = line.trim();
        if line.is_empty() || line.starts_with('#') || line.starts_with(';') {
            continue;
        }
        if line.starts_with('[') && line.ends_with(']') {
            in_section = line[1..line.len() - 1].eq_ignore_ascii_case(section);
            continue;
        }
        if !in_section {
            continue;
        }
        let Some((candidate_key, value)) = line.split_once('=') else {
            continue;
        };
        if keys
            .iter()
            .any(|key| candidate_key.trim().eq_ignore_ascii_case(key))
        {
            return normalize_optional_text(Some(value.trim().to_string()));
        }
    }
    None
}

async fn internal_list_topics(
    State(state): State<AppState>,
    Query(query): Query<InternalTopicQuery>,
) -> Result<Json<Value>, ApiError> {
    let prefix = normalize_optional_text(query.prefix);
    let topics = state
        .topics
        .read()
        .map_err(|error| ApiError::Internal(error.to_string()))?;
    let mut topic_ids = topics
        .values()
        .filter(|topic| {
            prefix.as_ref().is_none_or(|prefix| {
                topic.topic_id.starts_with(prefix) || topic.topic_path.starts_with(prefix)
            })
        })
        .map(|topic| topic.topic_id.clone())
        .collect::<Vec<_>>();
    topic_ids.sort();
    Ok(Json(json!(topic_ids)))
}

async fn internal_list_subscribers(
    State(state): State<AppState>,
    Path(topic_id): Path<String>,
) -> Result<Json<Value>, ApiError> {
    let mut destinations = topic_subscriber_destinations(&state, &topic_id)?;
    destinations.sort();
    destinations.dedup();
    Ok(Json(json!(destinations)))
}

async fn internal_node_status(
    State(state): State<AppState>,
    Path(node_id): Path<String>,
) -> Result<Json<Value>, ApiError> {
    let subscribers = state
        .subscribers
        .read()
        .map_err(|error| ApiError::Internal(error.to_string()))?;
    let mut topics = subscribers
        .values()
        .filter(|subscriber| subscriber.destination == node_id)
        .map(|subscriber| subscriber.topic_id.clone())
        .collect::<Vec<_>>();
    topics.sort();
    topics.dedup();
    Ok(Json(json!({
        "node_id": node_id,
        "online": false,
        "topics": topics
    })))
}

async fn internal_post_message(
    State(state): State<AppState>,
    Json(payload): Json<InternalMessagePayload>,
) -> Result<Json<Value>, ApiError> {
    let topic_id = payload.destination.trim();
    if topic_id.is_empty() {
        return Err(ApiError::BadRequest("destination is required".to_string()));
    }
    let text = payload.text.trim();
    if text.is_empty() {
        return Err(ApiError::BadRequest("text is required".to_string()));
    }
    let message = record_outbound_message(
        &state,
        text,
        Some(topic_id.to_string()),
        None,
        Vec::new(),
        false,
    )?;
    let _ = state.internal_events.send(internal_message_published_event(
        topic_id,
        &message.message_id,
    ));
    Ok(Json(json!({ "accepted": true })))
}

async fn internal_delivery_receipt(
    State(state): State<AppState>,
    Json(payload): Json<InternalDeliveryReceiptPayload>,
) -> Result<Json<Value>, ApiError> {
    let acknowledgement_type = payload
        .acknowledgement_type
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or("delivery_receipt");
    let is_propagated = acknowledgement_type == "propagation_acceptance";
    let delivered_state = if is_propagated {
        "propagated"
    } else {
        "delivered"
    };
    let now_ms = unix_now_ms();
    let message = {
        let mut messages = state
            .messages
            .write()
            .map_err(|error| ApiError::Internal(error.to_string()))?;
        let message = messages
            .iter_mut()
            .find(|message| {
                payload
                    .message_id
                    .as_deref()
                    .is_some_and(|message_id| message.message_id == message_id)
                    || payload.destination.as_deref().is_some_and(|destination| {
                        message.destination.as_deref() == Some(destination)
                            && delivery_receipt_pending(message)
                    })
            })
            .ok_or_else(|| ApiError::NotFound("Pending delivery receipt not found".to_string()))?;
        message.delivery_state = delivered_state.to_string();
        merge_delivery_metadata(
            &mut message.delivery_metadata,
            json!({
                "acked": true,
                "receipt_pending": false,
                "receipt_ack_ts_ms": now_ms,
                "acknowledgement_type": acknowledgement_type,
                "receipt_timeout": false,
            }),
        );
        message.clone()
    };
    persist_outbound_message_row(&state, &message)?;
    broadcast_message_event(&state, &message);
    let destination = message.destination.as_deref().unwrap_or("unknown");
    let event_type = if is_propagated {
        "message_propagated"
    } else {
        "message_delivered"
    };
    let event_message = if is_propagated {
        format!("Message accepted for propagation to {destination}")
    } else {
        format!("Message delivered to {destination}")
    };
    let event = record_system_event(
        &state,
        event_type,
        &event_message,
        outbound_delivery_callback_metadata(
            outbound_delivery_receipt_metadata(&message, acknowledgement_type),
            "delivery_receipt",
        ),
    )?;
    Ok(Json(json!({
        "status": delivered_state,
        "message": message,
        "event": event,
    })))
}

async fn internal_delivery_failure(
    State(state): State<AppState>,
    Json(payload): Json<InternalDeliveryFailurePayload>,
) -> Result<Json<Value>, ApiError> {
    let reason = payload
        .reason
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or("delivery_failed");
    let now_ms = unix_now_ms();
    let message = {
        let mut messages = state
            .messages
            .write()
            .map_err(|error| ApiError::Internal(error.to_string()))?;
        let message = messages
            .iter_mut()
            .find(|message| {
                payload
                    .message_id
                    .as_deref()
                    .is_some_and(|message_id| message.message_id == message_id)
                    || payload.destination.as_deref().is_some_and(|destination| {
                        message.destination.as_deref() == Some(destination)
                            && delivery_receipt_pending(message)
                    })
            })
            .ok_or_else(|| ApiError::NotFound("Pending delivery receipt not found".to_string()))?;
        message.delivery_state = "failed".to_string();
        merge_delivery_metadata(
            &mut message.delivery_metadata,
            json!({
                "acked": false,
                "dispatch_status": "failed",
                "error": reason,
                "receipt_pending": false,
                "delivery_failed_ts_ms": now_ms,
            }),
        );
        message.clone()
    };
    persist_outbound_message_row(&state, &message)?;
    broadcast_message_event(&state, &message);
    let destination = message.destination.as_deref().unwrap_or("unknown");
    let event = record_system_event(
        &state,
        "message_delivery_failed",
        &format!("Message delivery failed for {destination}"),
        outbound_delivery_callback_metadata(
            outbound_delivery_failure_metadata(&message, reason),
            "delivery_failure",
        ),
    )?;
    Ok(Json(json!({
        "status": "failed",
        "message": message,
        "event": event,
    })))
}

async fn internal_delivery_retry(
    State(state): State<AppState>,
    Json(payload): Json<InternalDeliveryRetryPayload>,
) -> Result<Json<Value>, ApiError> {
    let reason = payload
        .reason
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or("delivery_retry");
    let now_ms = unix_now_ms();
    let message = {
        let mut messages = state
            .messages
            .write()
            .map_err(|error| ApiError::Internal(error.to_string()))?;
        let message = messages
            .iter_mut()
            .find(|message| {
                payload
                    .message_id
                    .as_deref()
                    .is_some_and(|message_id| message.message_id == message_id)
                    || payload.destination.as_deref().is_some_and(|destination| {
                        message.destination.as_deref() == Some(destination)
                            && delivery_receipt_pending(message)
                    })
            })
            .ok_or_else(|| ApiError::NotFound("Pending delivery retry not found".to_string()))?;
        let attempts = payload.attempts.unwrap_or_else(|| {
            message
                .delivery_metadata
                .get("attempts")
                .and_then(Value::as_u64)
                .unwrap_or(0)
                .saturating_add(1)
        });
        message.delivery_state = "queued".to_string();
        merge_delivery_metadata(
            &mut message.delivery_metadata,
            json!({
                "acked": false,
                "attempts": attempts,
                "dispatch_status": "queued",
                "retry_scheduled": true,
                "retry_reason": reason,
                "last_attempt_failed_at_ts_ms": now_ms,
                "receipt_pending": false,
                "receipt_timeout": false,
                "next_attempt_at_ts_ms": payload.next_attempt_at_ts_ms,
            }),
        );
        message.clone()
    };
    persist_outbound_message_row(&state, &message)?;
    broadcast_message_event(&state, &message);
    let destination = message.destination.as_deref().unwrap_or("unknown");
    let event = record_system_event(
        &state,
        "message_delivery_retrying",
        &format!("Retrying message delivery to {destination}"),
        outbound_delivery_callback_metadata(
            outbound_delivery_retry_metadata(&message, reason),
            "delivery_retry",
        ),
    )?;
    Ok(Json(json!({
        "status": "retry_scheduled",
        "message": message,
        "event": event,
    })))
}

async fn internal_delivery_propagation(
    State(state): State<AppState>,
    Json(payload): Json<InternalDeliveryPropagationPayload>,
) -> Result<Json<Value>, ApiError> {
    let reason = payload
        .reason
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .unwrap_or("direct_delivery_failed");
    let local_propagation_fallback = payload.local_propagation_fallback.unwrap_or(false);
    let message = {
        let mut messages = state
            .messages
            .write()
            .map_err(|error| ApiError::Internal(error.to_string()))?;
        let message = messages
            .iter_mut()
            .find(|message| {
                payload
                    .message_id
                    .as_deref()
                    .is_some_and(|message_id| message.message_id == message_id)
                    || payload.destination.as_deref().is_some_and(|destination| {
                        message.destination.as_deref() == Some(destination)
                    })
            })
            .ok_or_else(|| {
                ApiError::NotFound("Pending propagation fallback not found".to_string())
            })?;
        let attempts = payload.attempts.unwrap_or_else(|| {
            message
                .delivery_metadata
                .get("attempts")
                .and_then(Value::as_u64)
                .unwrap_or(0)
        });
        message.delivery_state = "queued".to_string();
        message.delivery_method = "propagated".to_string();
        merge_delivery_metadata(
            &mut message.delivery_metadata,
            json!({
                "acked": false,
                "attempts": attempts,
                "delivery_mode": "propagated",
                "dispatch_status": "queued",
                "fallback_reason": reason,
                "local_propagation_fallback": local_propagation_fallback,
                "propagation_node_hex": payload.propagation_node_hex,
                "receipt_pending": false,
                "retry_scheduled": false,
            }),
        );
        message.clone()
    };
    persist_outbound_message_row(&state, &message)?;
    broadcast_message_event(&state, &message);
    let destination = message.destination.as_deref().unwrap_or("unknown");
    let event_message = if local_propagation_fallback {
        format!("Direct delivery exhausted; stored message for local propagation to {destination}")
    } else {
        let node = message
            .delivery_metadata
            .get("propagation_node_hex")
            .and_then(Value::as_str)
            .filter(|value| !value.is_empty())
            .unwrap_or("unknown");
        format!(
            "Direct delivery exhausted; queued message for propagation to {destination} via {node}"
        )
    };
    let event = record_system_event(
        &state,
        "message_propagation_queued",
        &event_message,
        outbound_delivery_callback_metadata(
            outbound_delivery_propagation_metadata(&message, reason),
            "propagation_fallback",
        ),
    )?;
    Ok(Json(json!({
        "status": "propagation_queued",
        "message": message,
        "event": event,
    })))
}

