fn normalize_chat_peer_name(value: &str) -> Option<String> {
    let value = value.trim().replace("%20", " ");
    let value = value.trim();
    if value.is_empty() {
        None
    } else {
        Some(value.to_ascii_lowercase())
    }
}

fn destination_excluded(excluded: &[String], requested: &str, delivery: &str) -> bool {
    excluded
        .iter()
        .any(|value| value == requested || value == delivery)
}

fn excluded_outbound_destinations(message: &OutboundMessageRecord) -> Vec<String> {
    message
        .delivery_metadata
        .get("exclude_destinations")
        .and_then(Value::as_array)
        .map(|values| {
            values
                .iter()
                .filter_map(Value::as_str)
                .map(str::trim)
                .filter(|value| !value.is_empty())
                .map(ToString::to_string)
                .collect::<Vec<_>>()
        })
        .unwrap_or_default()
}

fn push_unique_destination(destinations: &mut Vec<String>, destination: String) {
    if !destination.trim().is_empty()
        && !destinations
            .iter()
            .any(|existing| existing.as_str() == destination.as_str())
    {
        destinations.push(destination);
    }
}

fn push_unique_destination_with_seen(
    destinations: &mut Vec<String>,
    seen_destinations: &mut HashSet<String>,
    destination: String,
) {
    if destination.trim().is_empty() {
        return;
    }
    if seen_destinations.insert(destination.clone()) {
        destinations.push(destination);
    }
}

fn with_core_store_write(
    state: &AppState,
    operation: impl FnOnce(&mut RchSqliteStore) -> Result<(), r3akt_rch_core::RchCoreError>,
) -> Result<(), ApiError> {
    let Some(path) = &state.sqlite_path else {
        return Ok(());
    };
    let started = Instant::now();
    let mut store = RchSqliteStore::open(path.as_ref())
        .map_err(|error| ApiError::Internal(error.to_string()))?;
    let result = operation(&mut store).map_err(|error| ApiError::Internal(error.to_string()));
    record_sqlite_latency(state, started.elapsed());
    result
}

fn with_required_core_store_write<T>(
    state: &AppState,
    operation: impl FnOnce(&mut RchSqliteStore) -> Result<T, r3akt_rch_core::RchCoreError>,
) -> Result<T, ApiError> {
    let path = state
        .sqlite_path
        .as_ref()
        .ok_or_else(|| ApiError::ServiceUnavailable("RCH SQLite state unavailable".to_string()))?;
    let started = Instant::now();
    let mut store = RchSqliteStore::open(path.as_ref())
        .map_err(|error| ApiError::Internal(error.to_string()))?;
    let result = operation(&mut store).map_err(|error| ApiError::Internal(error.to_string()));
    record_sqlite_latency(state, started.elapsed());
    result
}

