fn command_fanout_recipients_for_state(state: &AppState) -> Result<Vec<ClientRecord>, ApiError> {
    let client_records = state
        .clients
        .read()
        .map_err(|error| ApiError::Internal(error.to_string()))?
        .values()
        .cloned()
        .collect::<Vec<_>>();
    let annotation_destinations = client_records
        .iter()
        .filter_map(|record| normalize_identity_key(&record.identity))
        .collect::<Vec<_>>();
    let annotations = rem_annotations_for_destinations(state, &annotation_destinations)?;
    let runtime_freshness_cutoff_ms = rem_peer_runtime_freshness_cutoff_ms(state);
    let mut recipients = Vec::new();
    let mut recipient_identities = HashSet::new();

    for record in identity_display_records_for_annotations(&client_records, &annotations) {
        let Some(destination) = normalize_identity_key(&record.identity) else {
            continue;
        };
        if !recipient_identities.insert(destination.clone()) {
            continue;
        }
        if runtime_freshness_cutoff_ms.is_some()
            && !annotations
                .get(destination.as_str())
                .is_some_and(|annotation| {
                    runtime_freshness_cutoff_ms
                        .is_none_or(|cutoff_ms| annotation.last_seen_ts_ms >= cutoff_ms)
                })
        {
            continue;
        }
        recipients.push(client_record_from_annotation_or_identity(
            destination,
            &annotations,
        ));
    }

    Ok(recipients)
}

fn client_record_from_annotation_or_identity(
    identity: String,
    annotations: &HashMap<String, RemIdentityAnnotation>,
) -> ClientRecord {
    if let Some(annotation) = annotations.get(&identity) {
        let mut record = ClientRecord::new(identity, annotation.last_seen_ts_ms);
        record.apply_rem_annotation(annotation);
        record
    } else {
        ClientRecord::new(identity, unix_now_ms())
    }
}

#[cfg(test)]
struct MissionDeltaNameResolver<'a> {
    snapshot: Option<&'a r3akt_rch_core::RchCoreSnapshot>,
}

#[cfg(test)]
impl<'a> MissionDeltaNameResolver<'a> {
    fn new(snapshot: Option<&'a r3akt_rch_core::RchCoreSnapshot>) -> Self {
        Self { snapshot }
    }

    fn mission_name(&self, mission_uid: &str) -> String {
        self.snapshot
            .and_then(|snapshot| {
                snapshot
                    .missions
                    .iter()
                    .find(|mission| mission.uid == mission_uid)
            })
            .map(|mission| mission.mission_name.trim())
            .filter(|name| !name.is_empty())
            .unwrap_or(mission_uid)
            .to_string()
    }

    fn task_label(&self, checklist_uid: Option<&Value>, task_uid: Option<&Value>) -> String {
        let checklist_uid = clean_markdown_text(checklist_uid);
        let task_uid = clean_markdown_text(task_uid);
        let Some(task_uid) = task_uid.as_deref() else {
            return "Checklist task".to_string();
        };
        let Some(snapshot) = self.snapshot else {
            return "Checklist task".to_string();
        };
        let task = snapshot.checklist_tasks.iter().find(|task| {
            task.task_uid == task_uid
                && checklist_uid
                    .as_deref()
                    .is_none_or(|checklist_uid| task.checklist_uid == checklist_uid)
        });
        let Some(task) = task else {
            return "Checklist task".to_string();
        };
        if let Some(label) = task
            .notes
            .as_deref()
            .map(str::trim)
            .filter(|v| !v.is_empty())
        {
            return label.to_string();
        }
        if let Some(label) = task
            .legacy_value
            .as_deref()
            .map(str::trim)
            .filter(|v| !v.is_empty())
        {
            return label.to_string();
        }
        let short_string_columns = snapshot
            .checklist_columns
            .iter()
            .filter(|column| {
                column.checklist_uid.as_deref() == Some(&task.checklist_uid)
                    && column.column_type.eq_ignore_ascii_case("SHORT_STRING")
            })
            .map(|column| column.column_uid.as_str())
            .collect::<Vec<_>>();
        snapshot
            .checklist_cells
            .iter()
            .find(|cell| {
                cell.task_uid == task.task_uid
                    && short_string_columns
                        .iter()
                        .any(|column_uid| *column_uid == cell.column_uid)
            })
            .and_then(|cell| cell.value.as_deref())
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map_or_else(
                || format!("Checklist task #{}", task.number),
                ToString::to_string,
            )
    }

    fn checklist_name(&self, checklist_uid: Option<&Value>) -> String {
        let checklist_uid = clean_markdown_text(checklist_uid);
        let Some(checklist_uid) = checklist_uid.as_deref() else {
            return "Checklist".to_string();
        };
        self.snapshot
            .and_then(|snapshot| {
                snapshot
                    .checklists
                    .iter()
                    .find(|checklist| checklist.uid == checklist_uid)
            })
            .map(|checklist| checklist.name.trim())
            .filter(|name| !name.is_empty())
            .unwrap_or(checklist_uid)
            .to_string()
    }

    fn column_name(&self, checklist_uid: Option<&Value>, column_uid: Option<&Value>) -> String {
        let checklist_uid = clean_markdown_text(checklist_uid);
        let column_uid = clean_markdown_text(column_uid);
        let Some(column_uid) = column_uid.as_deref() else {
            return "field".to_string();
        };
        self.snapshot
            .and_then(|snapshot| {
                snapshot.checklist_columns.iter().find(|column| {
                    column.column_uid == column_uid
                        && checklist_uid.as_deref().is_none_or(|checklist_uid| {
                            column.checklist_uid.as_deref() == Some(checklist_uid)
                        })
                })
            })
            .map(|column| column.column_name.trim())
            .filter(|name| !name.is_empty())
            .unwrap_or("field")
            .to_string()
    }

    fn asset_name(&self, asset_uid: Option<&Value>, fallback_name: Option<&Value>) -> String {
        if let Some(fallback) = clean_markdown_text(fallback_name) {
            return fallback;
        }
        let asset_uid = clean_markdown_text(asset_uid);
        let Some(asset_uid) = asset_uid.as_deref() else {
            return "asset".to_string();
        };
        self.snapshot
            .and_then(|snapshot| {
                snapshot
                    .assets
                    .iter()
                    .find(|asset| asset.asset_uid == asset_uid)
            })
            .map(|asset| asset.name.trim())
            .filter(|name| !name.is_empty())
            .unwrap_or("asset")
            .to_string()
    }

    fn team_member_name_from_identity(
        &self,
        mission_uid: &str,
        identity: Option<&Value>,
    ) -> Option<String> {
        let identity = clean_markdown_text(identity)?.to_ascii_lowercase();
        let snapshot = self.snapshot?;
        let team_uids = mission_team_uids(snapshot, mission_uid);
        snapshot
            .team_members
            .iter()
            .find(|member| {
                member.rns_identity.eq_ignore_ascii_case(&identity)
                    && member
                        .team_uid
                        .as_deref()
                        .is_some_and(|team_uid| team_uids.iter().any(|uid| uid == team_uid))
            })
            .and_then(team_member_display_name)
    }

    fn team_member_name_from_uid(
        &self,
        mission_uid: &str,
        team_member_uid: Option<&Value>,
    ) -> Option<String> {
        let team_member_uid = clean_markdown_text(team_member_uid)?;
        let snapshot = self.snapshot?;
        let team_uids = mission_team_uids(snapshot, mission_uid);
        snapshot
            .team_members
            .iter()
            .find(|member| {
                member.uid == team_member_uid
                    && member
                        .team_uid
                        .as_deref()
                        .is_some_and(|team_uid| team_uids.iter().any(|uid| uid == team_uid))
            })
            .and_then(team_member_display_name)
    }
}

#[cfg(test)]
fn mission_team_uids(snapshot: &r3akt_rch_core::RchCoreSnapshot, mission_uid: &str) -> Vec<String> {
    let mut team_uids = Vec::new();
    for team in &snapshot.teams {
        let linked = team.mission_uid.as_deref() == Some(mission_uid)
            || team.mission_uids.iter().any(|uid| uid == mission_uid)
            || snapshot
                .mission_team_links
                .iter()
                .any(|link| link.mission_uid == mission_uid && link.team_uid == team.uid);
        if linked && !team_uids.contains(&team.uid) {
            team_uids.push(team.uid.clone());
        }
    }
    team_uids
}

#[cfg(test)]
fn team_member_display_name(member: &r3akt_rch_core::TeamMemberRecord) -> Option<String> {
    for value in [
        member.display_name.as_str(),
        member.callsign.as_deref().unwrap_or_default(),
        member.uid.as_str(),
    ] {
        let value = value.trim();
        if !value.is_empty() {
            return Some(value.to_string());
        }
    }
    None
}

#[cfg(test)]
fn generic_mission_delta_markdown(
    mission_uid: &str,
    change: &Value,
    snapshot: Option<&r3akt_rch_core::RchCoreSnapshot>,
) -> String {
    let resolver = MissionDeltaNameResolver::new(snapshot);
    let delta = change.get("delta").unwrap_or(&Value::Null);
    let header = if mission_uid.trim().is_empty() {
        "### Checklist Update".to_string()
    } else {
        format!(
            "### Mission {}",
            clip_text(&resolver.mission_name(mission_uid), 120)
        )
    };
    if let Some(log) = delta
        .get("logs")
        .and_then(Value::as_array)
        .and_then(|logs| logs.first())
        .and_then(Value::as_object)
    {
        let mission = log
            .get("mission_uid")
            .and_then(Value::as_str)
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .unwrap_or(mission_uid);
        let callsign =
            clean_markdown_text(log.get("callsign")).unwrap_or_else(|| "Unknown".to_string());
        let content =
            clean_markdown_text(log.get("content")).unwrap_or_else(|| "(empty)".to_string());
        return format!(
            "### Mission Log Update\nMission: {}\n\nFrom: {}\n\n{}",
            clip_text(mission, 120),
            clip_text(&callsign, 80),
            clip_text(&content, 180)
        );
    }
    if let Some(asset) = delta
        .get("assets")
        .and_then(Value::as_array)
        .and_then(|assets| assets.first())
        .and_then(Value::as_object)
    {
        let op = asset
            .get("op")
            .and_then(Value::as_str)
            .unwrap_or_default()
            .trim()
            .to_ascii_lowercase();
        let update = if op == "delete" {
            "Asset removed"
        } else {
            "Asset updated"
        };
        let asset_name = resolver.asset_name(asset.get("asset_uid"), asset.get("name"));
        let asset_type = clean_markdown_text(asset.get("asset_type"));
        let status = if op == "delete" {
            None
        } else {
            clean_markdown_text(asset.get("status"))
        };
        let mut detail_suffix_parts = Vec::new();
        if let Some(asset_type) = asset_type {
            detail_suffix_parts.push(clip_text(&asset_type, 20));
        }
        if let Some(status) = status {
            detail_suffix_parts.push(clip_text(&status, 20));
        }
        let detail_suffix = if detail_suffix_parts.is_empty() {
            String::new()
        } else {
            format!(" ({})", detail_suffix_parts.join(", "))
        };
        let mut lines = vec![
            header,
            format!("- Update: {update}"),
            format!("- Detail: {}{}", clip_text(&asset_name, 80), detail_suffix),
        ];
        if let Some(team_member_name) =
            resolver.team_member_name_from_uid(mission_uid, asset.get("team_member_uid"))
        {
            lines.push(format!("- Assigned: {}", clip_text(&team_member_name, 48)));
        }
        if let Some(location) = clean_markdown_text(asset.get("location")) {
            lines.push(format!("- Location: {}", clip_text(&location, 96)));
        }
        return lines.join("\n");
    }
    if let Some(task) = delta
        .get("tasks")
        .and_then(Value::as_array)
        .and_then(|tasks| tasks.first())
        .and_then(Value::as_object)
    {
        let task_label = clean_markdown_text(task.get("notes"))
            .or_else(|| clean_markdown_text(task.get("legacy_value")))
            .or_else(|| Some(resolver.task_label(task.get("checklist_uid"), task.get("task_uid"))))
            .unwrap_or_else(|| "Checklist task".to_string());
        let checklist_name = resolver.checklist_name(task.get("checklist_uid"));
        let op = task
            .get("op")
            .and_then(Value::as_str)
            .unwrap_or_default()
            .trim()
            .to_ascii_lowercase();
        return match op.as_str() {
            "status_set" => {
                let previous = clean_markdown_text(task.get("previous_status"))
                    .unwrap_or_else(|| "UNKNOWN".to_string());
                let current = clean_markdown_text(task.get("current_status"))
                    .or_else(|| clean_markdown_text(task.get("user_status")))
                    .unwrap_or_else(|| "UNKNOWN".to_string());
                let action = if current.eq_ignore_ascii_case("COMPLETE") {
                    format!("Task {} completed", clip_text(&task_label, 80))
                } else if current.eq_ignore_ascii_case("PENDING") {
                    format!("Task {} marked pending", clip_text(&task_label, 80))
                } else {
                    format!(
                        "Task {} status changed to {}",
                        clip_text(&task_label, 80),
                        clip_text(&current, 24)
                    )
                };
                format!(
                    "{header}\n{action}\n- Checklist: {}\n- Status: {} -> {}",
                    clip_text(&checklist_name, 80),
                    previous,
                    current
                )
            }
            "cell_set" => {
                let column =
                    resolver.column_name(task.get("checklist_uid"), task.get("column_uid"));
                let value =
                    clean_markdown_text(task.get("value")).unwrap_or_else(|| "(empty)".to_string());
                format!(
                    "{header}\nTask {} updated\n- Checklist: {}\n- Field: {} = {}",
                    clip_text(&task_label, 80),
                    clip_text(&checklist_name, 80),
                    clip_text(&column, 48),
                    clip_text(&value, 100)
                )
            }
            "row_style_set" => format!(
                "{header}\nTask {} style updated\n- Checklist: {}",
                clip_text(&task_label, 80),
                clip_text(&checklist_name, 80)
            ),
            "row_added" => format!(
                "{header}\nTask {} added\n- Checklist: {}",
                clip_text(&task_label, 80),
                clip_text(&checklist_name, 80)
            ),
            "row_deleted" => format!(
                "{header}\nTask {} deleted\n- Checklist: {}",
                clip_text(&task_label, 80),
                clip_text(&checklist_name, 80)
            ),
            "assignment_upsert" => {
                let assignee = resolver
                    .team_member_name_from_identity(
                        mission_uid,
                        task.get("team_member_rns_identity"),
                    )
                    .unwrap_or_else(|| "Unknown team member".to_string());
                let status = clean_markdown_text(task.get("status"))
                    .unwrap_or_else(|| "UNKNOWN".to_string())
                    .to_ascii_uppercase();
                let mut lines = vec![
                    header,
                    "- Update: Assignment updated".to_string(),
                    format!(
                        "- Detail: {} -> {}",
                        clip_text(&task_label, 80),
                        clip_text(&assignee, 48)
                    ),
                    format!("- Status: {status}"),
                ];
                if let Some(assets) = task.get("assets").and_then(Value::as_array) {
                    let labels = assets
                        .iter()
                        .take(3)
                        .map(|asset_uid| resolver.asset_name(Some(asset_uid), None))
                        .map(|name| clip_text(&name, 24))
                        .collect::<Vec<_>>();
                    if !labels.is_empty() {
                        lines.push(format!("- Assets: {}", labels.join(", ")));
                    }
                    if assets.len() > 3 {
                        lines.push(format!("- Assets total: {}", assets.len()));
                    }
                }
                lines.join("\n")
            }
            "assignment_assets_set" => {
                let mut lines = vec![
                    header,
                    "- Update: Assignment asset set replaced".to_string(),
                    format!("- Detail: {}", clip_text(&task_label, 80)),
                ];
                if let Some(assets) = task.get("assets").and_then(Value::as_array) {
                    let labels = assets
                        .iter()
                        .take(3)
                        .map(|asset_uid| resolver.asset_name(Some(asset_uid), None))
                        .map(|name| clip_text(&name, 24))
                        .collect::<Vec<_>>();
                    if !labels.is_empty() {
                        lines.push(format!("- Assets: {}", labels.join(", ")));
                    }
                    if assets.len() > 3 {
                        lines.push(format!("- Assets total: {}", assets.len()));
                    }
                }
                lines.join("\n")
            }
            "assignment_asset_linked" | "assignment_asset_unlinked" => {
                let update = if op == "assignment_asset_linked" {
                    "Assignment asset linked"
                } else {
                    "Assignment asset removed"
                };
                let asset_name = resolver.asset_name(task.get("asset_uid"), None);
                format!(
                    "{header}\n- Update: {update}\n- Detail: {}\n- Asset: {}",
                    clip_text(&task_label, 80),
                    clip_text(&asset_name, 48)
                )
            }
            _ => format!(
                "{header}\n- Update: Mission content updated\n- Detail: Additional details unavailable on this link"
            ),
        };
    }
    if let Some(checklist) = delta
        .get("checklists")
        .and_then(Value::as_array)
        .and_then(|checklists| checklists.first())
        .and_then(Value::as_object)
    {
        let checklist_name = clean_markdown_text(checklist.get("name"))
            .or_else(|| clean_markdown_text(checklist.get("uid")))
            .unwrap_or_else(|| "Checklist".to_string());
        let source_event_type = delta
            .get("source_event_type")
            .and_then(Value::as_str)
            .unwrap_or_default();
        let update = match source_event_type {
            "mission.checklist.created" => format!("Checklist {checklist_name} created"),
            "mission.checklist.uploaded" => format!("Checklist {checklist_name} uploaded"),
            _ => format!("Checklist {checklist_name} updated"),
        };
        let task_count = checklist
            .get("tasks")
            .and_then(Value::as_array)
            .map(Vec::len)
            .or_else(|| {
                checklist
                    .get("expected_task_count")
                    .and_then(Value::as_u64)
                    .and_then(|value| usize::try_from(value).ok())
            })
            .unwrap_or(0);
        let mut lines = vec![
            header,
            clip_text(&update, 120),
            format!("- Checklist: {}", clip_text(&checklist_name, 80)),
        ];
        if task_count > 0 {
            lines.push(format!("- Tasks: {task_count}"));
        }
        if let Some(tasks) = checklist.get("tasks").and_then(Value::as_array) {
            for task in tasks.iter().take(3).filter_map(Value::as_object) {
                let task_label = clean_markdown_text(task.get("notes"))
                    .or_else(|| clean_markdown_text(task.get("legacy_value")))
                    .or_else(|| clean_markdown_text(task.get("task_uid")))
                    .unwrap_or_else(|| "Checklist task".to_string());
                lines.push(format!("- Task: {}", clip_text(&task_label, 80)));
            }
            if tasks.len() > 3 {
                lines.push(format!("- Additional tasks: {}", tasks.len() - 3));
            }
        }
        return lines.join("\n");
    }
    if let Some(notes) = clean_markdown_text(change.get("notes")) {
        return format!("{header}\n- Content: {}", clip_text(&notes, 180));
    }
    let change_type = change
        .get("change_type")
        .and_then(Value::as_str)
        .unwrap_or("Mission content updated");
    format!("{header}\n- Change: {change_type}")
}

#[cfg(test)]
fn clean_markdown_text(value: Option<&Value>) -> Option<String> {
    let text = match value {
        Some(Value::String(text)) => text.trim().to_string(),
        Some(Value::Number(number)) => number.to_string(),
        Some(Value::Bool(value)) => value.to_string(),
        _ => return None,
    };
    if text.is_empty() { None } else { Some(text) }
}

#[cfg(test)]
fn clip_text(text: &str, max_chars: usize) -> String {
    text.chars().take(max_chars).collect()
}

#[derive(Debug, Clone)]
struct RemChecklistFanoutMessage {
    body: String,
    fields: Value,
}

#[cfg(test)]
const LXMF_FIELDS_MSGPACK_B64_KEY: &str = "_lxmf_fields_msgpack_b64";
const REM_COMMAND_PLACEHOLDER_BODY: &str = "cmd";

#[cfg(test)]
fn rem_checklist_command_body(
    _command_type: &str,
    _args: &Value,
    _source: Option<&serde_json::Map<String, Value>>,
) -> &'static str {
    REM_COMMAND_PLACEHOLDER_BODY
}

fn rem_checklist_command_messages_for_mission_change(
    state: &AppState,
    mission_uid: &str,
    mission_change_uid: &str,
    change: &Value,
    participant_rns_identities: &[String],
) -> Vec<RemChecklistFanoutMessage> {
    let delta = change.get("delta").and_then(Value::as_object);
    let source_event_type = delta
        .and_then(|delta| delta.get("source_event_type"))
        .and_then(Value::as_str)
        .or_else(|| change.get("name").and_then(Value::as_str))
        .unwrap_or_default();
    let Some(delta) = delta else {
        return Vec::new();
    };

    let source_identity = state
        .reticulumd_source
        .as_ref()
        .map_or("r3akt-rch-server", |value| value.as_str());
    match source_event_type {
        "mission.checklist.task.row.added" => rem_task_messages(
            "checklist.task.row.add",
            delta.get("tasks"),
            mission_uid,
            mission_change_uid,
            source_identity,
            row_add_args,
        ),
        "mission.checklist.task.row.deleted" => rem_task_messages(
            "checklist.task.row.delete",
            delta.get("tasks"),
            mission_uid,
            mission_change_uid,
            source_identity,
            row_delete_args,
        ),
        "mission.checklist.task.row.style_set" => rem_task_messages(
            "checklist.task.row.style.set",
            delta.get("tasks"),
            mission_uid,
            mission_change_uid,
            source_identity,
            row_style_args,
        ),
        "mission.checklist.task.status_set" => rem_task_messages(
            "checklist.task.status.set",
            delta.get("tasks"),
            mission_uid,
            mission_change_uid,
            source_identity,
            status_set_args,
        ),
        "mission.checklist.task.cell_set" => rem_task_messages(
            "checklist.task.cell.set",
            delta.get("tasks"),
            mission_uid,
            mission_change_uid,
            source_identity,
            cell_set_args,
        ),
        "mission.checklist.created" => delta
            .get("checklists")
            .and_then(Value::as_array)
            .map(|checklists| {
                checklists
                    .iter()
                    .filter_map(Value::as_object)
                    .flat_map(|checklist| {
                        initial_rem_checklist_command_messages(
                            checklist,
                            mission_uid,
                            mission_change_uid,
                            source_identity,
                            participant_rns_identities,
                        )
                    })
                    .collect()
            })
            .unwrap_or_default(),
        "mission.checklist.uploaded" => delta
            .get("checklists")
            .and_then(Value::as_array)
            .map(|checklists| {
                checklists
                    .iter()
                    .filter_map(Value::as_object)
                    .filter_map(|checklist| {
                        rem_checklist_upload_command_message(
                            checklist,
                            mission_uid,
                            mission_change_uid,
                            source_identity,
                            participant_rns_identities,
                        )
                    })
                    .collect()
            })
            .unwrap_or_default(),
        _ => Vec::new(),
    }
}

fn rem_task_messages(
    command_type: &str,
    tasks: Option<&Value>,
    mission_uid: &str,
    mission_change_uid: &str,
    source_identity: &str,
    builder: fn(&serde_json::Map<String, Value>) -> Option<Value>,
) -> Vec<RemChecklistFanoutMessage> {
    tasks
        .and_then(Value::as_array)
        .into_iter()
        .flatten()
        .filter_map(Value::as_object)
        .filter_map(|task| {
            builder(task).map(|args| {
                rem_checklist_task_command_message(
                    command_type,
                    rem_args_with_mission_uid(args, mission_uid),
                    task,
                    source_identity,
                    mission_change_uid,
                )
            })
        })
        .collect()
}

fn rem_checklist_task_command_message(
    command_type: &str,
    args: Value,
    task: &serde_json::Map<String, Value>,
    source_identity: &str,
    mission_change_uid: &str,
) -> RemChecklistFanoutMessage {
    rem_checklist_task_command_message_at(
        command_type,
        args,
        task,
        source_identity,
        mission_change_uid,
        unix_now_ms(),
    )
}

fn rem_checklist_task_command_message_at(
    command_type: &str,
    args: Value,
    task: &serde_json::Map<String, Value>,
    source_identity: &str,
    mission_change_uid: &str,
    timestamp_ms: i64,
) -> RemChecklistFanoutMessage {
    let _ = task;
    rem_checklist_command_message_with_body_at(
        command_type,
        args,
        source_identity,
        mission_change_uid,
        REM_COMMAND_PLACEHOLDER_BODY.to_string(),
        timestamp_ms,
    )
}

fn rem_checklist_command_message_with_body_at(
    command_type: &str,
    args: Value,
    source_identity: &str,
    mission_change_uid: &str,
    body: String,
    timestamp_ms: i64,
) -> RemChecklistFanoutMessage {
    let command_subject = rem_command_subject(&args);
    let command_token = format!("{mission_change_uid}-{command_subject}");
    let command_id = compact_rem_command_id(command_type, &command_token);
    let envelope = json!({
        "command_id": command_id,
        "correlation_id": mission_change_uid,
        "command_type": command_type,
        "source": {
            "rns_identity": compact_rem_identifier_string(source_identity),
            "display_name": "RCH",
        },
        "timestamp": iso8601_from_unix_ms(timestamp_ms),
        "topics": rem_command_topics(&args),
        "args": clean_optional_args(args),
    });
    RemChecklistFanoutMessage {
        body,
        fields: rem_command_transport_fields(envelope),
    }
}

fn initial_rem_checklist_command_messages(
    checklist: &serde_json::Map<String, Value>,
    mission_uid: &str,
    mission_change_uid: &str,
    source_identity: &str,
    participant_rns_identities: &[String],
) -> Vec<RemChecklistFanoutMessage> {
    let checklist_uid = string_or_value(checklist.get("checklist_uid"))
        .or_else(|| string_or_value(checklist.get("uid")));
    let create_args = checklist_create_args(checklist, mission_uid, participant_rns_identities);
    let mut next_timestamp_ms = unix_now_ms();
    let mut take_timestamp_ms = || {
        let timestamp_ms = next_timestamp_ms;
        next_timestamp_ms = next_timestamp_ms.saturating_add(1);
        timestamp_ms
    };
    let mut messages = vec![rem_checklist_command_message_at(
        "checklist.create.online",
        create_args.clone(),
        source_identity,
        mission_change_uid,
        take_timestamp_ms(),
    )];
    let effective_mission_uid = create_args
        .get("mission_uid")
        .and_then(Value::as_str)
        .unwrap_or(mission_uid);
    if let Some(tasks) = checklist.get("tasks").and_then(Value::as_array) {
        for task in tasks.iter().filter_map(Value::as_object) {
            if let Some(args) = row_add_args(task) {
                messages.push(rem_checklist_task_command_message_at(
                    "checklist.task.row.add",
                    rem_args_with_checklist_and_mission_uid(
                        args,
                        checklist_uid.as_ref(),
                        effective_mission_uid,
                    ),
                    task,
                    source_identity,
                    mission_change_uid,
                    take_timestamp_ms(),
                ));
            }
            if let Some(args) = status_set_args(task) {
                if args
                    .get("user_status")
                    .and_then(serde_json::Value::as_str)
                    .is_some_and(|status| status.eq_ignore_ascii_case("COMPLETE"))
                {
                    messages.push(rem_checklist_task_command_message_at(
                        "checklist.task.status.set",
                        rem_args_with_checklist_and_mission_uid(
                            args,
                            checklist_uid.as_ref(),
                            effective_mission_uid,
                        ),
                        task,
                        source_identity,
                        mission_change_uid,
                        take_timestamp_ms(),
                    ));
                }
            }
        }
    }
    messages
}

fn rem_checklist_upload_command_message(
    checklist: &serde_json::Map<String, Value>,
    mission_uid: &str,
    mission_change_uid: &str,
    source_identity: &str,
    participant_rns_identities: &[String],
) -> Option<RemChecklistFanoutMessage> {
    let create_args = checklist_create_args(checklist, mission_uid, participant_rns_identities);
    let effective_mission_uid = create_args
        .get("mission_uid")
        .and_then(Value::as_str)
        .unwrap_or(mission_uid);
    rem_checklist_upload_command_message_at(
        checklist,
        effective_mission_uid,
        mission_change_uid,
        source_identity,
        participant_rns_identities,
        &create_args,
        unix_now_ms(),
    )
}

fn rem_checklist_command_message_at(
    command_type: &str,
    args: Value,
    source_identity: &str,
    mission_change_uid: &str,
    timestamp_ms: i64,
) -> RemChecklistFanoutMessage {
    rem_checklist_command_message_with_body_at(
        command_type,
        args,
        source_identity,
        mission_change_uid,
        REM_COMMAND_PLACEHOLDER_BODY.to_string(),
        timestamp_ms,
    )
}

fn rem_checklist_upload_command_message_at(
    checklist: &serde_json::Map<String, Value>,
    mission_uid: &str,
    mission_change_uid: &str,
    source_identity: &str,
    participant_rns_identities: &[String],
    create_args: &Value,
    timestamp_ms: i64,
) -> Option<RemChecklistFanoutMessage> {
    let checklist_uid = create_args.get("checklist_uid")?.as_str()?;
    let timestamp = iso8601_from_unix_ms(timestamp_ms);
    let snapshot = rem_checklist_snapshot_value(
        checklist,
        checklist_uid,
        mission_uid,
        source_identity,
        participant_rns_identities,
        &timestamp,
        create_args,
    );
    let snapshot_json = serde_json::to_string(&snapshot).ok()?;
    let command_subject = format!("{mission_change_uid}-{checklist_uid}");
    let command_id = compact_rem_command_id("checklist.upload", &command_subject);
    let envelope = json!( {
        "command_id": command_id,
        "correlation_id": mission_change_uid,
        "command_type": "checklist.upload",
        "source": {
            "rns_identity": compact_rem_identifier_string(source_identity),
            "display_name": "RCH",
        },
        "timestamp": timestamp,
        "topics": rem_command_topics(create_args),
        "args": {
            "checklist_uid": checklist_uid,
            "mission_uid": mission_uid,
        },
        "snapshot_json": snapshot_json,
    });
    Some(RemChecklistFanoutMessage {
        body: REM_COMMAND_PLACEHOLDER_BODY.to_string(),
        fields: rem_command_transport_fields(envelope),
    })
}

fn rem_checklist_snapshot_value(
    checklist: &serde_json::Map<String, Value>,
    checklist_uid: &str,
    mission_uid: &str,
    source_identity: &str,
    participant_rns_identities: &[String],
    timestamp: &str,
    create_args: &Value,
) -> Value {
    let columns = checklist
        .get("columns")
        .and_then(Value::as_array)
        .map(|columns| {
            columns
                .iter()
                .enumerate()
                .filter_map(|(index, column)| {
                    let column = column.as_object()?;
                    let column_uid = string_value(column.get("column_uid"))
                        .or_else(|| string_value(column.get("uid")))
                        .unwrap_or_else(|| format!("column-{}", index + 1));
                    let column_name = string_value(column.get("column_name"))
                        .or_else(|| string_value(column.get("name")))
                        .unwrap_or_else(|| "Task".to_string());
                    Some(json!({
                        "column_uid": column_uid,
                        "column_name": column_name,
                        "display_order": index + 1,
                        "column_type": column.get("column_type").and_then(Value::as_str).unwrap_or("SHORT_STRING"),
                        "column_editable": column.get("column_editable").and_then(Value::as_bool).unwrap_or(true),
                        "background_color": column.get("background_color").cloned().unwrap_or(Value::Null),
                        "text_color": column.get("text_color").cloned().unwrap_or(Value::Null),
                        "is_removable": column.get("is_removable").and_then(Value::as_bool).unwrap_or(true),
                        "system_key": column.get("system_key").cloned().unwrap_or(Value::Null),
                    }))
                })
                .collect::<Vec<_>>()
        })
        .filter(|columns| !columns.is_empty())
        .unwrap_or_else(|| {
            vec![json!({
                "column_uid": "task",
                "column_name": "Task",
                "display_order": 1,
                "column_type": "SHORT_STRING",
                "column_editable": true,
                "background_color": null,
                "text_color": null,
                "is_removable": true,
                "system_key": null,
            })]
        });
    let tasks = checklist
        .get("tasks")
        .and_then(Value::as_array)
        .map(|tasks| {
            tasks
                .iter()
                .enumerate()
                .filter_map(|(index, task)| {
                    let task = task.as_object()?;
                    let task_uid = string_value(task.get("task_uid"))
                        .or_else(|| string_value(task.get("uid")))
                        .unwrap_or_else(|| format!("{checklist_uid}-task-{}", index + 1));
                    let number = task
                        .get("number")
                        .and_then(Value::as_u64)
                        .unwrap_or((index + 1) as u64);
                    let user_status = task
                        .get("user_status")
                        .and_then(Value::as_str)
                        .filter(|value| value.eq_ignore_ascii_case("COMPLETE"))
                        .map(|_| "COMPLETE")
                        .unwrap_or("PENDING");
                    let task_status = if user_status == "COMPLETE" {
                        "COMPLETE"
                    } else {
                        "PENDING"
                    };
                    Some(json!({
                        "task_uid": task_uid,
                        "number": number,
                        "user_status": user_status,
                        "task_status": task_status,
                        "is_late": false,
                        "updated_at": task.get("updated_at").and_then(Value::as_str).unwrap_or(timestamp),
                        "deleted_at": task.get("deleted_at").cloned().unwrap_or(Value::Null),
                        "custom_status": task.get("custom_status").cloned().unwrap_or(Value::Null),
                        "due_relative_minutes": task.get("due_relative_minutes").cloned().unwrap_or(Value::Null),
                        "due_dtg": task.get("due_dtg").cloned().unwrap_or(Value::Null),
                        "notes": task.get("notes").cloned().unwrap_or(Value::Null),
                        "row_background_color": task.get("row_background_color").cloned().unwrap_or(Value::Null),
                        "line_break_enabled": task.get("line_break_enabled").and_then(Value::as_bool).unwrap_or(false),
                        "completed_at": task.get("completed_at").cloned().unwrap_or(Value::Null),
                        "completed_by_team_member_rns_identity": task.get("completed_by_team_member_rns_identity").cloned().unwrap_or(Value::Null),
                        "legacy_value": task.get("legacy_value").cloned().unwrap_or(Value::Null),
                        "cells": task.get("cells").cloned().unwrap_or_else(|| json!([])),
                    }))
                })
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();
    let complete_count = tasks
        .iter()
        .filter(|task| task.get("user_status").and_then(Value::as_str) == Some("COMPLETE"))
        .count();
    let total = tasks.len();
    let pending_count = total.saturating_sub(complete_count);
    let progress_percent = if total == 0 {
        0.0
    } else {
        let complete_count = u32::try_from(complete_count).unwrap_or(u32::MAX);
        let total = u32::try_from(total).unwrap_or(u32::MAX);
        (f64::from(complete_count) / f64::from(total)) * 100.0
    };
    let mut participants = participant_rns_identities.to_vec();
    push_unique_destination(
        &mut participants,
        compact_rem_identifier_string(source_identity),
    );
    json!({
        "uid": checklist_uid,
        "mission_uid": mission_uid,
        "template_uid": create_args.get("template_uid").cloned().unwrap_or_else(|| json!(format!("rch:{checklist_uid}:template"))),
        "template_version": checklist.get("template_version").cloned().unwrap_or(Value::Null),
        "template_name": checklist.get("template_name").cloned().unwrap_or(Value::Null),
        "name": string_value(checklist.get("name")).unwrap_or_else(|| checklist_uid.to_string()),
        "description": string_value(checklist.get("description")).unwrap_or_default(),
        "start_time": checklist.get("start_time").and_then(Value::as_str).unwrap_or(timestamp),
        "mode": "ONLINE",
        "sync_state": "SYNCED",
        "origin_type": "RCH_TEMPLATE",
        "checklist_status": if pending_count == 0 && total > 0 { "COMPLETE" } else { "PENDING" },
        "created_at": checklist.get("created_at").and_then(Value::as_str).unwrap_or(timestamp),
        "created_by_team_member_rns_identity": compact_rem_identifier_string(source_identity),
        "created_by_team_member_display_name": "RCH",
        "updated_at": timestamp,
        "last_changed_by_team_member_rns_identity": compact_rem_identifier_string(source_identity),
        "deleted_at": null,
        "uploaded_at": timestamp,
        "participant_rns_identities": participants,
        "expected_task_count": total,
        "progress_percent": progress_percent,
        "counts": {
            "pending_count": pending_count,
            "late_count": 0,
            "complete_count": complete_count,
        },
        "columns": columns,
        "tasks": tasks,
        "feed_publications": [],
    })
}

fn rem_command_transport_fields(envelope: Value) -> Value {
    let mut fields_map = serde_json::Map::new();
    fields_map.insert(
        FIELD_COMMANDS.to_string(),
        json!([rem_wire_command_envelope(&envelope)]),
    );
    Value::Object(fields_map)
}

fn rem_wire_command_envelope(envelope: &Value) -> Value {
    let command_type = envelope
        .get("command_type")
        .and_then(Value::as_str)
        .unwrap_or_default();
    let mut wire = serde_json::Map::new();
    if !command_type.is_empty() {
        wire.insert("command_type".to_string(), json!(command_type));
    }
    if let Some(args) = envelope.get("args") {
        wire.insert(
            "args".to_string(),
            rem_wire_command_args(command_type, args),
        );
    }
    if command_type == "checklist.upload" {
        if let Some(snapshot_json) = envelope.get("snapshot_json").and_then(Value::as_str) {
            if let Ok(snapshot) = serde_json::from_str::<Value>(snapshot_json) {
                wire.insert("snapshot".to_string(), snapshot);
            }
        } else if let Some(snapshot) = envelope.get("snapshot") {
            wire.insert("snapshot".to_string(), snapshot.clone());
        }
    }
    Value::Object(
        wire.into_iter()
            .filter(|(_, value)| !value.is_null())
            .collect(),
    )
}

fn rem_wire_command_args(command_type: &str, args: &Value) -> Value {
    let Some(object) = args.as_object() else {
        return args.clone();
    };
    if command_type == "checklist.create.online" {
        return clean_optional_args(Value::Object(object.clone()));
    }
    let keys: &[&str] = match command_type {
        "checklist.task.row.add" => &[
            "checklist_uid",
            "task_uid",
            "number",
            "due_relative_minutes",
            "due_dtg",
            "notes",
            "legacy_value",
            "task",
            "changed_by_team_member_rns_identity",
        ],
        "checklist.task.row.delete" => &["checklist_uid", "task_uid"],
        "checklist.task.row.style.set" => &[
            "checklist_uid",
            "task_uid",
            "row_background_color",
            "line_break_enabled",
            "changed_by_team_member_rns_identity",
        ],
        "checklist.task.cell.set" => &[
            "checklist_uid",
            "task_uid",
            "column_uid",
            "value",
            "updated_by_team_member_rns_identity",
        ],
        "checklist.task.status.set" => &["checklist_uid", "task_uid", "user_status"],
        _ => return args.clone(),
    };
    let mut out = serde_json::Map::new();
    for key in keys {
        if let Some(value) = object.get(*key) {
            if !value.is_null() {
                out.insert((*key).to_string(), value.clone());
            }
        }
    }
    Value::Object(out)
}

fn rem_args_with_mission_uid(args: Value, mission_uid: &str) -> Value {
    let Some(mut object) = args.as_object().cloned() else {
        return args;
    };
    if !mission_uid.trim().is_empty() && !object.contains_key("mission_uid") {
        object.insert(
            "mission_uid".to_string(),
            compact_rem_identifier_text(mission_uid),
        );
    }
    Value::Object(object)
}

fn rem_args_with_checklist_and_mission_uid(
    args: Value,
    checklist_uid: Option<&Value>,
    mission_uid: &str,
) -> Value {
    let args = rem_args_with_mission_uid(args, mission_uid);
    let Some(mut object) = args.as_object().cloned() else {
        return args;
    };
    if !object.contains_key("checklist_uid") {
        if let Some(value) = checklist_uid {
            object.insert("checklist_uid".to_string(), value.clone());
        }
    }
    Value::Object(object)
}

fn rem_command_topics(args: &Value) -> Vec<String> {
    let Some(object) = args.as_object() else {
        return Vec::new();
    };
    let mut topics = Vec::new();
    for key in ["mission_uid", "mission_id", "checklist_uid", "uid"] {
        if let Some(topic) = object
            .get(key)
            .and_then(Value::as_str)
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(str::to_string)
        {
            push_unique_destination(&mut topics, topic);
        }
    }
    topics
}

fn rem_command_subject(args: &Value) -> String {
    let Some(object) = args.as_object() else {
        return "update".to_string();
    };
    for key in ["checklist_uid", "task_uid", "mission_uid", "mission_id"] {
        if let Some(subject) = object
            .get(key)
            .and_then(Value::as_str)
            .map(str::trim)
            .filter(|value| !value.is_empty())
        {
            return subject.to_string();
        }
    }
    "update".to_string()
}

fn rem_log_entry_command_fields(
    log_entry: &serde_json::Map<String, Value>,
    mission_uid: &str,
    mission_change_uid: &str,
    source_identity: &str,
) -> Option<Value> {
    let entry_uid = string_or_value(log_entry.get("entry_uid"))
        .or_else(|| string_or_value(log_entry.get("uid")))?;
    let log_mission_uid =
        string_or_value(log_entry.get("mission_uid")).unwrap_or_else(|| json!(mission_uid));
    let content = string_or_value(log_entry.get("content"))
        .or_else(|| string_or_value(log_entry.get("text")))?;
    let callsign = string_or_value(log_entry.get("callsign")).unwrap_or_else(|| json!("RCH"));
    let command_id =
        compact_rem_command_id("mission.registry.log_entry.upsert", mission_change_uid);
    let args = json_object_without_nulls([
        (
            "entry_uid",
            Some(match entry_uid {
                Value::String(text) => compact_rem_identifier_text(&text),
                value => value,
            }),
        ),
        (
            "mission_uid",
            Some(match log_mission_uid {
                Value::String(text) => compact_rem_identifier_text(&text),
                value => value,
            }),
        ),
        ("content", Some(content)),
        ("callsign", Some(callsign)),
        (
            "source_identity",
            Some(json!(compact_rem_identifier_string(source_identity))),
        ),
    ]);
    let command = json!({
        "command_id": command_id,
        "command_type": "mission.registry.log_entry.upsert",
        "source": {
            "rns_identity": compact_rem_identifier_string(source_identity),
        },
        "timestamp": iso8601_from_unix_ms(unix_now_ms()),
        "args": clean_optional_args(args),
    });
    Some(rem_command_transport_fields(command))
}

fn first_log_entry_from_mission_change(change: &Value) -> Option<&serde_json::Map<String, Value>> {
    let delta = change.get("delta")?;
    delta
        .get("logs")
        .or_else(|| delta.get("log_entries"))
        .and_then(Value::as_array)
        .and_then(|logs| logs.first())
        .and_then(Value::as_object)
}

fn first_telemetry_from_mission_change(change: &Value) -> Option<&serde_json::Map<String, Value>> {
    change
        .get("delta")
        .and_then(|delta| delta.get("telemetry"))
        .and_then(Value::as_array)
        .and_then(|items| items.first())
        .and_then(Value::as_object)
}

fn rem_telemetry_command_fields(
    telemetry: &serde_json::Map<String, Value>,
    mission_uid: &str,
    source_identity: &str,
) -> Value {
    let telemetry_mission_uid =
        string_or_value(telemetry.get("mission_uid")).unwrap_or_else(|| json!(mission_uid));
    let args = json_object_without_nulls([
        ("uid", compact_rem_identifier_value(telemetry.get("uid"))),
        ("mission_uid", Some(telemetry_mission_uid)),
        ("callsign", string_or_value(telemetry.get("callsign"))),
        ("lat", string_or_value(telemetry.get("lat"))),
        ("lon", string_or_value(telemetry.get("lon"))),
        ("alt", string_or_value(telemetry.get("alt"))),
        ("speed", string_or_value(telemetry.get("speed"))),
        ("course", string_or_value(telemetry.get("course"))),
        ("accuracy", string_or_value(telemetry.get("accuracy"))),
        ("battery", string_or_value(telemetry.get("battery"))),
        ("notes", string_or_value(telemetry.get("notes"))),
        (
            "source_identity",
            Some(json!(compact_rem_identifier_string(source_identity))),
        ),
    ]);
    let envelope = json!({
        "command_type": "mission.registry.telemetry.upsert",
        "args": clean_optional_args(args),
    });
    rem_command_transport_fields(envelope)
}

fn clean_optional_args(args: Value) -> Value {
    let Some(object) = args.as_object() else {
        return args;
    };
    Value::Object(
        object
            .iter()
            .filter(|(_, value)| !value.is_null())
            .map(|(key, value)| (key.clone(), value.clone()))
            .collect(),
    )
}

fn string_or_value(value: Option<&Value>) -> Option<Value> {
    match value {
        Some(Value::String(text)) if !text.trim().is_empty() => Some(json!(text.trim())),
        Some(Value::Number(_) | Value::Bool(_)) => value.cloned(),
        _ => None,
    }
}

fn string_value(value: Option<&Value>) -> Option<String> {
    match value {
        Some(Value::String(text)) => {
            let trimmed = text.trim();
            (!trimmed.is_empty()).then(|| trimmed.to_string())
        }
        Some(Value::Number(number)) => Some(number.to_string()),
        Some(Value::Bool(value)) => Some(value.to_string()),
        _ => None,
    }
}

fn compact_rem_identifier_text(value: &str) -> Value {
    json!(value.trim())
}

fn compact_rem_identifier_string(value: &str) -> String {
    compact_rem_identifier_text(value)
        .as_str()
        .unwrap_or_default()
        .to_string()
}

fn compact_rem_identifier_value(value: Option<&Value>) -> Option<Value> {
    match string_or_value(value)? {
        Value::String(text) => Some(compact_rem_identifier_text(&text)),
        value => Some(value),
    }
}

fn rem_command_code(command_type: &str) -> &'static str {
    match command_type {
        "checklist.create.online" => "cco",
        "checklist.task.row.add" => "cra",
        "checklist.task.row.delete" => "crd",
        "checklist.task.row.style.set" => "crs",
        "checklist.task.status.set" => "css",
        "checklist.task.cell.set" => "cce",
        "mission.registry.log_entry.upsert" => "lgu",
        "mission.registry.eam.upsert" => "eau",
        "mission.registry.eam.delete" => "ead",
        "mission.registry.telemetry.upsert" => "tpu",
        _ => "cmd",
    }
}

fn compact_rem_command_id(command_type: &str, token: &str) -> String {
    format!(
        "{}-{}",
        rem_command_code(command_type),
        compact_rem_identifier_string(token)
    )
}

fn row_add_args(task: &serde_json::Map<String, Value>) -> Option<Value> {
    let mut task_snapshot = task.clone();
    if let Some(checklist_uid) = compact_rem_identifier_value(task.get("checklist_uid")) {
        task_snapshot.insert("checklist_uid".to_string(), checklist_uid);
    }
    if let Some(task_uid) = compact_rem_identifier_value(task.get("task_uid")) {
        task_snapshot.insert("task_uid".to_string(), task_uid);
    }
    Some(json_object_without_nulls([
        (
            "checklist_uid",
            compact_rem_identifier_value(task.get("checklist_uid")),
        ),
        (
            "task_uid",
            compact_rem_identifier_value(task.get("task_uid")),
        ),
        ("number", task.get("number").cloned()),
        (
            "due_relative_minutes",
            task.get("due_relative_minutes").cloned(),
        ),
        ("due_dtg", string_or_value(task.get("due_dtg"))),
        ("notes", string_or_value(task.get("notes"))),
        ("legacy_value", string_or_value(task.get("legacy_value"))),
        ("task", Some(Value::Object(task_snapshot))),
        (
            "changed_by_team_member_rns_identity",
            string_or_value(task.get("changed_by_team_member_rns_identity")),
        ),
    ]))
}

