fn emit_mission_change_listener_events(
    state: &AppState,
    before: &HashMap<String, Value>,
    after: &HashMap<String, Value>,
) -> Result<(), ApiError> {
    let mut changes = after
        .iter()
        .filter(|(uid, payload)| before.get(*uid) != Some(*payload))
        .map(|(_, payload)| payload.clone())
        .collect::<Vec<_>>();
    changes.sort_by(|left, right| {
        left.get("timestamp")
            .and_then(Value::as_str)
            .cmp(&right.get("timestamp").and_then(Value::as_str))
            .then_with(|| {
                left.get("uid")
                    .and_then(serde_json::Value::as_str)
                    .cmp(&right.get("uid").and_then(Value::as_str))
            })
    });
    for change in changes {
        let mission_uid = change
            .get("mission_uid")
            .and_then(Value::as_str)
            .unwrap_or_default()
            .to_string();
        let mission_change_uid = change
            .get("uid")
            .and_then(Value::as_str)
            .unwrap_or_default()
            .to_string();
        let fanout_marked =
            mark_mission_change_fanned_out(state, &mission_change_uid, unix_now_ms())?;
        let fanout_summary = if fanout_marked {
            fanout_mission_change_to_recipients(state, &mission_uid, &mission_change_uid, &change)?
        } else {
            json!({
                "attempted": false,
                "reason": "duplicate_suppressed",
                "recipient_count": 0,
                "sent": 0,
                "failed": 0,
            })
        };
        let _ = record_system_event(
            state,
            "mission.registry.mission_change.upserted",
            "Mission change listener notification",
            json!({
                "mission_uid": mission_uid,
                "mission_change_uid": mission_change_uid,
                "mission_change": change,
                "listener_event": true,
                "fanout_duplicate_suppressed": !fanout_marked,
                "fanout_cache_ttl_ms": MISSION_CHANGE_FANOUT_CACHE_TTL_MS,
                "recipient_fanout": fanout_summary,
            }),
        )?;
    }
    Ok(())
}

fn spawn_mission_change_listener_events(
    state: &AppState,
    before: HashMap<String, Value>,
    after: HashMap<String, Value>,
) -> Result<(), ApiError> {
    if before == after {
        return Ok(());
    }
    emit_mission_change_listener_events(&state, &before, &after)
}

async fn send_message(
    State(state): State<AppState>,
    Json(input): Json<Value>,
) -> Result<Json<Value>, ApiError> {
    let payload = parse_message_payload(input)?;
    let content = payload.content;
    let topic_id = normalize_optional_text(payload.topic_id);
    let destination = normalize_optional_text(payload.destination);
    let _ = record_outbound_message_deferred_with_metadata(
        &state,
        &content,
        topic_id,
        destination,
        Vec::new(),
        false,
        json!({}),
    )?;
    Ok(Json(json!({ "sent": true })))
}

fn parse_message_payload(input: Value) -> Result<MessagePayload, ApiError> {
    if input.is_null() {
        return Err(ApiError::PydanticValidation(python_missing_body_body()));
    }
    if !input.is_object() {
        return Err(ApiError::PydanticValidation(python_model_attributes_body(
            input,
        )));
    }
    let validation_input = python_alias_normalized_input(input.clone());
    match serde_json::from_value::<MessagePayload>(input) {
        Ok(payload) => Ok(payload),
        Err(error) if error.to_string().contains("missing field `content`") => Err(
            ApiError::PydanticValidation(python_missing_field_body("content", validation_input)),
        ),
        Err(error) => Err(ApiError::Unprocessable(error.to_string())),
    }
}

fn python_alias_normalized_input(input: Value) -> Value {
    let mut normalized = input;
    if let Some(object) = normalized.as_object_mut() {
        if let Some(value) = object.get("TopicID").cloned() {
            object.entry("topic_id").or_insert(value);
        }
        if let Some(value) = object.get("topicId").cloned() {
            object.entry("topic_id").or_insert(value);
        }
        if let Some(value) = object.get("Destination").cloned() {
            object.entry("destination").or_insert(value);
        }
    }
    normalized
}

async fn list_chat_messages(
    State(state): State<AppState>,
    Query(query): Query<ChatListQuery>,
) -> Result<Json<Value>, ApiError> {
    let limit = usize::try_from(query.limit.unwrap_or(200).max(1)).unwrap_or(1);
    let direction = normalize_optional_text(query.direction);
    let topic_id = normalize_optional_text(query.topic_id);
    let destination = normalize_optional_text(query.destination);
    let source = normalize_optional_text(query.source);
    let mut messages = state
        .messages
        .read()
        .map_err(|error| ApiError::Internal(error.to_string()))?
        .clone();
    messages.sort_by(|left, right| right.created_ts_ms.cmp(&left.created_ts_ms));
    let payload = messages
        .into_iter()
        .filter(|message| {
            message_visible_in_chat(message)
                && direction
                    .as_deref()
                    .is_none_or(|value| message_direction(message) == value)
                && topic_id
                    .as_deref()
                    .is_none_or(|value| message.topic_id.as_deref() == Some(value))
                && destination
                    .as_deref()
                    .is_none_or(|value| message.destination.as_deref() == Some(value))
                && source
                    .as_deref()
                    .is_none_or(|value| message.sender.as_str() == value)
        })
        .take(limit)
        .map(chat_message_payload)
        .collect::<Vec<_>>();
    Ok(Json(json!(payload)))
}

fn message_visible_in_chat(message: &OutboundMessageRecord) -> bool {
    !is_rem_command_message(message)
}

fn parse_chat_send_payload(input: Value) -> Result<ChatSendPayload, ApiError> {
    if input.is_null() {
        return Err(ApiError::PydanticValidation(python_missing_body_body()));
    }
    if !input.is_object() {
        return Err(ApiError::PydanticValidation(python_model_attributes_body(
            input,
        )));
    }
    match serde_json::from_value::<ChatSendPayload>(input.clone()) {
        Ok(mut payload) => {
            payload.validation_input = input;
            Ok(payload)
        }
        Err(error) if error.to_string().contains("missing field `scope`") => Err(
            ApiError::PydanticValidation(python_missing_field_body("scope", input)),
        ),
        Err(error) => Err(ApiError::Unprocessable(error.to_string())),
    }
}

fn chat_value_error(message: &str, input: Value) -> ApiError {
    ApiError::PydanticValidation(python_value_error_body(message, input))
}

async fn send_chat_message(
    State(state): State<AppState>,
    Json(input): Json<Value>,
) -> Result<Json<Value>, ApiError> {
    let payload = parse_chat_send_payload(input)?;
    let content = payload.content.unwrap_or_default();
    if content.trim().is_empty() && payload.file_ids.is_empty() && payload.image_ids.is_empty() {
        return Err(chat_value_error(
            "Content or attachments are required",
            payload.validation_input,
        ));
    }
    let scope = payload.scope.trim().to_ascii_lowercase();
    if !matches!(scope.as_str(), "dm" | "topic" | "broadcast") {
        return Err(chat_value_error(
            "Scope must be dm, topic, or broadcast",
            payload.validation_input,
        ));
    }
    let topic_id = normalize_optional_text(payload.topic_id);
    let destination = normalize_optional_text(payload.destination);
    if scope == "dm" && destination.is_none() {
        return Err(chat_value_error(
            "Destination is required for DM scope",
            payload.validation_input,
        ));
    }
    if scope == "topic" && topic_id.is_none() {
        return Err(chat_value_error(
            "TopicID is required for topic scope",
            payload.validation_input,
        ));
    }
    let attachment_files =
        resolve_chat_attachment_files(&state, &payload.file_ids, &payload.image_ids)?;
    let attachments = attachment_files
        .iter()
        .map(chat_attachment_from_file_record)
        .collect::<Vec<_>>();
    let delivery_metadata = json!({
        "delivery_receipt_required": scope == "dm",
        "max_attempts": 1,
        "lxmf_fields": chat_outbound_lxmf_fields(
            topic_id.as_deref(),
            destination.as_deref(),
            &attachment_files,
        )?,
    });
    let message = record_outbound_message_deferred_with_metadata(
        &state,
        &content,
        topic_id,
        destination,
        attachments,
        true,
        delivery_metadata,
    )?;
    let response = chat_message_payload(message.clone());
    Ok(Json(response))
}

async fn upload_chat_attachment(
    State(state): State<AppState>,
    mut multipart: Multipart,
) -> Result<Json<Value>, ApiError> {
    let mut category: Option<String> = None;
    let mut sha256: Option<String> = None;
    let mut topic_id: Option<String> = None;
    let mut filename: Option<String> = None;
    let mut media_type: Option<String> = None;
    let mut content: Option<Vec<u8>> = None;

    while let Some(field) = multipart
        .next_field()
        .await
        .map_err(|error| ApiError::BadRequest(error.to_string()))?
    {
        let name = field.name().unwrap_or_default().to_string();
        match name.as_str() {
            "category" => {
                category = Some(
                    field
                        .text()
                        .await
                        .map_err(|error| ApiError::BadRequest(error.to_string()))?,
                );
            }
            "sha256" => {
                sha256 = Some(
                    field
                        .text()
                        .await
                        .map_err(|error| ApiError::BadRequest(error.to_string()))?,
                );
            }
            "topic_id" | "TopicID" | "topicId" => {
                topic_id = Some(
                    field
                        .text()
                        .await
                        .map_err(|error| ApiError::BadRequest(error.to_string()))?,
                );
            }
            "file" => {
                filename = Some(
                    field
                        .file_name()
                        .filter(|value| !value.trim().is_empty())
                        .unwrap_or("upload.bin")
                        .to_string(),
                );
                media_type = field.content_type().map(ToString::to_string);
                content = Some(
                    field
                        .bytes()
                        .await
                        .map_err(|error| ApiError::BadRequest(error.to_string()))?
                        .to_vec(),
                );
            }
            _ => {}
        }
    }

    let category = category
        .map(|value| value.trim().to_ascii_lowercase())
        .filter(|value| !value.is_empty())
        .ok_or_else(|| {
            ApiError::BadRequest("Attachment category must be file or image".to_string())
        })?;
    if !matches!(category.as_str(), "file" | "image") {
        return Err(ApiError::BadRequest(
            "Attachment category must be file or image".to_string(),
        ));
    }
    let content =
        content.ok_or_else(|| ApiError::BadRequest("field `file` is required".to_string()))?;
    if content.is_empty() {
        return Err(ApiError::BadRequest(
            "Attachment content is empty".to_string(),
        ));
    }
    if content.len() > CHAT_ATTACHMENT_MAX_BYTES {
        return Err(ApiError::PayloadTooLarge(
            "Attachment exceeds size limit".to_string(),
        ));
    }
    if category == "image" {
        let media_type_value = media_type.as_deref().unwrap_or_default();
        if !media_type_value.starts_with("image/") {
            return Err(ApiError::BadRequest(
                "Image attachments must use an image content type".to_string(),
            ));
        }
    }
    if let Some(expected_hash) = sha256
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
    {
        let digest = Sha256::digest(&content);
        let actual_hash = digest
            .iter()
            .map(|byte| format!("{byte:02x}"))
            .collect::<String>();
        if actual_hash != expected_hash.to_ascii_lowercase() {
            return Err(ApiError::BadRequest("Attachment hash mismatch".to_string()));
        }
    }

    let safe_name = sanitize_attachment_filename(filename.as_deref().unwrap_or("upload.bin"));
    let suffix = FsPath::new(&safe_name)
        .extension()
        .and_then(|value| value.to_str())
        .map(|value| format!(".{value}"))
        .unwrap_or_default();
    let stored_name = format!("{}{}", Uuid::new_v4().simple(), suffix);
    let base_path = state.attachment_storage_path(&category)?;
    std::fs::create_dir_all(&base_path).map_err(|error| ApiError::Internal(error.to_string()))?;
    let target_path = base_path.join(stored_name);
    std::fs::write(&target_path, &content)
        .map_err(|error| ApiError::Internal(error.to_string()))?;

    let now = unix_now_ms();
    let record = insert_file_attachment_row(
        &state,
        FileAttachmentRecord {
            file_id: 0,
            name: safe_name,
            path: target_path.display().to_string(),
            category,
            size: content.len() as u64,
            media_type,
            topic_id: normalize_optional_text(topic_id),
            created_ts_ms: now,
            updated_ts_ms: now,
        },
    )?;

    Ok(Json(attachment_to_python_value(&record)))
}

fn chat_message_payload(message: OutboundMessageRecord) -> Value {
    let direction = message_direction(&message).to_string();
    let scope = message_scope(&message);
    let source = if direction == "inbound" {
        json!(
            message
                .delivery_metadata
                .get("source")
                .and_then(Value::as_str)
                .unwrap_or(message.sender.as_str())
        )
    } else {
        Value::Null
    };
    let state = if message.delivery_state.is_empty() {
        if direction == "inbound" {
            "received"
        } else {
            "queued"
        }
    } else {
        message.delivery_state.as_str()
    };
    let timestamp = iso8601_from_unix_ms(message.created_ts_ms);
    let attachments = message
        .attachments
        .iter()
        .map(chat_attachment_to_python_value)
        .collect::<Vec<_>>();
    let mut delivery_metadata = message.delivery_metadata.clone();
    if let Some(metadata) = delivery_metadata.as_object_mut() {
        metadata.remove("lxmf_fields");
    }
    merge_delivery_metadata(
        &mut delivery_metadata,
        json!({
            "method": message.delivery_method,
            "delivery_policy_reason": message.delivery_policy_reason,
        }),
    );
    json!({
        "MessageID": message.message_id,
        "Direction": direction,
        "Scope": scope,
        "State": state,
        "Content": message.content,
        "Source": source,
        "Destination": message.destination,
        "TopicID": message.topic_id,
        "Attachments": attachments,
        "DeliveryMetadata": delivery_metadata,
        "CreatedAt": timestamp,
        "UpdatedAt": timestamp,
    })
}

fn message_direction(message: &OutboundMessageRecord) -> &str {
    message
        .delivery_metadata
        .get("direction")
        .and_then(Value::as_str)
        .filter(|value| *value == "inbound")
        .unwrap_or("outbound")
}

fn message_scope(message: &OutboundMessageRecord) -> &'static str {
    match message.delivery_mode {
        DeliveryMode::Targeted => "dm",
        DeliveryMode::Fanout => "topic",
        DeliveryMode::Broadcast => "broadcast",
    }
}

fn system_event_payload(event: SystemEventRecord) -> Value {
    json!({
        "id": event.event_id,
        "timestamp": iso8601_from_unix_ms(event.timestamp_ms),
        "type": event.event_type,
        "message": event.message,
        "metadata": event.metadata,
        "origin": "rust",
    })
}

fn telemetry_payload(record: TelemetryRecord) -> Value {
    json!({
        "peer_destination": record.peer_destination,
        "timestamp": record.timestamp_s,
        "telemetry": record.telemetry,
        "display_name": record.display_name,
        "identity_label": record.identity_label,
    })
}

fn chat_attachment_to_python_value(record: &ChatAttachmentRecord) -> Value {
    json!({
        "FileID": record.file_id,
        "Category": record.category,
        "Name": record.name,
        "Size": record.size,
        "MediaType": record.media_type,
    })
}

fn sanitize_attachment_filename(filename: &str) -> String {
    let safe = FsPath::new(filename)
        .file_name()
        .and_then(|value| value.to_str())
        .unwrap_or("upload.bin")
        .trim();
    if safe.is_empty() {
        "upload.bin".to_string()
    } else {
        safe.to_string()
    }
}

fn resolve_chat_attachment_files(
    state: &AppState,
    file_ids: &[u64],
    image_ids: &[u64],
) -> Result<Vec<FileAttachmentRecord>, ApiError> {
    let mut attachments = Vec::new();
    for file_id in file_ids {
        attachments.push(get_attachment_record(state, *file_id, "file")?);
    }
    for image_id in image_ids {
        attachments.push(get_attachment_record(state, *image_id, "image")?);
    }
    Ok(attachments)
}

fn chat_attachment_from_file_record(attachment: &FileAttachmentRecord) -> ChatAttachmentRecord {
    ChatAttachmentRecord {
        file_id: attachment.file_id,
        category: attachment.category.clone(),
        name: attachment.name.clone(),
        size: attachment.size,
        media_type: attachment.media_type.clone(),
    }
}

fn chat_outbound_lxmf_fields(
    _topic_id: Option<&str>,
    _destination: Option<&str>,
    attachments: &[FileAttachmentRecord],
) -> Result<Value, ApiError> {
    let mut fields = serde_json::Map::new();
    if !attachments.is_empty() {
        fields.insert(
            LXMF_FIELD_ATTACHMENTS_PUBLIC_KEY.to_string(),
            Value::Array(
                attachments
                    .iter()
                    .map(chat_lxmf_attachment_value)
                    .collect::<Result<Vec<_>, _>>()?,
            ),
        );
    }
    Ok(Value::Object(fields))
}

fn chat_lxmf_attachment_value(attachment: &FileAttachmentRecord) -> Result<Value, ApiError> {
    let data = std::fs::read(&attachment.path).map_err(|error| {
        ApiError::Internal(format!(
            "Failed to read attachment {} for LXMF dispatch: {error}",
            attachment.file_id
        ))
    })?;
    Ok(json!({
        "name": attachment.name,
        "data": format!("base64:{}", BASE64_STANDARD.encode(data)),
    }))
}

const REM_PEER_ACTIVE_WINDOW_MS: i64 = 60 * 60 * 1000;
const REM_PEER_RUNTIME_START_GRACE_MS: i64 = 5 * 1000;
#[cfg(test)]
const OUTBOUND_BROADCAST_ACTIVE_WINDOW_MS: i64 = 5 * 60 * 1000;

async fn rem_peer_registry(State(state): State<AppState>) -> Result<Json<Value>, ApiError> {
    if state.sqlite_path.is_none() {
        return Ok(Json(empty_rem_peer_registry()));
    }
    let payload = rem_peer_registry_payload_for_state(&state, None)?;
    Ok(Json(payload))
}

fn empty_rem_peer_registry() -> Value {
    json!({
        "effective_connected_mode": false,
        "items": []
    })
}

fn rem_annotations_for_state(
    state: &AppState,
) -> Result<HashMap<String, RemIdentityAnnotation>, ApiError> {
    rem_annotations_for_destinations(state, &[])
}

fn rem_annotations_for_destinations(
    state: &AppState,
    destinations: &[String],
) -> Result<HashMap<String, RemIdentityAnnotation>, ApiError> {
    if state.sqlite_path.is_none() {
        return Ok(HashMap::new());
    }
    let Some(path) = &state.sqlite_path else {
        return Ok(HashMap::new());
    };
    let store = RchSqliteStore::open_read_only(path.as_ref())
        .map_err(|error| ApiError::Internal(error.to_string()))?;
    let identity_announces = if destinations.is_empty() {
        store
            .load_identity_announces()
            .map_err(|error| ApiError::Internal(error.to_string()))?
    } else {
        store
            .load_identity_announces_by_destination_hashes(destinations)
            .map_err(|error| ApiError::Internal(error.to_string()))?
    };
    let identity_rem_modes = if destinations.is_empty() {
        store
            .load_identity_rem_modes()
            .map_err(|error| ApiError::Internal(error.to_string()))?
    } else {
        store
            .load_identity_rem_modes_by_identities(destinations)
            .map_err(|error| ApiError::Internal(error.to_string()))?
    };
    Ok(rem_annotations_from_records(
        &identity_announces,
        &identity_rem_modes,
    ))
}

#[cfg(test)]
fn rem_annotations_from_snapshot(
    snapshot: &r3akt_rch_core::RchCoreSnapshot,
) -> HashMap<String, RemIdentityAnnotation> {
    rem_annotations_from_records(&snapshot.identity_announces, &snapshot.identity_rem_modes)
}

fn rem_annotations_from_records(
    identity_announces: &[r3akt_rch_core::IdentityAnnounceRecord],
    identity_rem_modes: &[r3akt_rch_core::IdentityRemModeRecord],
) -> HashMap<String, RemIdentityAnnotation> {
    let rem_modes: HashMap<String, String> = identity_rem_modes
        .iter()
        .filter_map(|record| {
            normalize_identity_key(&record.identity).map(|identity| {
                let mode = record.mode.trim().to_ascii_lowercase();
                (
                    identity,
                    if mode.is_empty() {
                        "autonomous".to_string()
                    } else {
                        mode
                    },
                )
            })
        })
        .collect();
    let mut candidates: HashMap<String, (&r3akt_rch_core::IdentityAnnounceRecord, String)> =
        HashMap::new();
    for record in identity_announces {
        let identity = record
            .announced_identity_hash
            .as_deref()
            .and_then(normalize_identity_key)
            .or_else(|| normalize_identity_key(&record.destination_hash));
        let Some(identity) = identity else {
            continue;
        };
        let source = record
            .source_interface
            .as_deref()
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(str::to_ascii_lowercase)
            .unwrap_or_else(|| "identity".to_string());
        let replace = candidates
            .get(&identity)
            .is_none_or(|(_, existing_source)| {
                source == "destination" && existing_source != "destination"
            });
        if replace {
            candidates.insert(identity, (record, source));
        }
    }
    candidates
        .into_iter()
        .map(|(identity, (record, _))| {
            let client_type = record.client_type.trim().to_ascii_lowercase();
            let is_rem_capable = client_type == "rem";
            let rem_mode = is_rem_capable.then(|| {
                rem_modes
                    .get(&identity)
                    .cloned()
                    .unwrap_or_else(|| "autonomous".to_string())
            });
            (
                identity,
                RemIdentityAnnotation {
                    destination_hash: record.destination_hash.clone(),
                    announced_identity_hash: record.announced_identity_hash.clone(),
                    display_name: record
                        .display_name
                        .as_deref()
                        .map(str::trim)
                        .filter(|value| !value.is_empty())
                        .map(str::to_string),
                    source_interface: record
                        .source_interface
                        .as_deref()
                        .map(str::trim)
                        .filter(|value| !value.is_empty())
                        .map(str::to_string),
                    announce_capabilities: record.announce_capabilities.clone(),
                    client_type: if client_type.is_empty() {
                        "generic_lxmf".to_string()
                    } else {
                        client_type
                    },
                    rem_mode,
                    is_rem_capable,
                    first_seen_ts_ms: record.first_seen_ts_ms,
                    last_seen_ts_ms: record.last_seen_ts_ms,
                },
            )
        })
        .collect()
}

fn rem_peer_runtime_freshness_cutoff_ms(state: &AppState) -> Option<i64> {
    state.reticulumd_rpc_endpoint.as_ref()?;
    let runtime_start_ms = state
        .runtime_control
        .read()
        .ok()
        .and_then(|control| control.last_start_ts_ms.or(Some(control.started_ts_ms)))?;
    let managed_start_ms = state
        .managed_reticulumd
        .read()
        .ok()
        .and_then(|managed| managed.started_ts_ms);
    let start_ms = managed_start_ms.map_or(runtime_start_ms, |managed_start_ms| {
        runtime_start_ms.max(managed_start_ms)
    });
    Some(start_ms.saturating_sub(REM_PEER_RUNTIME_START_GRACE_MS))
}

fn rem_peer_announce_is_fresh_for_runtime(
    record: &r3akt_rch_core::IdentityAnnounceRecord,
    runtime_freshness_cutoff_ms: Option<i64>,
) -> bool {
    runtime_freshness_cutoff_ms.is_none_or(|cutoff_ms| record.last_seen_ts_ms >= cutoff_ms)
}

fn rem_peer_registry_payload_for_state(
    state: &AppState,
    runtime_freshness_cutoff_ms: Option<i64>,
) -> Result<Value, ApiError> {
    let Some(path) = &state.sqlite_path else {
        return Ok(empty_rem_peer_registry());
    };
    let store = RchSqliteStore::open_read_only(path.as_ref())
        .map_err(|error| ApiError::Internal(error.to_string()))?;
    let identity_announces = store
        .load_identity_announces()
        .map_err(|error| ApiError::Internal(error.to_string()))?;
    let identity_states = store
        .load_identity_states()
        .map_err(|error| ApiError::Internal(error.to_string()))?;
    let identity_rem_modes = store
        .load_identity_rem_modes()
        .map_err(|error| ApiError::Internal(error.to_string()))?;
    Ok(rem_peer_registry_payload_from_records(
        &identity_announces,
        &identity_states,
        &identity_rem_modes,
        runtime_freshness_cutoff_ms,
    ))
}

fn rem_peer_registry_payload_from_records(
    identity_announces: &[r3akt_rch_core::IdentityAnnounceRecord],
    identity_states: &[r3akt_rch_core::IdentityStateRecord],
    identity_rem_modes: &[r3akt_rch_core::IdentityRemModeRecord],
    runtime_freshness_cutoff_ms: Option<i64>,
) -> Value {
    let cutoff_ms = unix_now_ms().saturating_sub(REM_PEER_ACTIVE_WINDOW_MS);
    let moderation: HashMap<String, (bool, bool)> = identity_states
        .iter()
        .filter_map(|record| {
            normalize_identity_key(&record.identity)
                .map(|identity| (identity, (record.is_banned, record.is_blackholed)))
        })
        .collect();
    let rem_modes: HashMap<String, String> = identity_rem_modes
        .iter()
        .filter_map(|record| {
            normalize_identity_key(&record.identity).map(|identity| {
                let mode = record.mode.trim().to_ascii_lowercase();
                (
                    identity,
                    if mode.is_empty() {
                        "autonomous".to_string()
                    } else {
                        mode
                    },
                )
            })
        })
        .collect();
    let mut candidates: HashMap<String, (&r3akt_rch_core::IdentityAnnounceRecord, String)> =
        HashMap::new();
    for record in identity_announces {
        let identity = record
            .announced_identity_hash
            .as_deref()
            .and_then(normalize_identity_key)
            .or_else(|| normalize_identity_key(&record.destination_hash));
        let Some(identity) = identity else {
            continue;
        };
        if record.last_seen_ts_ms < cutoff_ms {
            continue;
        }
        if !rem_peer_announce_is_fresh_for_runtime(record, runtime_freshness_cutoff_ms) {
            continue;
        }
        if record.client_type.trim().to_ascii_lowercase() != "rem" {
            continue;
        }
        if moderation
            .get(&identity)
            .is_some_and(|(is_banned, is_blackholed)| *is_banned || *is_blackholed)
        {
            continue;
        }
        let source = record
            .source_interface
            .as_deref()
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .map(str::to_ascii_lowercase)
            .unwrap_or_else(|| "identity".to_string());
        let replace = candidates
            .get(&identity)
            .is_none_or(|(_, existing_source)| {
                source == "destination" && existing_source != "destination"
            });
        if replace {
            candidates.insert(identity, (record, source));
        }
    }

    let effective_connected_mode = candidates.keys().any(|identity| {
        rem_modes
            .get(identity)
            .is_some_and(|mode| mode == "connected")
    });
    let mut items: Vec<_> = candidates
        .into_iter()
        .map(|(identity, (record, source))| {
            let destination_hash = if source == "destination" {
                normalize_identity_key(&record.destination_hash).unwrap_or_else(|| identity.clone())
            } else {
                identity.clone()
            };
            json!({
                "identity": identity,
                "destination_hash": destination_hash,
                "display_name": record.display_name.as_deref().map(str::trim).filter(|value| !value.is_empty()),
                "announce_capabilities": record.announce_capabilities,
                "client_type": record.client_type.trim().to_ascii_lowercase(),
                "registered_mode": rem_modes.get(&identity).cloned().unwrap_or_else(|| "autonomous".to_string()),
                "last_seen": iso8601_from_unix_ms(record.last_seen_ts_ms),
                "last_seen_ts_ms": record.last_seen_ts_ms,
                "online": true,
                "name_source": source,
                "trust_level": Value::Null,
                "bootstrap": false,
                "delivery_readiness": "fresh",
                "status": "active",
            })
        })
        .collect();
    items.sort_by(|left, right| {
        left["identity"]
            .as_str()
            .unwrap_or_default()
            .cmp(right["identity"].as_str().unwrap_or_default())
    });

    json!({
        "effective_connected_mode": effective_connected_mode,
        "items": items
    })
}

async fn list_eam_messages(
    State(state): State<AppState>,
    Query(query): Query<HashMap<String, String>>,
) -> Result<Json<Value>, ApiError> {
    if state.sqlite_path.is_none() {
        return Ok(Json(json!([])));
    }
    let store = open_r3akt_read_store(&state)?;
    let payload = store
        .load_eam_list_value(
            query.get("team_uid").map(String::as_str),
            query.get("overall_status").map(String::as_str),
        )
        .map_err(|error| ApiError::Internal(error.to_string()))?;
    Ok(Json(
        payload.get("eams").cloned().unwrap_or_else(|| json!([])),
    ))
}

async fn create_eam_message(
    State(state): State<AppState>,
    Json(payload): Json<Value>,
) -> Result<Json<Value>, ApiError> {
    validate_eam_upsert_http_payload(&payload)?;
    let payload = r3akt_command(&state, "mission.registry.eam.upsert", payload)?;
    let eam = payload.get("eam").cloned().unwrap_or_else(|| json!({}));
    let _ = fanout_eam_status_update(&state, "mission.registry.eam.upserted", &eam)?;
    Ok(Json(eam))
}

async fn get_latest_eam_message(
    State(state): State<AppState>,
    Path(team_member_uid): Path<String>,
) -> Result<Json<Value>, ApiError> {
    match r3akt_command(
        &state,
        "mission.registry.eam.latest",
        json!({ "team_member_uid": team_member_uid }),
    ) {
        Ok(payload) => Ok(Json(
            payload.get("eam").cloned().unwrap_or_else(|| json!({})),
        )),
        Err(ApiError::NotFound(_)) => Err(ApiError::NotFound(format!(
            "\"No active EmergencyActionMessage found for member/{team_member_uid}\""
        ))),
        Err(error) => Err(error),
    }
}

