fn marker_not_found(object_destination_hash: &str) -> ApiError {
    ApiError::NotFound(format!("\"Marker '{object_destination_hash}' not found\""))
}

fn record_marker_activity(
    state: &AppState,
    event_type: &str,
    marker: &MarkerRecord,
) -> Result<(), ApiError> {
    let event_payload = marker_event_payload(event_type, marker);
    let action = event_type
        .split('.')
        .next_back()
        .unwrap_or("updated")
        .to_string();
    let _ = record_system_event(
        state,
        &event_type.replace('.', "_"),
        &format!("Marker {action}: {}", marker.name),
        event_payload,
    )?;
    let telemetry = marker_telemetry_payload(event_type, marker);
    state.record_telemetry(
        &marker.object_destination_hash,
        telemetry,
        marker.updated_ts_ms / 1000,
        Some(marker.name.clone()),
    )?;
    let fanout_summary = fanout_marker_activity_to_recipients(state, event_type, marker)?;
    let _ = record_system_event(
        state,
        "marker_telemetry_recorded",
        "Marker telemetry recorded",
        json!({
            "event_type": event_type,
            "object_destination_hash": marker.object_destination_hash,
            "recipient_fanout": fanout_summary,
        }),
    )?;
    Ok(())
}

fn marker_event_payload(event_type: &str, marker: &MarkerRecord) -> Value {
    let time = iso8601_from_unix_ms(marker.updated_ts_ms);
    let mut payload = json!({
        "object_type": "marker",
        "object_id": marker.object_destination_hash,
        "event_type": event_type,
        "marker_type": marker.marker_type,
        "symbol": marker.symbol,
        "lat": marker.lat,
        "lon": marker.lon,
        "position": {"lat": marker.lat, "lon": marker.lon},
        "origin_rch": marker.origin_rch,
        "time": time,
        "stale_at": time,
        "timestamp": iso8601_from_unix_ms(marker.updated_ts_ms),
    });
    if event_type == "marker.created" {
        payload["metadata"] = json!({
            "name": marker.name,
            "category": marker.category,
            "symbol": marker.symbol,
            "marker_type": marker.marker_type,
        });
        payload["name"] = json!(marker.name);
        payload["category"] = json!(marker.category);
        payload["symbol"] = json!(marker.symbol);
        payload["marker_type"] = json!(marker.marker_type);
    }
    payload
}

fn marker_telemetry_payload(event_type: &str, marker: &MarkerRecord) -> Value {
    json!({
        "time": marker.updated_ts_ms / 1000,
        "location": {
            "latitude": marker.lat,
            "longitude": marker.lon,
            "altitude": 0.0,
            "speed": 0.0,
            "bearing": 0.0,
            "accuracy": 0.0,
            "last_update": iso8601_from_unix_ms(marker.updated_ts_ms),
        },
        "information": {
            "name": marker.name,
        },
        "custom": {
            "type_label": "marker",
            "metadata": {
                "object_type": "marker",
                "object_id": marker.object_destination_hash,
                "event_type": event_type,
                "marker_type": marker.marker_type,
                "symbol": marker.symbol,
                "category": marker.category,
                "name": marker.name,
                "origin_rch": marker.origin_rch,
                "position": {"lat": marker.lat, "lon": marker.lon},
                "time": iso8601_from_unix_ms(marker.updated_ts_ms),
                "stale_at": iso8601_from_unix_ms(marker.updated_ts_ms),
                "notes": marker.notes,
            }
        }
    })
}

fn marker_to_python_value(marker: &MarkerRecord) -> Value {
    let updated_at = iso8601_from_unix_ms(marker.updated_ts_ms);
    json!({
        "object_destination_hash": marker.object_destination_hash,
        "origin_rch": marker.origin_rch,
        "type": marker.marker_type,
        "name": marker.name,
        "category": marker.category,
        "symbol": marker.symbol,
        "notes": marker.notes,
        "position": {
            "lat": marker.lat,
            "lon": marker.lon
        },
        "time": updated_at,
        "stale_at": updated_at,
        "created_at": iso8601_from_unix_ms(marker.created_ts_ms),
        "updated_at": updated_at
    })
}

fn validate_lat_lon(lat: f64, lon: f64) -> Result<(), ApiError> {
    if !(-90.0..=90.0).contains(&lat) {
        return Err(ApiError::Unprocessable(
            "lat must be between -90 and 90".to_string(),
        ));
    }
    if !(-180.0..=180.0).contains(&lon) {
        return Err(ApiError::Unprocessable(
            "lon must be between -180 and 180".to_string(),
        ));
    }
    Ok(())
}

fn validate_python_name_field(value: String, field: &str) -> Result<String, ApiError> {
    let value = value.trim().to_string();
    if value.is_empty() {
        return Err(ApiError::Unprocessable(format!("{field} is required")));
    }
    if value.len() > 96 {
        return Err(ApiError::Unprocessable(format!(
            "{field} must be at most 96 characters"
        )));
    }
    Ok(value)
}

