async fn create_zone(
    State(state): State<AppState>,
    Json(input): Json<Value>,
) -> Result<impl IntoResponse, ApiError> {
    let payload = parse_zone_create_payload(input)?;
    let name = validate_python_name_field(payload.name, "name")?;
    validate_zone_points(&payload.points)?;
    let now_ms = unix_now_ms();
    let zone_id = Uuid::new_v4().simple().to_string();
    let zone = ZoneRecord {
        zone_id: zone_id.clone(),
        name,
        points: payload.points,
        created_ts_ms: now_ms,
        updated_ts_ms: now_ms,
    };
    state
        .zones
        .write()
        .map_err(|error| ApiError::Internal(error.to_string()))?
        .insert(zone_id.clone(), zone.clone());
    persist_zone_row(&state, &zone)?;
    Ok((
        StatusCode::CREATED,
        Json(json!({
            "zone_id": zone_id,
            "created_at": iso8601_from_unix_ms(now_ms)
        })),
    ))
}

async fn patch_zone(
    Path(zone_id): Path<String>,
    State(state): State<AppState>,
    Json(input): Json<Value>,
) -> Result<Json<Value>, ApiError> {
    let payload = parse_zone_update_payload(input)?;
    if let Some(points) = &payload.points {
        validate_zone_points(points)?;
    }
    let name = payload
        .name
        .map(|value| validate_python_name_field(value, "name"))
        .transpose()?;
    let updated_at = unix_now_ms();
    let zone = {
        let mut zones = state
            .zones
            .write()
            .map_err(|error| ApiError::Internal(error.to_string()))?;
        let zone = zones
            .get_mut(&zone_id)
            .ok_or_else(|| zone_not_found(&zone_id))?;
        if let Some(name) = name {
            zone.name = name;
        }
        if let Some(points) = payload.points {
            zone.points = points;
        }
        zone.updated_ts_ms = updated_at;
        zone.clone()
    };
    persist_zone_row(&state, &zone)?;
    Ok(Json(json!({
        "status": "ok",
        "updated_at": iso8601_from_unix_ms(updated_at)
    })))
}

fn parse_zone_create_payload(input: Value) -> Result<ZoneCreatePayload, ApiError> {
    if input.is_null() {
        return Err(ApiError::PydanticValidation(python_missing_body_body()));
    }
    if !input.is_object() {
        return Err(ApiError::PydanticValidation(python_model_attributes_body(
            input,
        )));
    }
    let missing = ["name", "points"]
        .into_iter()
        .filter(|field| {
            input
                .as_object()
                .is_none_or(|object| !object.contains_key(*field))
        })
        .collect::<Vec<_>>();
    if !missing.is_empty() {
        return Err(ApiError::PydanticValidation(python_missing_fields_body(
            &missing, input,
        )));
    }
    validate_zone_pydantic_shape(&input, true)?;
    serde_json::from_value::<ZoneCreatePayload>(input)
        .map_err(|error| ApiError::Unprocessable(error.to_string()))
}

fn parse_zone_update_payload(input: Value) -> Result<ZoneUpdatePayload, ApiError> {
    if input.is_null() {
        return Err(ApiError::PydanticValidation(python_missing_body_body()));
    }
    if !input.is_object() {
        return Err(ApiError::PydanticValidation(python_model_attributes_body(
            input,
        )));
    }
    let has_name = input.get("name").is_some();
    let has_points = input.get("points").is_some_and(|value| !value.is_null());
    if !has_name && !has_points {
        return Err(ApiError::PydanticValidation(python_value_error_body(
            "At least one zone field must be provided",
            input,
        )));
    }
    validate_zone_pydantic_shape(&input, false)?;
    serde_json::from_value::<ZoneUpdatePayload>(input)
        .map_err(|error| ApiError::Unprocessable(error.to_string()))
}

fn validate_zone_pydantic_shape(input: &Value, require_points: bool) -> Result<(), ApiError> {
    if let Some(Value::String(name)) = input.get("name") {
        if name.is_empty() {
            return Err(ApiError::PydanticValidation(python_string_too_short_body(
                "name",
                json!(name),
                1,
            )));
        }
    }
    if let Some(points) = input.get("points") {
        if points.is_null() && !require_points {
            return Ok(());
        }
        if let Some(points) = points.as_array() {
            if points.len() < 3 {
                return Err(ApiError::PydanticValidation(python_list_too_short_body(
                    "points",
                    Value::Array(points.clone()),
                    3,
                    points.len(),
                )));
            }
        }
    }
    Ok(())
}

async fn delete_zone(
    Path(zone_id): Path<String>,
    State(state): State<AppState>,
) -> Result<Json<Value>, ApiError> {
    let removed = state
        .zones
        .write()
        .map_err(|error| ApiError::Internal(error.to_string()))?
        .remove(&zone_id);
    if removed.is_none() {
        return Err(zone_not_found(&zone_id));
    }
    delete_zone_row(&state, &zone_id)?;
    Ok(Json(json!({
        "status": "ok",
        "deleted_at": iso8601_from_unix_ms(unix_now_ms())
    })))
}

fn zone_not_found(zone_id: &str) -> ApiError {
    ApiError::NotFound(format!("\"Zone '{zone_id}' not found\""))
}

fn zone_to_python_value(zone: &ZoneRecord) -> Value {
    json!({
        "zone_id": zone.zone_id,
        "name": zone.name,
        "points": zone.points.iter().map(|point| {
            json!({"lat": point.lat, "lon": point.lon})
        }).collect::<Vec<_>>(),
        "created_at": iso8601_from_unix_ms(zone.created_ts_ms),
        "updated_at": iso8601_from_unix_ms(zone.updated_ts_ms)
    })
}

fn validate_zone_points(points: &[ZonePointRecord]) -> Result<(), ApiError> {
    if points.len() < 3 {
        return Err(ApiError::Unprocessable(
            "Zone must include at least 3 points".to_string(),
        ));
    }
    if points.len() > 200 {
        return Err(ApiError::Unprocessable(
            "Zone must include no more than 200 points".to_string(),
        ));
    }
    for point in points {
        validate_lat_lon(point.lat, point.lon)?;
    }
    Ok(())
}

