fn checklist_command(state: &AppState, command_type: &str, args: Value) -> Result<Value, ApiError> {
    let path = state
        .sqlite_path
        .as_ref()
        .ok_or_else(|| ApiError::ServiceUnavailable("Checklist writes unavailable".to_string()))?;
    let started = Instant::now();
    let is_read_only = checklist_command_is_read_only(command_type);
    let command = MissionCommandEnvelope {
        command_id: Uuid::new_v4().to_string(),
        source: RchSource::new("rust-rch-http"),
        timestamp: OffsetDateTime::now_utc()
            .format(&Rfc3339)
            .unwrap_or_else(|_| "1970-01-01T00:00:00Z".to_string()),
        command_type: command_type.to_string(),
        args,
        correlation_id: None,
        topics: Vec::new(),
    };
    if is_read_only {
        let store = RchSqliteStore::open_read_only(path.as_ref())
            .map_err(|error| ApiError::Internal(error.to_string()))?;
        let snapshot = store
            .load_checklist_command_snapshot()
            .map_err(|error| ApiError::Internal(error.to_string()))?;
        let mut core = RchCore::from_snapshot(snapshot.clone())
            .map_err(|error| ApiError::Internal(error.to_string()))?;
        let outcome = core.handle_command(&command);
        record_sqlite_latency(state, started.elapsed());
        return checklist_command_outcome_value(outcome);
    }
    let (outcome, mission_changes_after) = {
        let mut store = RchSqliteStore::open(path.as_ref())
            .map_err(|error| ApiError::Internal(error.to_string()))?;
        let snapshot = store
            .load_checklist_command_snapshot()
            .map_err(|error| ApiError::Internal(error.to_string()))?;
        let mut core = RchCore::from_snapshot(snapshot.clone())
            .map_err(|error| ApiError::Internal(error.to_string()))?;
        let mission_change_uids_before = mission_change_uid_set(&core);
        let outcome = core.handle_command(&command);
        let mission_changes_after = if outcome.result.status == CommandResultStatus::Accepted {
            let mission_changes_after =
                mission_change_payload_map_excluding(&core, &mission_change_uids_before);
            let after = core.snapshot();
            store
                .save_checklist_command_delta(&snapshot, &after)
                .map_err(|error| ApiError::Internal(error.to_string()))?;
            mission_changes_after
        } else {
            HashMap::new()
        };
        (outcome, mission_changes_after)
    };
    record_sqlite_latency(state, started.elapsed());
    if outcome.result.status == CommandResultStatus::Accepted {
        spawn_mission_change_listener_events(state, HashMap::new(), mission_changes_after)?;
        return Ok(outcome.result.result);
    }
    checklist_command_outcome_value(outcome)
}

fn checklist_command_is_read_only(command_type: &str) -> bool {
    matches!(
        command_type,
        "checklist.template.list" | "checklist.template.get"
    )
}

fn checklist_command_outcome_value(
    outcome: r3akt_rch_core::RchCommandOutcome,
) -> Result<Value, ApiError> {
    if outcome.result.status == CommandResultStatus::Accepted {
        return Ok(outcome.result.result);
    }
    let detail = outcome
        .result
        .detail
        .or(outcome.result.reason)
        .unwrap_or_else(|| "Checklist command rejected".to_string());
    let detail = detail
        .strip_prefix("invalid payload: ")
        .unwrap_or(detail.as_str())
        .to_string();
    if detail.contains(" not found") {
        Err(ApiError::NotFound(format!("\"{detail}\"")))
    } else {
        Err(ApiError::BadRequest(detail))
    }
}

async fn list_r3akt_domain_events(
    State(state): State<AppState>,
    Query(query): Query<R3aktHistoryQuery>,
) -> Result<Json<Value>, ApiError> {
    let limit = validate_r3akt_limit(query.limit)?;
    if state.sqlite_path.is_none() {
        return Ok(Json(json!([])));
    }
    let path = state
        .sqlite_path
        .as_ref()
        .ok_or_else(|| ApiError::ServiceUnavailable("R3AKT reads unavailable".to_string()))?;
    let store = RchSqliteStore::open(path.as_ref())
        .map_err(|error| ApiError::Internal(error.to_string()))?;
    let payload = store
        .load_audit_events_desc(limit)
        .map_err(|error| ApiError::Internal(error.to_string()))?
        .into_iter()
        .map(|event| r3akt_domain_event_value(event, query.include_payload.unwrap_or(true)))
        .collect::<Vec<_>>();
    Ok(Json(json!(payload)))
}

async fn list_r3akt_domain_snapshots(
    State(state): State<AppState>,
    Query(query): Query<R3aktHistoryQuery>,
) -> Result<Json<Value>, ApiError> {
    let _limit = validate_r3akt_limit(query.limit)?;
    if state.sqlite_path.is_none() {
        return Ok(Json(json!([])));
    }
    let path = state
        .sqlite_path
        .as_ref()
        .ok_or_else(|| ApiError::ServiceUnavailable("R3AKT reads unavailable".to_string()))?;
    let store = RchSqliteStore::open(path.as_ref())
        .map_err(|error| ApiError::Internal(error.to_string()))?;
    let snapshot = store
        .load_r3akt_read_snapshot()
        .map_err(|error| ApiError::Internal(error.to_string()))?;
    if rch_snapshot_is_empty(&snapshot) {
        return Ok(Json(json!([])));
    }
    let created_ts_ms = store
        .load_audit_events_desc(1)
        .map_err(|error| ApiError::Internal(error.to_string()))?
        .first()
        .map_or_else(unix_now_ms, |event| event.timestamp_ms);
    let payload = vec![json!({
        "snapshot_uid": "rust-rch-core-snapshot",
        "domain": "r3akt",
        "aggregate_type": "rch_core",
        "aggregate_uid": "state",
        "version": 1,
        "state": snapshot,
        "created_at": iso8601_from_unix_ms(created_ts_ms),
    })];
    Ok(Json(json!(payload)))
}

fn validate_r3akt_limit(limit: Option<i64>) -> Result<usize, ApiError> {
    let limit = limit.unwrap_or(200);
    if !(1..=2000).contains(&limit) {
        return Err(ApiError::Unprocessable(
            "limit must be greater than or equal to 1 and less than or equal to 2000".to_string(),
        ));
    }
    usize::try_from(limit).map_err(|error| ApiError::Internal(error.to_string()))
}

fn r3akt_domain_event_value(event: MissionAuditEvent, include_payload: bool) -> Value {
    let (aggregate_type, aggregate_uid) = r3akt_domain_event_aggregate(&event);
    let mut value = json!({
        "event_uid": event.event_id,
        "domain": "r3akt",
        "aggregate_type": aggregate_type,
        "aggregate_uid": aggregate_uid,
        "event_type": event.event_type,
        "payload_summary": r3akt_domain_event_payload_summary(&event.payload),
        "created_at": iso8601_from_unix_ms(event.timestamp_ms),
    });
    if include_payload {
        value["payload"] = event.payload;
    }
    value
}

fn r3akt_domain_event_payload_summary(payload: &Value) -> Value {
    const SUMMARY_KEYS: &[&str] = &[
        "mission_uid",
        "mission_id",
        "uid",
        "name",
        "notes",
        "team_uid",
        "team_member_uid",
        "asset_uid",
        "assignment_uid",
        "checklist_uid",
        "checklist_id",
        "task_uid",
        "eam_uid",
    ];
    let Some(object) = payload.as_object() else {
        return json!({});
    };
    let summary = SUMMARY_KEYS
        .iter()
        .filter_map(|key| {
            object
                .get(*key)
                .map(|value| ((*key).to_string(), value.clone()))
        })
        .collect::<serde_json::Map<String, Value>>();
    Value::Object(summary)
}

fn r3akt_domain_event_aggregate(event: &MissionAuditEvent) -> (String, String) {
    let payload = &event.payload;
    let aggregate_uid = [
        "mission_uid",
        "uid",
        "team_uid",
        "team_member_uid",
        "asset_uid",
        "assignment_uid",
        "checklist_id",
        "eam_uid",
    ]
    .into_iter()
    .find_map(|key| payload.get(key).and_then(Value::as_str))
    .unwrap_or(event.command_id.as_str())
    .to_string();
    let aggregate_type = event
        .event_type
        .split('.')
        .next()
        .filter(|value| !value.is_empty())
        .unwrap_or("command")
        .to_string();
    (aggregate_type, aggregate_uid)
}

