async fn list_r3akt_operation_rights(
    State(state): State<AppState>,
    Query(query): Query<HashMap<String, String>>,
) -> Result<Json<Value>, ApiError> {
    if state.sqlite_path.is_none() {
        return Ok(Json(json!([])));
    }
    let subject_type = query.get("subject_type").map(|value| value.to_lowercase());
    if subject_type.is_none() && query.contains_key("subject_id") {
        return Err(ApiError::BadRequest(
            "subject_type is required when subject_id is provided".to_string(),
        ));
    }
    let subject_id = subject_type
        .as_deref()
        .zip(query.get("subject_id"))
        .map(|(subject_type, subject_id)| normalize_subject_id_text(subject_type, subject_id));
    let operation = query.get("operation").map(|value| value.trim().to_string());
    let scope = if query.contains_key("scope_type") || query.contains_key("scope_id") {
        Some((
            query
                .get("scope_type")
                .map_or_else(|| "global".to_string(), |value| value.trim().to_lowercase()),
            query
                .get("scope_id")
                .map_or_else(String::new, |value| value.trim().to_string()),
        ))
    } else {
        None
    };
    let payload = with_r3akt_core(&state, false, |core| {
        let rows = core
            .snapshot()
            .subject_operation_rights
            .into_iter()
            .filter(|right| {
                subject_type
                    .as_ref()
                    .is_none_or(|value| right.subject_type == *value)
                    && subject_id
                        .as_ref()
                        .is_none_or(|value| right.subject_id == *value)
                    && operation
                        .as_ref()
                        .is_none_or(|value| right.operation == *value)
                    && scope.as_ref().is_none_or(|(scope_type, scope_id)| {
                        right.scope_type == *scope_type && right.scope_id == *scope_id
                    })
            })
            .map(|right| operation_right_value(&right))
            .collect::<Vec<_>>();
        Ok(json!(rows))
    })?;
    Ok(Json(payload))
}

async fn grant_r3akt_operation_right(
    State(state): State<AppState>,
    Json(payload): Json<Value>,
) -> Result<Json<Value>, ApiError> {
    upsert_r3akt_operation_right(state, payload, true).map(Json)
}

async fn revoke_r3akt_operation_right(
    State(state): State<AppState>,
    Json(payload): Json<Value>,
) -> Result<Json<Value>, ApiError> {
    upsert_r3akt_operation_right(state, payload, false).map(Json)
}

fn upsert_r3akt_operation_right(
    state: AppState,
    payload: Value,
    granted: bool,
) -> Result<Value, ApiError> {
    if state.sqlite_path.is_none() {
        return Err(ApiError::ServiceUnavailable(
            "R3AKT HTTP writes unavailable".to_string(),
        ));
    }
    let subject_type = required_json_text(&payload, "subject_type")?;
    let subject_id = required_json_text(&payload, "subject_id")?;
    let operation = required_json_text(&payload, "operation")?;
    let scope_type =
        optional_json_text(&payload, "scope_type").unwrap_or_else(|| "global".to_string());
    let scope_id = optional_json_text(&payload, "scope_id").unwrap_or_default();
    let record = with_r3akt_core(&state, true, |core| {
        if granted {
            core.grant_operation_right(
                &subject_type,
                &subject_id,
                &operation,
                &scope_type,
                &scope_id,
            )
        } else {
            core.revoke_operation_right(
                &subject_type,
                &subject_id,
                &operation,
                &scope_type,
                &scope_id,
            )
        }
        .map_err(r3akt_core_error)
    })?;
    Ok(operation_right_value(&record))
}

