fn open_r3akt_read_store(state: &AppState) -> Result<RchSqliteStore, ApiError> {
    let path = state
        .sqlite_path
        .as_ref()
        .ok_or_else(|| ApiError::ServiceUnavailable("R3AKT reads unavailable".to_string()))?;
    RchSqliteStore::open_read_only(path.as_ref())
        .map_err(|error| ApiError::Internal(error.to_string()))
}

fn with_r3akt_core<T>(
    state: &AppState,
    write: bool,
    f: impl FnOnce(&mut RchCore) -> Result<T, ApiError>,
) -> Result<T, ApiError> {
    let path = state
        .sqlite_path
        .as_ref()
        .ok_or_else(|| ApiError::ServiceUnavailable("R3AKT HTTP writes unavailable".to_string()))?;
    let started = Instant::now();
    let mut store = if write {
        RchSqliteStore::open(path.as_ref())
    } else {
        RchSqliteStore::open_read_only(path.as_ref())
    }
    .map_err(|error| ApiError::Internal(error.to_string()))?;
    let snapshot = store
        .load_r3akt_read_snapshot()
        .map_err(|error| ApiError::Internal(error.to_string()))?;
    let mut core = RchCore::from_snapshot(snapshot.clone())
        .map_err(|error| ApiError::Internal(error.to_string()))?;
    let result = f(&mut core)?;
    if write {
        let after = core.snapshot();
        store
            .save_r3akt_command_delta(&snapshot, &after)
            .map_err(|error| ApiError::Internal(error.to_string()))?;
    }
    record_sqlite_latency(state, started.elapsed());
    Ok(result)
}

fn r3akt_command(state: &AppState, command_type: &str, args: Value) -> Result<Value, ApiError> {
    let path = state
        .sqlite_path
        .as_ref()
        .ok_or_else(|| ApiError::ServiceUnavailable("R3AKT HTTP writes unavailable".to_string()))?;
    let started = Instant::now();
    let is_read_only = r3akt_command_is_read_only(command_type);
    let command = MissionCommandEnvelope {
        command_id: Uuid::new_v4().to_string(),
        source: RchSource::new("rust-rch-http"),
        timestamp: OffsetDateTime::now_utc()
            .format(&Rfc3339)
            .unwrap_or_else(|_| "1970-01-01T00:00:00Z".to_string()),
        command_type: command_type.to_string(),
        args,
        correlation_id: None,
        topics: Vec::new(),
    };
    if is_read_only {
        let store = RchSqliteStore::open_read_only(path.as_ref())
            .map_err(|error| ApiError::Internal(error.to_string()))?;
        let snapshot = store
            .load_r3akt_read_snapshot()
            .map_err(|error| ApiError::Internal(error.to_string()))?;
        let mut core = RchCore::from_snapshot(snapshot)
            .map_err(|error| ApiError::Internal(error.to_string()))?;
        let outcome = core.handle_command(&command);
        record_sqlite_latency(state, started.elapsed());
        return r3akt_command_outcome_value(outcome);
    }
    let (outcome, mission_changes_before, mission_changes_after) = {
        let mut store = RchSqliteStore::open(path.as_ref())
            .map_err(|error| ApiError::Internal(error.to_string()))?;
        let snapshot = store
            .load_r3akt_read_snapshot()
            .map_err(|error| ApiError::Internal(error.to_string()))?;
        let mut core = RchCore::from_snapshot(snapshot.clone())
            .map_err(|error| ApiError::Internal(error.to_string()))?;
        let mission_changes_before = mission_change_payload_map(&core);
        let outcome = core.handle_command(&command);
        let mission_changes_after = if outcome.result.status == CommandResultStatus::Accepted {
            let mission_changes_after = mission_change_payload_map(&core);
            let after = core.snapshot();
            store
                .save_r3akt_command_delta(&snapshot, &after)
                .map_err(|error| ApiError::Internal(error.to_string()))?;
            mission_changes_after
        } else {
            HashMap::new()
        };
        (outcome, mission_changes_before, mission_changes_after)
    };
    record_sqlite_latency(state, started.elapsed());
    if outcome.result.status == CommandResultStatus::Accepted {
        spawn_mission_change_listener_events(state, mission_changes_before, mission_changes_after)?;
        return Ok(outcome.result.result);
    }
    r3akt_command_outcome_value(outcome)
}

fn r3akt_command_is_read_only(command_type: &str) -> bool {
    command_type.ends_with(".list")
        || command_type.ends_with(".get")
        || matches!(
            command_type,
            "mission.registry.eam.latest" | "mission.registry.eam.team.summary"
        )
}

fn r3akt_command_outcome_value(
    outcome: r3akt_rch_core::RchCommandOutcome,
) -> Result<Value, ApiError> {
    if outcome.result.status == CommandResultStatus::Accepted {
        return Ok(outcome.result.result);
    }
    let detail = outcome
        .result
        .detail
        .or(outcome.result.reason)
        .unwrap_or_else(|| "R3AKT command rejected".to_string());
    let detail = detail
        .strip_prefix("invalid command payload: ")
        .or_else(|| detail.strip_prefix("invalid payload: "))
        .unwrap_or(detail.as_str())
        .to_string();
    if detail.contains("not found") {
        Err(ApiError::NotFound(format!("\"{detail}\"")))
    } else {
        Err(ApiError::BadRequest(detail))
    }
}

fn r3akt_core_error(error: r3akt_rch_core::RchCoreError) -> ApiError {
    let detail = error.to_string();
    if detail.contains("not found") {
        ApiError::NotFound(format!("\"{detail}\""))
    } else {
        ApiError::BadRequest(detail)
    }
}

fn required_json_text(payload: &Value, key: &str) -> Result<String, ApiError> {
    optional_json_text(payload, key)
        .ok_or_else(|| ApiError::BadRequest(format!("{key} is required")))
}

fn optional_json_text(payload: &Value, key: &str) -> Option<String> {
    payload
        .get(key)
        .and_then(Value::as_str)
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(ToString::to_string)
}

fn normalize_identity_text(identity: &str) -> String {
    identity.trim().to_lowercase()
}

fn normalize_subject_id_text(subject_type: &str, subject_id: &str) -> String {
    if subject_type == "identity" {
        normalize_identity_text(subject_id)
    } else {
        subject_id.trim().to_string()
    }
}

fn operation_right_value(right: &SubjectOperationRight) -> Value {
    json!({
        "grant_uid": right.grant_uid,
        "subject_type": right.subject_type,
        "subject_id": right.subject_id,
        "operation": right.operation,
        "scope_type": right.scope_type,
        "scope_id": right.scope_id,
        "granted": right.granted,
        "granted_by": Value::Null,
        "granted_at": Value::Null,
        "expires_at": Value::Null,
        "updated_at": Value::Null,
    })
}

fn capability_grant_value(right: &SubjectOperationRight) -> Value {
    json!({
        "grant_uid": right.grant_uid,
        "identity": right.subject_id,
        "capability": right.operation,
        "granted": right.granted,
        "granted_by": Value::Null,
        "granted_at": Value::Null,
        "expires_at": Value::Null,
        "updated_at": Value::Null,
    })
}

