async fn dump_routing(State(state): State<AppState>) -> Result<Json<Value>, ApiError> {
    let mut destinations = state
        .clients
        .read()
        .map_err(|error| ApiError::Internal(error.to_string()))?
        .values()
        .map(|client| client.identity.clone())
        .collect::<Vec<_>>();
    destinations.sort();
    Ok(Json(json!({ "destinations": destinations })))
}

async fn flush_telemetry(State(state): State<AppState>) -> Result<Json<Value>, ApiError> {
    let deleted = {
        let mut records = state
            .telemetry_records
            .write()
            .map_err(|error| ApiError::Internal(error.to_string()))?;
        let deleted = records.len();
        records.clear();
        deleted
    };
    let _ = record_system_event(
        &state,
        "telemetry_flushed",
        &format!("Telemetry flushed ({deleted} rows)"),
        json!({ "deleted": deleted }),
    )?;
    Ok(Json(json!({ "deleted": deleted })))
}

async fn reload_config(State(state): State<AppState>) -> Result<Json<Value>, ApiError> {
    let payload = app_info_payload(&state);
    let _ = record_system_event(
        &state,
        "config_reloaded",
        "Configuration reloaded",
        json!({ "config_path": state.config_path.as_deref().map(|path| path.display().to_string()) }),
    )?;
    Ok(Json(payload))
}

async fn control_status(State(state): State<AppState>) -> Result<Json<Value>, ApiError> {
    Ok(Json(control_status_payload(&state)?))
}

async fn control_stop(State(state): State<AppState>) -> Result<Json<Value>, ApiError> {
    {
        let mut control = state
            .runtime_control
            .write()
            .map_err(|error| ApiError::Internal(error.to_string()))?;
        control.status = "stopping".to_string();
        control.shutdown_requested = true;
        control.last_stop_ts_ms = Some(unix_now_ms());
    }
    stop_runtime_services(&state)?;
    let _ = record_system_event(
        &state,
        "control_stop_requested",
        "Rust runtime stop requested",
        json!({ "status": "stopping" }),
    );
    Ok(Json(json!({ "status": "stopping" })))
}

async fn control_start(State(state): State<AppState>) -> Result<Json<Value>, ApiError> {
    {
        let mut control = state
            .runtime_control
            .write()
            .map_err(|error| ApiError::Internal(error.to_string()))?;
        control.status = "running".to_string();
        control.shutdown_requested = false;
        control.last_start_ts_ms = Some(unix_now_ms());
    }
    start_runtime_services(&state)?;
    let _ = record_system_event(
        &state,
        "control_start_requested",
        "Rust runtime start requested",
        json!({ "status": "running" }),
    );
    Ok(Json(control_status_payload(&state)?))
}

fn stop_runtime_services(state: &AppState) -> Result<(), ApiError> {
    state
        .stop_managed_reticulumd()
        .map_err(ApiError::ServiceUnavailable)?;
    Ok(())
}

fn start_runtime_services(state: &AppState) -> Result<(), ApiError> {
    state
        .start_managed_reticulumd()
        .map_err(ApiError::ServiceUnavailable)?;
    Ok(())
}

async fn control_announce(State(state): State<AppState>) -> Result<Json<Value>, ApiError> {
    let announce_id = if let Some(endpoint) = &state.reticulumd_rpc_endpoint {
        let mut client = r3akt_rch_bridge::ReticulumdRpcClient::new(endpoint.as_str());
        let response = control_announce_call_with_fallback(&mut client)?;
        response
            .result
            .as_ref()
            .and_then(|result| result.get("announce_id"))
            .cloned()
            .unwrap_or(Value::Null)
    } else if let (Some(command_endpoint), Some(response_endpoint)) = (
        &state.lxmf_zmq_command_endpoint,
        &state.lxmf_zmq_response_endpoint,
    ) {
        announce_lxmf_zmq_identity(command_endpoint.as_str(), response_endpoint.as_str())
            .map_err(|error| ApiError::ServiceUnavailable(error.to_string()))?
            .map(Value::String)
            .unwrap_or(Value::Null)
    } else {
        return Err(ApiError::ServiceUnavailable(
            "Announce unavailable".to_string(),
        ));
    };
    let _ = record_system_event(
        &state,
        "control_announce_requested",
        "Rust runtime Reticulum announce requested",
        json!({ "announce_id": announce_id }),
    );
    Ok(Json(json!({ "status": "announce sent" })))
}

fn control_announce_call_with_fallback(
    client: &mut ReticulumdRpcClient,
) -> Result<r3akt_rch_bridge::ReticulumdRpcResponse, ApiError> {
    let response = client
        .call("sdk_identity_announce_now_v2", Some(json!({})))
        .map_err(|error| ApiError::ServiceUnavailable(error.to_string()))?;
    if let Some(error) = response.error {
        if reticulumd_identity_announce_capability_disabled(&error) {
            let fallback = client
                .call("announce_now", None)
                .map_err(|error| ApiError::ServiceUnavailable(error.to_string()))?;
            if let Some(error) = fallback.error {
                return Err(ApiError::ServiceUnavailable(format!(
                    "{}: {}",
                    error.code, error.message
                )));
            }
            return Ok(fallback);
        }
        return Err(ApiError::ServiceUnavailable(format!(
            "{}: {}",
            error.code, error.message
        )));
    }
    Ok(response)
}

fn reticulumd_identity_announce_capability_disabled(
    error: &r3akt_rch_bridge::ReticulumdRpcError,
) -> bool {
    error.code == "SDK_CAPABILITY_DISABLED"
        && error
            .message
            .to_ascii_lowercase()
            .contains("identity_discovery")
}

async fn control_sync(State(state): State<AppState>) -> Result<Json<Value>, ApiError> {
    let Some(endpoint) = &state.reticulumd_rpc_endpoint else {
        return Err(ApiError::ServiceUnavailable("Sync unavailable".to_string()));
    };
    let mut client = r3akt_rch_bridge::ReticulumdRpcClient::new(endpoint.as_str());
    let propagation_nodes = client
        .call("list_propagation_nodes", None)
        .map_err(|error| ApiError::ServiceUnavailable(error.to_string()))?;
    if let Some(error) = propagation_nodes.error {
        return Err(ApiError::ServiceUnavailable(format!(
            "{}: {}",
            error.code, error.message
        )));
    }
    let peer = propagation_nodes
        .result
        .as_ref()
        .and_then(first_reticulumd_propagation_node)
        .ok_or_else(|| ApiError::ServiceUnavailable("No reachable propagation node".to_string()))?;
    let sync = client
        .call("peer_sync", Some(json!({ "peer": peer })))
        .map_err(|error| ApiError::ServiceUnavailable(error.to_string()))?;
    if let Some(error) = sync.error {
        return Err(ApiError::ServiceUnavailable(format!(
            "{}: {}",
            error.code, error.message
        )));
    }
    let selected = client
        .call(
            "set_outbound_propagation_node",
            Some(json!({ "peer": peer })),
        )
        .map_err(|error| ApiError::ServiceUnavailable(error.to_string()))?;
    if let Some(error) = selected.error {
        return Err(ApiError::ServiceUnavailable(format!(
            "{}: {}",
            error.code, error.message
        )));
    }
    let fetch_result = match client.call(
        "propagation_remote_fetch",
        Some(json!({
            "remote": peer,
            "timeout_secs": 45.0,
            "transfer_limit_kb": 10_240.0,
        })),
    ) {
        Ok(fetch) => {
            if let Some(error) = fetch.error {
                json!({
                    "status": "failed",
                    "error": format!("{}: {}", error.code, error.message),
                })
            } else {
                fetch.result.unwrap_or_else(|| json!({}))
            }
        }
        Err(error) => json!({
            "status": "failed",
            "error": error.to_string(),
        }),
    };
    let rpc_result = sync.result.unwrap_or_else(|| json!({}));
    let payload = json!({
        "status": "sync_requested",
        "reason": "manual",
        "propagation_node": peer,
        "rpc_result": rpc_result,
        "fetch_result": fetch_result,
    });
    let _ = record_system_event(
        &state,
        "control_sync_requested",
        "Rust runtime propagation sync requested",
        payload.clone(),
    );
    Ok(Json(payload))
}

fn first_reticulumd_propagation_node(result: &Value) -> Option<String> {
    result
        .get("nodes")
        .and_then(Value::as_array)?
        .iter()
        .find_map(|node| {
            node.as_str().map(str::to_string).or_else(|| {
                ["peer", "destination_hash", "node", "identity"]
                    .iter()
                    .find_map(|key| node.get(*key).and_then(Value::as_str).map(str::to_string))
            })
        })
}

fn control_status_payload(state: &AppState) -> Result<Value, ApiError> {
    let control = state
        .runtime_control
        .read()
        .map_err(|error| ApiError::Internal(error.to_string()))?
        .clone();
    Ok(json!({
        "status": control.status,
        "pid": std::process::id(),
        "host": null,
        "port": null,
        "uptime_seconds": runtime_uptime_seconds(control.started_ts_ms),
        "hub_thread_alive": control.status == "running",
        "shutdown_requested": control.shutdown_requested,
        "started_at": iso8601_from_unix_ms(control.started_ts_ms),
        "last_start_at": control.last_start_ts_ms.map(iso8601_from_unix_ms),
        "last_stop_at": control.last_stop_ts_ms.map(iso8601_from_unix_ms),
        "reticulumd_rpc_configured": state.reticulumd_rpc_endpoint.is_some(),
        "services": runtime_services_payload(state),
        "propagation": null,
    }))
}

fn runtime_uptime_seconds(started_ts_ms: i64) -> i64 {
    unix_now_ms().saturating_sub(started_ts_ms) / 1000
}

async fn reticulum_interface_capabilities(State(state): State<AppState>) -> Json<Value> {
    Json(reticulum_interface_capabilities_payload(&state))
}

async fn reticulum_discovery(State(state): State<AppState>) -> Json<Value> {
    Json(reticulum_discovery_payload(&state))
}

fn reticulum_interface_capabilities_payload(state: &AppState) -> Value {
    let all_types = reticulum_known_interface_types();
    let Some(runtime) = reticulum_runtime_snapshot(state) else {
        return json!({
            "runtime_active": false,
            "os": std::env::consts::OS,
            "identity_hash_hex_length": 0,
            "supported_interface_types": [],
            "unsupported_interface_types": all_types,
            "discoverable_interface_types": [],
            "autoconnect_interface_types": [],
            "rns_version": "unavailable"
        });
    };
    let mut supported_interface_types = runtime
        .interfaces
        .iter()
        .filter_map(reticulum_interface_type_name)
        .collect::<Vec<_>>();
    supported_interface_types.sort();
    supported_interface_types.dedup();

    let unsupported_interface_types = all_types
        .iter()
        .filter(|interface_type| !supported_interface_types.contains(interface_type))
        .cloned()
        .collect::<Vec<_>>();
    let discoverable_interface_types = supported_interface_types
        .iter()
        .filter(|interface_type| {
            matches!(
                interface_type.as_str(),
                "TCPClientInterface" | "TCPServerInterface" | "UDPInterface"
            )
        })
        .cloned()
        .collect::<Vec<_>>();
    let autoconnect_interface_types = supported_interface_types
        .iter()
        .filter(|interface_type| interface_type.as_str() == "TCPClientInterface")
        .cloned()
        .collect::<Vec<_>>();

    json!({
        "runtime_active": true,
        "os": std::env::consts::OS,
        "identity_hash_hex_length": runtime.identity_hash_hex_length(),
        "supported_interface_types": supported_interface_types,
        "unsupported_interface_types": unsupported_interface_types,
        "discoverable_interface_types": discoverable_interface_types,
        "autoconnect_interface_types": autoconnect_interface_types,
        "rns_version": runtime.rns_version()
    })
}

fn reticulum_discovery_payload(state: &AppState) -> Value {
    let Some(runtime) = reticulum_runtime_snapshot(state) else {
        return json!({
            "runtime_active": false,
            "should_autoconnect": false,
            "max_autoconnected_interfaces": null,
            "required_discovery_value": null,
            "interface_discovery_sources": [],
            "discovered_interfaces": [],
            "refreshed_at": iso8601_from_unix_ms(unix_now_ms())
        });
    };
    let discovered_interfaces = runtime
        .interfaces
        .iter()
        .enumerate()
        .map(|(index, interface)| normalize_reticulum_discovery_interface(index, interface))
        .collect::<Vec<_>>();

    json!({
        "runtime_active": true,
        "should_autoconnect": runtime.status_bool("should_autoconnect").unwrap_or(false),
        "max_autoconnected_interfaces": runtime.status_value("max_autoconnected_interfaces").unwrap_or(Value::Null),
        "required_discovery_value": runtime.status_value("required_discovery_value").unwrap_or(Value::Null),
        "interface_discovery_sources": runtime.status_array("interface_discovery_sources"),
        "discovered_interfaces": discovered_interfaces,
        "refreshed_at": iso8601_from_unix_ms(unix_now_ms())
    })
}

#[derive(Debug)]
struct ReticulumRuntimeSnapshot {
    status: Option<Value>,
    interfaces: Vec<Value>,
}

impl ReticulumRuntimeSnapshot {
    fn identity_hash_hex_length(&self) -> usize {
        self.status
            .as_ref()
            .and_then(reticulum_identity_hash)
            .map(|hash| hash.len())
            .unwrap_or(0)
    }

    fn rns_version(&self) -> String {
        self.status
            .as_ref()
            .and_then(|status| {
                ["rns_version", "reticulum_version", "version"]
                    .iter()
                    .find_map(|key| status.get(*key).and_then(Value::as_str))
            })
            .unwrap_or("unavailable")
            .to_string()
    }

    fn status_bool(&self, key: &str) -> Option<bool> {
        self.status
            .as_ref()
            .and_then(|status| status.get(key))
            .and_then(Value::as_bool)
    }

    fn status_value(&self, key: &str) -> Option<Value> {
        self.status
            .as_ref()
            .and_then(|status| status.get(key))
            .cloned()
    }

    fn status_array(&self, key: &str) -> Vec<Value> {
        self.status
            .as_ref()
            .and_then(|status| status.get(key))
            .and_then(Value::as_array)
            .cloned()
            .unwrap_or_default()
    }
}

fn reticulum_runtime_snapshot(state: &AppState) -> Option<ReticulumRuntimeSnapshot> {
    let endpoint = state.reticulumd_rpc_endpoint.as_ref()?;
    let mut client = r3akt_rch_bridge::ReticulumdRpcClient::new(endpoint.as_str());
    let status = call_first_successful_reticulumd_status(&mut client);
    let interfaces = client
        .call("list_interfaces", None)
        .ok()
        .and_then(|response| response.result)
        .and_then(|result| result.get("interfaces").and_then(Value::as_array).cloned())
        .unwrap_or_default();
    if status.is_none() && interfaces.is_empty() {
        return None;
    }
    Some(ReticulumRuntimeSnapshot { status, interfaces })
}

fn call_first_successful_reticulumd_status(
    client: &mut r3akt_rch_bridge::ReticulumdRpcClient,
) -> Option<Value> {
    ["daemon_status_ex", "status"].iter().find_map(|method| {
        let response = client.call(method, None).ok()?;
        if response.error.is_some() {
            return None;
        }
        response.result
    })
}

fn reticulum_identity_hash(status: &Value) -> Option<String> {
    status
        .get("identity_hash")
        .or_else(|| status.get("identity"))
        .or_else(|| status.get("destination_hash"))
        .and_then(Value::as_str)
        .map(str::to_string)
}

fn reticulum_known_interface_types() -> Vec<String> {
    [
        "AX25KISSInterface",
        "AutoInterface",
        "BackboneInterface",
        "I2PInterface",
        "KISSInterface",
        "PipeInterface",
        "RNodeIPInterface",
        "RNodeInterface",
        "RNodeMultiInterface",
        "SerialInterface",
        "TCPClientInterface",
        "TCPServerInterface",
        "UDPInterface",
    ]
    .iter()
    .map(|value| (*value).to_string())
    .collect()
}

fn reticulum_interface_type_name(interface: &Value) -> Option<String> {
    let kind = interface
        .get("type")
        .or_else(|| interface.get("kind"))
        .and_then(Value::as_str)?;
    Some(
        match kind {
            "tcp_client" | "TCPClientInterface" => "TCPClientInterface",
            "tcp_server" | "TCPServerInterface" => "TCPServerInterface",
            "udp" | "udp_interface" | "UDPInterface" => "UDPInterface",
            "serial" | "SerialInterface" => "SerialInterface",
            "kiss" | "KISSInterface" => "KISSInterface",
            "ax25_kiss" | "AX25KISSInterface" => "AX25KISSInterface",
            "pipe" | "PipeInterface" => "PipeInterface",
            "rnode" | "RNodeInterface" => "RNodeInterface",
            "rnode_multi" | "RNodeMultiInterface" => "RNodeMultiInterface",
            "rnode_ip" | "RNodeIPInterface" => "RNodeIPInterface",
            "i2p" | "I2PInterface" => "I2PInterface",
            "backbone" | "BackboneInterface" => "BackboneInterface",
            "auto" | "AutoInterface" => "AutoInterface",
            other => other,
        }
        .to_string(),
    )
}

fn normalize_reticulum_discovery_interface(index: usize, interface: &Value) -> Value {
    let settings = interface.get("settings").and_then(Value::as_object);
    let runtime = settings.and_then(|settings| settings.get("_runtime"));
    let raw_status = runtime
        .and_then(|runtime| runtime.get("startup_status"))
        .or_else(|| interface.get("status"))
        .cloned()
        .unwrap_or(Value::Null);
    let has_runtime_handle = runtime
        .and_then(|runtime| runtime.get("iface"))
        .and_then(Value::as_str)
        .is_some_and(|value| !value.trim().is_empty());
    let enabled = interface
        .get("enabled")
        .or_else(|| interface.get("interface_enabled"))
        .and_then(Value::as_bool)
        .unwrap_or(true);
    let status = raw_status
        .as_str()
        .is_some_and(|value| value.eq_ignore_ascii_case("spawned"))
        .then_some(())
        .filter(|_| enabled && has_runtime_handle)
        .map_or_else(|| raw_status.clone(), |_| json!("active"));
    let name = interface
        .get("name")
        .and_then(Value::as_str)
        .map(str::to_string)
        .unwrap_or_else(|| format!("interface-{index}"));
    let transport = interface
        .get("type")
        .or_else(|| interface.get("kind"))
        .cloned()
        .unwrap_or(Value::Null);
    let interface_type = reticulum_interface_type_name(interface)
        .map(Value::String)
        .unwrap_or(Value::Null);
    let discovery_hash = interface
        .get("discovery_hash")
        .or_else(|| interface.get("id"))
        .and_then(Value::as_str)
        .map(str::to_string)
        .unwrap_or_else(|| name.clone());

    json!({
        "discovery_hash": discovery_hash,
        "status": status,
        "raw_status": raw_status,
        "status_code": null,
        "type": interface_type,
        "name": name,
        "transport": transport,
        "transport_id": runtime.and_then(|runtime| runtime.get("iface")).cloned().unwrap_or(Value::Null),
        "network_id": interface.get("network_id").cloned().unwrap_or(Value::Null),
        "hops": null,
        "value": null,
        "received": null,
        "last_heard": null,
        "heard_count": null,
        "reachable_on": interface.get("host").or_else(|| interface.get("target_host")).cloned().unwrap_or(Value::Null),
        "port": interface.get("port").or_else(|| interface.get("target_port")).cloned().unwrap_or(Value::Null),
        "config_entry": interface,
    })
}

async fn config_text(State(state): State<AppState>) -> Result<impl IntoResponse, ApiError> {
    let body = read_config_file(state.config_path.as_deref())?;
    Ok(([(header::CONTENT_TYPE, "text/plain; charset=utf-8")], body))
}

async fn reticulum_config_text(
    State(state): State<AppState>,
) -> Result<impl IntoResponse, ApiError> {
    let body = read_config_file(state.reticulum_config_path.as_deref())?;
    Ok(([(header::CONTENT_TYPE, "text/plain; charset=utf-8")], body))
}

fn read_config_file(path: Option<&PathBuf>) -> Result<String, ApiError> {
    let Some(path) = path else {
        return Ok(String::new());
    };
    if !path.exists() {
        return Ok(String::new());
    }
    std::fs::read_to_string(path).map_err(|error| ApiError::Internal(error.to_string()))
}

async fn validate_config_text(body: String) -> Json<Value> {
    let errors = validate_ini_text(&body);
    Json(json!({
        "valid": errors.is_empty(),
        "errors": errors,
    }))
}

fn validate_ini_text(config_text: &str) -> Vec<String> {
    let mut errors = Vec::new();
    let mut seen_section = false;

    for (index, line) in config_text.lines().enumerate() {
        let trimmed = line.trim();
        if trimmed.is_empty() || trimmed.starts_with('#') || trimmed.starts_with(';') {
            continue;
        }
        if trimmed.starts_with('[') {
            if trimmed.ends_with(']') && trimmed.len() > 2 {
                seen_section = true;
            } else {
                errors.push(format!(
                    "File contains no section headers or has an invalid section header at line {}: {:?}",
                    index + 1,
                    line
                ));
            }
            continue;
        }
        if !seen_section {
            errors.push(format!(
                "File contains no section headers. file: '<string>', line: {} {:?}",
                index + 1,
                line
            ));
            break;
        }
        if !(trimmed.contains('=') || trimmed.contains(':')) {
            errors.push(format!(
                "Source contains parsing errors: '<string>' [line {}]: {:?}",
                index + 1,
                line
            ));
            break;
        }
    }

    errors
}

async fn apply_config_text(
    State(state): State<AppState>,
    body: String,
) -> Result<Json<Value>, ApiError> {
    apply_config_file(state.config_path.clone(), body, ConfigFileKind::Hub)
}

async fn apply_reticulum_config_text(
    State(state): State<AppState>,
    body: String,
) -> Result<Json<Value>, ApiError> {
    apply_config_file(
        state.reticulum_config_path.clone(),
        body,
        ConfigFileKind::Reticulum,
    )
}

fn apply_config_file(
    path: Option<Arc<PathBuf>>,
    body: String,
    kind: ConfigFileKind,
) -> Result<Json<Value>, ApiError> {
    let path = path.ok_or_else(|| ApiError::BadRequest(config_path_missing_message(kind)))?;
    let errors = validate_ini_text(&body);
    if !errors.is_empty() {
        let details = errors
            .iter()
            .filter(|error| !error.is_empty())
            .cloned()
            .collect::<Vec<_>>()
            .join("; ");
        let mut message = match kind {
            ConfigFileKind::Hub => "Invalid configuration payload".to_string(),
            ConfigFileKind::Reticulum => "Invalid Reticulum configuration payload".to_string(),
        };
        if !details.is_empty() {
            message = format!("{message}: {details}");
        }
        return Err(ApiError::BadRequest(message));
    }

    if matches!(kind, ConfigFileKind::Reticulum) {
        ensure_parent_dir(&path)?;
    }
    let backup_path = backup_config_file(&path, kind)?;
    std::fs::write(path.as_ref(), body).map_err(|error| ApiError::Internal(error.to_string()))?;
    Ok(Json(json!({
        "applied": true,
        "config_path": path.display().to_string(),
        "backup_path": backup_path.map(|path| path.display().to_string()),
    })))
}

async fn rollback_config_text(
    State(state): State<AppState>,
    payload: Option<Json<ConfigRollbackPayload>>,
) -> Result<Json<Value>, ApiError> {
    rollback_config_file(state.config_path.clone(), ConfigFileKind::Hub, payload)
}

async fn rollback_reticulum_config_text(
    State(state): State<AppState>,
    payload: Option<Json<ConfigRollbackPayload>>,
) -> Result<Json<Value>, ApiError> {
    rollback_config_file(
        state.reticulum_config_path.clone(),
        ConfigFileKind::Reticulum,
        payload,
    )
}

fn rollback_config_file(
    path: Option<Arc<PathBuf>>,
    kind: ConfigFileKind,
    payload: Option<Json<ConfigRollbackPayload>>,
) -> Result<Json<Value>, ApiError> {
    let path = path.ok_or_else(|| ApiError::BadRequest(config_path_missing_message(kind)))?;
    let backup_path = payload
        .and_then(|Json(payload)| payload.backup_path)
        .map(PathBuf::from)
        .or_else(|| latest_backup_file(&path, kind));
    let Some(backup_path) = backup_path else {
        return Ok(Json(
            json!({"rolled_back": false, "error": "No backup available"}),
        ));
    };
    if !backup_path.exists() {
        return Ok(Json(
            json!({"rolled_back": false, "error": "No backup available"}),
        ));
    }
    let content = std::fs::read_to_string(&backup_path)
        .map_err(|error| ApiError::Internal(error.to_string()))?;
    if matches!(kind, ConfigFileKind::Reticulum) {
        ensure_parent_dir(&path)?;
    }
    std::fs::write(path.as_ref(), content)
        .map_err(|error| ApiError::Internal(error.to_string()))?;
    Ok(Json(json!({
        "rolled_back": true,
        "backup_path": backup_path.display().to_string(),
    })))
}

fn config_path_missing_message(kind: ConfigFileKind) -> String {
    match kind {
        ConfigFileKind::Hub => "Configuration path is not configured".to_string(),
        ConfigFileKind::Reticulum => "Reticulum configuration path is not configured".to_string(),
    }
}

fn ensure_parent_dir(path: &FsPath) -> Result<(), ApiError> {
    if let Some(parent) = path.parent() {
        std::fs::create_dir_all(parent).map_err(|error| ApiError::Internal(error.to_string()))?;
    }
    Ok(())
}

fn backup_config_file(path: &FsPath, kind: ConfigFileKind) -> Result<Option<PathBuf>, ApiError> {
    if !path.exists() {
        return Ok(None);
    }
    let timestamp = unix_now_ms();
    let backup_path = match kind {
        ConfigFileKind::Hub => path.with_extension(format!("ini.bak.{timestamp}")),
        ConfigFileKind::Reticulum => PathBuf::from(format!("{}.bak.{timestamp}", path.display())),
    };
    let content =
        std::fs::read_to_string(path).map_err(|error| ApiError::Internal(error.to_string()))?;
    std::fs::write(&backup_path, content).map_err(|error| ApiError::Internal(error.to_string()))?;
    Ok(Some(backup_path))
}

fn latest_backup_file(path: &FsPath, kind: ConfigFileKind) -> Option<PathBuf> {
    let parent = path.parent()?;
    let prefix = match kind {
        ConfigFileKind::Hub => "config.ini.bak.".to_string(),
        ConfigFileKind::Reticulum => format!("{}.bak.", path.file_name()?.to_string_lossy()),
    };
    let mut backups = std::fs::read_dir(parent)
        .ok()?
        .filter_map(Result::ok)
        .map(|entry| entry.path())
        .filter(|candidate| {
            candidate
                .file_name()
                .and_then(|name| name.to_str())
                .is_some_and(|name| name.starts_with(&prefix))
        })
        .collect::<Vec<_>>();
    backups.sort();
    backups.pop()
}

fn status_payload(state: &AppState) -> Result<Value, ApiError> {
    let control = state
        .runtime_control
        .read()
        .map_err(|error| ApiError::Internal(error.to_string()))?
        .clone();
    let clients = state
        .clients
        .read()
        .map_err(|error| ApiError::Internal(error.to_string()))?
        .len();
    let topics = state
        .topics
        .read()
        .map_err(|error| ApiError::Internal(error.to_string()))?
        .len();
    let subscribers = state
        .subscribers
        .read()
        .map_err(|error| ApiError::Internal(error.to_string()))?
        .len();
    let files = attachment_record_count(state, "file")?;
    let images = attachment_record_count(state, "image")?;
    Ok(json!({
        "uptime_seconds": runtime_uptime_seconds(control.started_ts_ms),
        "clients": clients,
        "topics": topics,
        "subscribers": subscribers,
        "files": files,
        "images": images,
        "chat": chat_status_counts(state)?,
        "telemetry": telemetry_status_stats(state)?,
        "runtime": runtime_status_payload(state)?,
    }))
}

fn status_payload_for_ws(state: &AppState) -> Value {
    status_payload(state).unwrap_or_else(|error| {
        json!({
            "uptime_seconds": 0,
            "clients": 0,
            "topics": 0,
            "subscribers": 0,
            "files": 0,
            "images": 0,
            "chat": { "sent": 0, "failed": 0, "received": 0 },
            "telemetry": { "ingest_count": 0, "last_ingest_at": null },
            "runtime": {
                "runtime": "rust",
                "status": "error",
                "error": error.to_string(),
            },
        })
    })
}

fn chat_status_counts(state: &AppState) -> Result<Value, ApiError> {
    let messages = state
        .messages
        .read()
        .map_err(|error| ApiError::Internal(error.to_string()))?;
    let mut sent = 0usize;
    let mut failed = 0usize;
    let mut delivered = 0usize;
    for message in messages.iter() {
        match normalized_delivery_state(message).as_str() {
            "sent" => sent += 1,
            "failed" => failed += 1,
            "delivered" => delivered += 1,
            _ => {}
        }
    }
    Ok(json!({
        "sent": sent,
        "failed": failed,
        "received": delivered,
    }))
}

fn telemetry_status_stats(state: &AppState) -> Result<Value, ApiError> {
    let records = state
        .telemetry_records
        .read()
        .map_err(|error| ApiError::Internal(error.to_string()))?;
    let last_ingest_at = records
        .iter()
        .map(|record| record.timestamp_s)
        .max()
        .map(|timestamp_s| iso8601_from_unix_ms(timestamp_s.saturating_mul(1000)));
    Ok(json!({
        "ingest_count": records.len(),
        "last_ingest_at": last_ingest_at,
    }))
}

