fn list_attachments(
    state: &AppState,
    category: &str,
    query: AttachmentListQuery,
) -> Result<Json<Value>, ApiError> {
    let mut records = load_attachment_records(state, category)?;
    if query.page.is_none() && query.per_page.is_none() {
        records.sort_by_key(|record| record.file_id);
        return Ok(Json(json!(
            records
                .iter()
                .map(attachment_to_python_value)
                .collect::<Vec<_>>()
        )));
    }
    let (page, per_page) = resolve_python_pagination(query.page, query.per_page)?;
    records.sort_by(|left, right| {
        right
            .created_ts_ms
            .cmp(&left.created_ts_ms)
            .then_with(|| left.file_id.cmp(&right.file_id))
    });
    let total = records.len();
    let total_pages = if total == 0 {
        0
    } else {
        total.div_ceil(per_page)
    };
    let start = page.saturating_sub(1).saturating_mul(per_page);
    let items = records
        .iter()
        .skip(start)
        .take(per_page)
        .map(attachment_to_python_value)
        .collect::<Vec<_>>();
    Ok(Json(json!({
        "items": items,
        "page": page,
        "per_page": per_page,
        "total": total,
        "total_pages": total_pages,
        "has_next": page < total_pages,
        "has_previous": page > 1,
    })))
}

fn resolve_python_pagination(
    page: Option<i64>,
    per_page: Option<i64>,
) -> Result<(usize, usize), ApiError> {
    let page = page.unwrap_or(1);
    if page < 1 {
        return Err(ApiError::Unprocessable(
            "page must be greater than or equal to 1".to_string(),
        ));
    }
    let per_page =
        per_page.unwrap_or(i64::try_from(API_PAGINATION_DEFAULT_PAGE_SIZE).unwrap_or(50));
    if per_page < 1 {
        return Err(ApiError::Unprocessable(
            "per_page must be greater than or equal to 1".to_string(),
        ));
    }
    let max_per_page = i64::try_from(API_PAGINATION_MAX_PAGE_SIZE).unwrap_or(500);
    if per_page > max_per_page {
        return Err(ApiError::Unprocessable(format!(
            "per_page must be less than or equal to {API_PAGINATION_MAX_PAGE_SIZE}"
        )));
    }
    Ok((
        usize::try_from(page).map_err(|error| ApiError::Internal(error.to_string()))?,
        usize::try_from(per_page).map_err(|error| ApiError::Internal(error.to_string()))?,
    ))
}

