async fn method_not_allowed(request: Request) -> Response {
    let allow = method_not_allowed_allowed_methods(request.uri().path()).unwrap_or("POST");
    (
        StatusCode::METHOD_NOT_ALLOWED,
        [(header::ALLOW, allow)],
        Json(ErrorBody {
            detail: "Method Not Allowed".to_string(),
        }),
    )
        .into_response()
}

fn method_not_allowed_allowed_methods(path: &str) -> Option<&'static str> {
    match path {
        "/Message"
        | "/Command/FlushTelemetry"
        | "/Command/ReloadConfig"
        | "/Control/Stop"
        | "/Control/Start"
        | "/Control/Announce"
        | "/Control/Sync"
        | "/Config/Validate"
        | "/Config/Rollback"
        | "/Reticulum/Config/Validate"
        | "/Reticulum/Config/Rollback"
        | "/Chat/Message"
        | "/Chat/Attachment"
        | "/checklists/offline"
        | "/checklists/import/csv"
        | "/Topic/Associate"
        | "/Topic/Subscribe"
        | "/Subscriber/Add"
        | "/internal/message"
        | "/internal/delivery-receipt"
        | "/internal/delivery-failure"
        | "/internal/delivery-retry"
        | "/internal/delivery-propagation"
        | "/internal/delivery-drop"
        | "/internal/delivery-attempt"
        | "/internal/identity-announce" => Some("POST"),
        "/RTH" | "/RCH" => Some("POST, PUT"),
        _ => method_not_allowed_allowed_methods_for_segments(path),
    }
}

fn method_not_allowed_allowed_methods_for_segments(path: &str) -> Option<&'static str> {
    let segments: Vec<&str> = path
        .trim_matches('/')
        .split('/')
        .filter(|segment| !segment.is_empty())
        .collect();
    match segments.as_slice() {
        ["api", "markers", _, "position"] => Some("PATCH"),
        ["api", "markers" | "zones", _] => Some("PATCH, DELETE"),
        ["checklists", "templates", _, "clone"]
        | ["checklists", _, "join" | "upload" | "tasks"]
        | ["checklists", _, "feeds", _]
        | ["checklists", _, "tasks", _, "status"]
        | ["Client", _, "Ban" | "Unban" | "Blackhole"] => Some("POST"),
        ["checklists", _, "tasks", _, "row-style"] | ["checklists", _, "tasks", _, "cells", _] => {
            Some("PATCH")
        }
        ["checklists", _, "tasks", _] => Some("DELETE"),
        ["api", "r3akt", "capabilities", _, _]
        | ["api", "r3akt", "missions", _, "zones" | "markers", _]
        | ["api", "r3akt", "teams", _, "missions", _]
        | ["api", "r3akt", "team-members", _, "clients", _]
        | ["api", "r3akt", "assignments", _, "assets", _] => Some("PUT, DELETE"),
        ["api", "r3akt", "missions", _, "parent"]
        | ["api", "r3akt", "assignments", _, "assets"] => Some("PUT"),
        _ => None,
    }
}

