async fn subscribe_topic(
    State(state): State<AppState>,
    Json(input): Json<Value>,
) -> Result<Json<SubscriberRecord>, ApiError> {
    let payload = parse_subscribe_topic_payload(input)?;
    let destination = payload
        .destination
        .filter(|value| !value.trim().is_empty())
        .ok_or_else(|| {
            ApiError::BadRequest(
                "Destination is required when authentication identity is unavailable".to_string(),
            )
        })?;
    {
        let topics = state
            .topics
            .read()
            .map_err(|error| ApiError::Internal(error.to_string()))?;
        if !topics.contains_key(payload.topic_id.as_str()) {
            return Err(ApiError::NotFound(format!(
                "Topic not found: {}",
                payload.topic_id
            )));
        }
    }
    let subscriber = SubscriberRecord {
        subscriber_id: Uuid::new_v4().simple().to_string(),
        destination,
        topic_id: payload.topic_id,
        reject_tests: payload.reject_tests,
        metadata: payload.metadata.unwrap_or_else(|| json!({})),
    };
    let mut subscribers = state
        .subscribers
        .write()
        .map_err(|error| ApiError::Internal(error.to_string()))?;
    subscribers.insert(subscriber.subscriber_id.clone(), subscriber.clone());
    drop(subscribers);
    persist_subscriber_row(&state, &subscriber)?;
    Ok(Json(subscriber))
}

fn parse_subscribe_topic_payload(input: Value) -> Result<SubscribeTopicPayload, ApiError> {
    if input.is_null() {
        return Err(ApiError::PydanticValidation(python_missing_body_body()));
    }
    let object = input
        .as_object()
        .ok_or_else(|| ApiError::PydanticValidation(python_model_attributes_body(input.clone())))?;
    let topic_id = first_string_alias(object, &["TopicID", "topic_id", "topicId", "id"])
        .ok_or_else(|| {
            ApiError::PydanticValidation(python_missing_field_body("TopicID", input.clone()))
        })?;
    let destination = first_string_alias(object, &["Destination", "destination"]);
    let reject_tests = first_alias_value(object, &["RejectTests", "reject_tests", "rejectTests"])
        .map(parse_python_optional_int)
        .transpose()?;
    let metadata = first_alias_value(object, &["Metadata", "metadata"]).cloned();
    Ok(SubscribeTopicPayload {
        topic_id,
        destination,
        reject_tests,
        metadata,
    })
}

fn first_alias_value<'a>(
    object: &'a serde_json::Map<String, Value>,
    aliases: &[&str],
) -> Option<&'a Value> {
    aliases.iter().find_map(|alias| object.get(*alias))
}

fn first_string_alias(object: &serde_json::Map<String, Value>, aliases: &[&str]) -> Option<String> {
    first_alias_value(object, aliases)
        .and_then(Value::as_str)
        .map(ToOwned::to_owned)
}

fn parse_python_optional_int(value: &Value) -> Result<i64, ApiError> {
    if let Some(number) = value.as_i64() {
        return Ok(number);
    }
    if let Some(text) = value.as_str() {
        if let Ok(number) = text.parse::<i64>() {
            return Ok(number);
        }
    }
    Err(ApiError::PydanticValidation(python_int_parsing_body(
        "RejectTests",
        value.clone(),
    )))
}

