fn build_topic(payload: TopicPayload) -> Result<TopicRecord, ApiError> {
    let topic_name = payload
        .topic_name
        .filter(|value| !value.trim().is_empty())
        .ok_or_else(|| ApiError::BadRequest("TopicName and TopicPath are required".to_string()))?;
    let topic_path = payload
        .topic_path
        .filter(|value| !value.trim().is_empty())
        .ok_or_else(|| ApiError::BadRequest("TopicName and TopicPath are required".to_string()))?;
    let topic_id = payload
        .topic_id
        .as_deref()
        .and_then(|value| normalize_topic_id(Some(value)))
        .unwrap_or_else(|| Uuid::new_v4().simple().to_string());
    Ok(TopicRecord {
        topic_id,
        topic_name,
        topic_path,
        topic_description: payload.topic_description.unwrap_or_default(),
    })
}

fn paginated_payload(records: &[TopicRecord], page: usize, per_page: usize) -> Value {
    let safe_page = page.max(1);
    let safe_per_page = per_page.max(1);
    let start = safe_page.saturating_sub(1).saturating_mul(safe_per_page);
    let items = records
        .iter()
        .skip(start)
        .take(safe_per_page)
        .cloned()
        .collect::<Vec<_>>();
    let total = records.len();
    let total_pages = if total == 0 {
        0
    } else {
        total.div_ceil(safe_per_page)
    };
    json!({
        "items": items,
        "page": safe_page,
        "per_page": safe_per_page,
        "total": total,
        "total_pages": total_pages,
        "has_next": safe_page < total_pages,
        "has_previous": safe_page > 1
    })
}

