    fn multipart_attachment_body(
        boundary: &str,
        category: &str,
        filename: &str,
        media_type: &str,
        bytes: &[u8],
        sha256: &str,
        topic_id: &str,
    ) -> Vec<u8> {
        let mut body = Vec::new();
        for (name, value) in [
            ("category", category),
            ("sha256", sha256),
            ("topic_id", topic_id),
        ] {
            body.extend_from_slice(format!("--{boundary}\r\n").as_bytes());
            body.extend_from_slice(
                format!("Content-Disposition: form-data; name=\"{name}\"\r\n\r\n").as_bytes(),
            );
            body.extend_from_slice(value.as_bytes());
            body.extend_from_slice(b"\r\n");
        }
        body.extend_from_slice(format!("--{boundary}\r\n").as_bytes());
        body.extend_from_slice(
            format!("Content-Disposition: form-data; name=\"file\"; filename=\"{filename}\"\r\n")
                .as_bytes(),
        );
        body.extend_from_slice(format!("Content-Type: {media_type}\r\n\r\n").as_bytes());
        body.extend_from_slice(bytes);
        body.extend_from_slice(b"\r\n");
        body.extend_from_slice(format!("--{boundary}--\r\n").as_bytes());
        body
    }

    fn parse_http_body(request: &[u8]) -> Vec<u8> {
        let header_end = request
            .windows(4)
            .position(|window| window == b"\r\n\r\n")
            .expect("http header end");
        let headers = String::from_utf8_lossy(&request[..header_end]);
        let content_length = headers
            .lines()
            .find_map(|line| {
                let (name, value) = line.split_once(':')?;
                name.eq_ignore_ascii_case("content-length")
                    .then(|| value.trim().parse::<usize>().ok())
                    .flatten()
            })
            .expect("content length");
        let body_start = header_end + 4;
        request[body_start..body_start + content_length].to_vec()
    }

    fn read_http_request(stream: &mut impl Read) -> Vec<u8> {
        let mut request = Vec::new();
        let mut buffer = [0_u8; 1024];
        loop {
            let bytes_read = match stream.read(&mut buffer) {
                Ok(bytes_read) => bytes_read,
                Err(error) if error.kind() == std::io::ErrorKind::WouldBlock => {
                    std::thread::sleep(Duration::from_millis(5));
                    continue;
                }
                Err(error) => panic!("read request: {error}"),
            };
            if bytes_read == 0 {
                break;
            }
            request.extend_from_slice(&buffer[..bytes_read]);
            if let Some(header_end) = request.windows(4).position(|window| window == b"\r\n\r\n") {
                let headers = String::from_utf8_lossy(&request[..header_end]);
                let content_length = headers
                    .lines()
                    .find_map(|line| {
                        let (name, value) = line.split_once(':')?;
                        name.eq_ignore_ascii_case("content-length")
                            .then(|| value.trim().parse::<usize>().ok())
                            .flatten()
                    })
                    .expect("content length");
                if request.len() >= header_end + 4 + content_length {
                    break;
                }
            }
        }
        request
    }

    fn decode_reticulumd_frame<T: serde::de::DeserializeOwned>(bytes: &[u8]) -> T {
        let len = u32::from_be_bytes(bytes[..4].try_into().expect("frame length")) as usize;
        rmp_serde::from_slice(&bytes[4..4 + len]).expect("messagepack frame")
    }

    fn encode_reticulumd_frame<T: Serialize>(message: &T) -> Vec<u8> {
        let mut framed = vec![0, 0, 0, 0];
        message
            .serialize(&mut rmp_serde::Serializer::new(&mut framed))
            .expect("serialize frame");
        let len = u32::try_from(framed.len() - 4).expect("frame length");
        framed[..4].copy_from_slice(&len.to_be_bytes());
        framed
    }

    async fn wait_for_outbound_worker_running(state: &crate::AppState, expected: bool) {
        for _ in 0..100 {
            let running = state
                .outbound_retry_worker_stats
                .read()
                .expect("worker stats")
                .running;
            if running == expected {
                return;
            }
            tokio::time::sleep(Duration::from_millis(10)).await;
        }
        panic!("outbound worker running state did not become {expected}");
    }

    async fn wait_for_reticulumd_inbound_worker_running(state: &crate::AppState, expected: bool) {
        for _ in 0..100 {
            let running = state
                .reticulumd_inbound_worker_stats
                .read()
                .expect("worker stats")
                .running;
            if running == expected {
                return;
            }
            tokio::time::sleep(Duration::from_millis(10)).await;
        }
        panic!("reticulumd inbound worker running state did not become {expected}");
    }

