    fn fake_reticulumd_rpc_server() -> (String, thread::JoinHandle<ReticulumdRpcRequest>) {
        let (endpoint, server) = fake_reticulumd_rpc_server_for_request_count(1);
        let server = thread::spawn(move || {
            server
                .join()
                .expect("rpc server")
                .into_iter()
                .next()
                .expect("rpc request")
        });
        (endpoint, server)
    }

    fn fake_reticulumd_rpc_server_for_request_count(
        expected_requests: usize,
    ) -> (String, thread::JoinHandle<Vec<ReticulumdRpcRequest>>) {
        fake_reticulumd_rpc_server_for_request_count_with_accept_timeout(
            expected_requests,
            Duration::from_secs(10),
        )
    }

    fn fake_reticulumd_rpc_server_for_request_count_with_accept_timeout(
        expected_requests: usize,
        accept_timeout: Duration,
    ) -> (String, thread::JoinHandle<Vec<ReticulumdRpcRequest>>) {
        let responses = (0..expected_requests)
            .map(|_| {
                json!({
                    "message_id": "message"
                })
            })
            .collect::<Vec<_>>();
        fake_reticulumd_rpc_server_with_results_and_accept_timeout(responses, accept_timeout)
    }

    fn fake_reticulumd_rpc_server_with_results(
        results: Vec<serde_json::Value>,
    ) -> (String, thread::JoinHandle<Vec<ReticulumdRpcRequest>>) {
        fake_reticulumd_rpc_server_with_results_and_accept_timeout(results, Duration::from_secs(10))
    }

    fn fake_reticulumd_rpc_server_with_results_and_accept_timeout(
        results: Vec<serde_json::Value>,
        accept_timeout: Duration,
    ) -> (String, thread::JoinHandle<Vec<ReticulumdRpcRequest>>) {
        let responses = results
            .into_iter()
            .map(|result| (Some(result), None))
            .collect::<Vec<_>>();
        fake_reticulumd_rpc_server_with_responses_and_accept_timeout(responses, accept_timeout)
    }

    fn fake_reticulumd_rpc_server_with_responses(
        responses: Vec<(Option<serde_json::Value>, Option<ReticulumdRpcError>)>,
    ) -> (String, thread::JoinHandle<Vec<ReticulumdRpcRequest>>) {
        fake_reticulumd_rpc_server_with_responses_and_accept_timeout(
            responses,
            Duration::from_secs(10),
        )
    }

    fn fake_reticulumd_rpc_server_with_responses_and_accept_timeout(
        responses: Vec<(Option<serde_json::Value>, Option<ReticulumdRpcError>)>,
        accept_timeout: Duration,
    ) -> (String, thread::JoinHandle<Vec<ReticulumdRpcRequest>>) {
        let listener = StdTcpListener::bind("127.0.0.1:0").expect("listener");
        listener
            .set_nonblocking(true)
            .expect("set fake RPC listener nonblocking");
        let endpoint = listener.local_addr().expect("addr").to_string();
        let server = thread::spawn(move || {
            let mut requests = Vec::new();
            for (result, error) in responses {
                let accept_deadline = std::time::Instant::now() + accept_timeout;
                let mut stream = loop {
                    match listener.accept() {
                        Ok((stream, _)) => break stream,
                        Err(error) if error.kind() == std::io::ErrorKind::WouldBlock => {
                            if std::time::Instant::now() >= accept_deadline {
                                return requests;
                            }
                            std::thread::sleep(Duration::from_millis(10));
                        }
                        Err(error) => panic!("accept fake RPC request: {error}"),
                    }
                };
                let request = read_http_request(&mut stream);
                let body = parse_http_body(&request);
                let decoded: ReticulumdRpcRequest = decode_reticulumd_frame(&body);
                let response = ReticulumdRpcResponse {
                    id: decoded.id,
                    result,
                    error,
                };
                let body = encode_reticulumd_frame(&response);
                let http = [
                    b"HTTP/1.1 200 OK\r\nContent-Type: application/msgpack\r\nContent-Length: "
                        .as_slice(),
                    body.len().to_string().as_bytes(),
                    b"\r\n\r\n",
                    body.as_slice(),
                ]
                .concat();
                stream.write_all(&http).expect("write response");
                requests.push(decoded);
            }
            requests
        });
        (endpoint, server)
    }

    #[tokio::test]
    async fn reticulumd_announce_import_records_identity_without_user_or_team_member() {
        let db_path = std::env::temp_dir().join(format!(
            "r3akt-rch-reticulumd-announce-import-{}.db",
            Uuid::new_v4()
        ));
        let state = crate::AppState::from_sqlite_path(&db_path).expect("sqlite state");
        let announce_response = json!({
            "announces": [
                {
                    "id": "announce-1700000000-7f3c0b2cc4bc423d25742b014c0e03b9-1",
                    "peer": "7F3C0B2CC4BC423D25742B014C0E03B9",
                    "timestamp": 1_700_000_000,
                    "name": "Field REM",
                    "name_source": "app_data",
                    "first_seen": 1_700_000_000,
                    "seen_count": 1,
                    "app_data_hex": null,
                    "capabilities": ["r3akt", "EmergencyMessages"],
                    "rssi": null,
                    "snr": null,
                    "q": null,
                    "stamp_cost_flexibility": null,
                    "peering_cost": null
                }
            ],
            "next_cursor": null
        });
        let (endpoint, rpc_server) = fake_reticulumd_rpc_server_with_results(vec![
            announce_response.clone(),
            announce_response,
        ]);

        let imported =
            crate::import_reticulumd_announces(&state, endpoint.as_str(), 500).expect("import");
        assert_eq!(imported, 1);
        let snapshot = crate::with_rch_snapshot(&state, false, |snapshot| Ok(snapshot.clone()))
            .expect("snapshot");
        assert_eq!(snapshot.identity_announces.len(), 1);
        assert_eq!(
            snapshot.identity_announces[0].destination_hash,
            "7f3c0b2cc4bc423d25742b014c0e03b9"
        );
        assert_eq!(
            snapshot.identity_announces[0].display_name.as_deref(),
            Some("Field REM")
        );
        assert_eq!(
            snapshot.identity_announces[0].announce_capabilities,
            vec!["r3akt".to_string(), "emergencymessages".to_string()]
        );
        assert!(
            state
                .clients
                .read()
                .expect("clients")
                .get("7f3c0b2cc4bc423d25742b014c0e03b9")
                .is_none()
        );
        assert!(snapshot.clients.is_empty());
        assert!(snapshot.team_members.is_empty());
        let identities = state.identity_states.read().expect("identities");
        assert!(identities.contains_key("7f3c0b2cc4bc423d25742b014c0e03b9"));
        drop(identities);
        state.identity_states.write().expect("identities").clear();
        let imported_again =
            crate::import_reticulumd_announces(&state, endpoint.as_str(), 500).expect("reimport");
        assert_eq!(imported_again, 0);
        assert!(
            state
                .identity_states
                .read()
                .expect("identities")
                .contains_key("7f3c0b2cc4bc423d25742b014c0e03b9")
        );
        let snapshot = crate::with_rch_snapshot(&state, false, |snapshot| Ok(snapshot.clone()))
            .expect("snapshot");
        assert!(snapshot.clients.is_empty());
        assert!(snapshot.team_members.is_empty());
        let requests = rpc_server.join().expect("rpc server");
        assert_eq!(requests[0].method, "list_announces");
        assert_eq!(requests[1].method, "list_announces");

        let _ = std::fs::remove_file(db_path);
    }

