    #[tokio::test]
    async fn openapi_documents_python_paginated_list_contract() {
        let app = crate::create_app();

        let response = app
            .oneshot(
                Request::builder()
                    .method(Method::GET)
                    .uri("/openapi.json")
                    .body(Body::empty())
                    .expect("request"),
            )
            .await
            .expect("response");
        assert_eq!(response.status(), StatusCode::OK);
        let body = response
            .into_body()
            .collect()
            .await
            .expect("body")
            .to_bytes();
        let payload: serde_json::Value = serde_json::from_slice(&body).expect("json");
        let expected = [
            ("/Client", "PaginatedClientList"),
            ("/Topic", "PaginatedTopicList"),
            ("/Subscriber", "PaginatedSubscriberList"),
            ("/File", "PaginatedFileAttachmentList"),
            ("/Image", "PaginatedFileAttachmentList"),
        ];

        for (path, schema_name) in expected {
            let operation = &payload["paths"][path]["get"];
            let parameters = operation["parameters"]
                .as_array()
                .unwrap_or_else(|| panic!("{path} get parameters"));
            assert!(parameters.contains(&json!({ "$ref": "#/components/parameters/page" })));
            assert!(parameters.contains(&json!({ "$ref": "#/components/parameters/perPage" })));

            let response = &operation["responses"]["200"];
            let response =
                if let Some(reference) = response.get("$ref").and_then(serde_json::Value::as_str) {
                    let response_name = reference
                        .rsplit('/')
                        .next()
                        .unwrap_or_else(|| panic!("{path} response reference name"));
                    &payload["components"]["responses"][response_name]
                } else {
                    response
                };
            let one_of = response["content"]["application/json"]["schema"]["oneOf"]
                .as_array()
                .unwrap_or_else(|| panic!("{path} 200 response oneOf"));
            assert!(one_of.contains(&json!({
                "$ref": format!("#/components/schemas/{schema_name}")
            })));
            assert!(
                payload["components"]["schemas"][schema_name].is_object(),
                "{schema_name} schema missing from OpenAPI components"
            );
        }
    }

