    #[tokio::test]
    async fn openapi_documents_python_dynamic_route_contracts() {
        let app = crate::create_app();

        let response = app
            .oneshot(
                Request::builder()
                    .method(Method::GET)
                    .uri("/openapi.json")
                    .body(Body::empty())
                    .expect("request"),
            )
            .await
            .expect("response");
        assert_eq!(response.status(), StatusCode::OK);
        let body = response
            .into_body()
            .collect()
            .await
            .expect("body")
            .to_bytes();
        let spec: serde_json::Value = serde_json::from_slice(&body).expect("json");
        let paths = &spec["paths"];
        let schemas = &spec["components"]["schemas"];

        for schema_name in [
            "RuntimeDiagnostics",
            "ChatMessage",
            "ChatSendPayload",
            "ChatAttachmentUploadRequest",
            "RemPeerRegistry",
            "MarkerUpdatePayload",
            "R3aktMissionMarkersResponse",
        ] {
            assert!(
                schemas[schema_name].is_object(),
                "{schema_name} schema missing"
            );
        }

        for path in ["/diagnostics/runtime", "/Diagnostics/Runtime"] {
            assert_eq!(
                paths[path]["get"]["responses"]["200"]["content"]["application/json"]["schema"]["$ref"],
                "#/components/schemas/RuntimeDiagnostics",
                "{path} diagnostics response"
            );
        }

        let chat_messages = &paths["/Chat/Messages"]["get"];
        let chat_params = chat_messages["parameters"]
            .as_array()
            .expect("chat message query parameters");
        for name in ["limit", "direction", "topic_id", "destination", "source"] {
            assert!(
                chat_params.iter().any(|param| param["name"] == name),
                "Chat/Messages query parameter {name} missing"
            );
        }
        assert_eq!(
            chat_params
                .iter()
                .find(|param| param["name"] == "limit")
                .expect("limit parameter")["schema"]["type"],
            "integer"
        );
        assert_eq!(
            chat_messages["responses"]["200"]["content"]["application/json"]["schema"]["items"]["$ref"],
            "#/components/schemas/ChatMessage"
        );

        assert_eq!(
            paths["/Chat/Message"]["post"]["requestBody"]["content"]["application/json"]["schema"]
                ["$ref"],
            "#/components/schemas/ChatSendPayload"
        );
        assert_eq!(
            paths["/Chat/Message"]["post"]["responses"]["200"]["content"]["application/json"]["schema"]
                ["$ref"],
            "#/components/schemas/ChatMessage"
        );
        assert_eq!(
            paths["/Chat/Attachment"]["post"]["requestBody"]["content"]["multipart/form-data"]["schema"]
                ["$ref"],
            "#/components/schemas/ChatAttachmentUploadRequest"
        );
        assert_eq!(
            paths["/Chat/Attachment"]["post"]["responses"]["200"]["content"]["application/json"]["schema"]
                ["$ref"],
            "#/components/schemas/FileAttachment"
        );
        assert_eq!(
            paths["/api/rem/peers"]["get"]["responses"]["200"]["content"]["application/json"]["schema"]
                ["$ref"],
            "#/components/schemas/RemPeerRegistry"
        );

        let marker_detail = &paths["/api/markers/{object_destination_hash}"];
        assert_eq!(
            marker_detail["patch"]["parameters"][0]["name"],
            "object_destination_hash"
        );
        assert_eq!(
            marker_detail["patch"]["requestBody"]["content"]["application/json"]["schema"]["$ref"],
            "#/components/schemas/MarkerUpdatePayload"
        );
        assert_eq!(
            marker_detail["patch"]["responses"]["200"]["content"]["application/json"]["schema"]["type"],
            "object"
        );
        assert_eq!(
            marker_detail["delete"]["parameters"][0]["name"],
            "object_destination_hash"
        );

        assert_eq!(
            paths["/api/r3akt/missions/{mission_uid}/markers"]["get"]["parameters"][0]["name"],
            "mission_uid"
        );
        assert_eq!(
            paths["/api/r3akt/missions/{mission_uid}/markers"]["get"]["responses"]["200"]["content"]
                ["application/json"]["schema"]["$ref"],
            "#/components/schemas/R3aktMissionMarkersResponse"
        );
        for method in ["put", "delete"] {
            let operation = &paths["/api/r3akt/missions/{mission_uid}/markers/{marker_id}"][method];
            let params = operation["parameters"]
                .as_array()
                .expect("mission marker link parameters");
            assert!(
                params.iter().any(|param| param["name"] == "mission_uid"),
                "{method} mission_uid parameter missing"
            );
            assert!(
                params.iter().any(|param| param["name"] == "marker_id"),
                "{method} marker_id parameter missing"
            );
            assert_eq!(
                operation["responses"]["200"]["content"]["application/json"]["schema"]["$ref"],
                "#/components/schemas/R3aktMission",
                "{method} mission marker response"
            );
        }
    }

