    #[tokio::test]
    async fn topic_routes_preserve_python_response_shape() {
        let app = crate::create_app();

        let created = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::POST)
                    .uri("/Topic")
                    .header("content-type", "application/json")
                    .body(Body::from(
                        r#"{"TopicID":"ops","TopicName":"Ops","TopicPath":"ops","TopicDescription":"Ops channel"}"#,
                    ))
                    .expect("request"),
            )
            .await
            .expect("create response");
        assert_eq!(created.status(), StatusCode::OK);
        let body = created
            .into_body()
            .collect()
            .await
            .expect("body")
            .to_bytes();
        let payload: serde_json::Value = serde_json::from_slice(&body).expect("json");
        assert_eq!(payload["TopicID"], "ops");
        assert_eq!(payload["TopicName"], "Ops");
        assert_eq!(payload["TopicPath"], "ops");
        assert_eq!(payload["TopicDescription"], "Ops channel");

        let listed = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::GET)
                    .uri("/Topic")
                    .body(Body::empty())
                    .expect("request"),
            )
            .await
            .expect("list response");
        assert_eq!(listed.status(), StatusCode::OK);
        let body = listed.into_body().collect().await.expect("body").to_bytes();
        let payload: serde_json::Value = serde_json::from_slice(&body).expect("json");
        assert_eq!(payload.as_array().expect("topics").len(), 1);
        assert_eq!(payload[0]["TopicID"], "ops");

        let retrieved = app
            .oneshot(
                Request::builder()
                    .method(Method::GET)
                    .uri("/Topic/ops")
                    .body(Body::empty())
                    .expect("request"),
            )
            .await
            .expect("retrieve response");
        assert_eq!(retrieved.status(), StatusCode::OK);
        let body = retrieved
            .into_body()
            .collect()
            .await
            .expect("body")
            .to_bytes();
        let payload: serde_json::Value = serde_json::from_slice(&body).expect("json");
        assert_eq!(payload["TopicID"], "ops");
    }

    #[tokio::test]
    async fn topic_create_matches_python_required_name_path_and_generated_id() {
        let app = crate::create_app();

        let missing_name = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::POST)
                    .uri("/Topic")
                    .header("content-type", "application/json")
                    .body(Body::from(r#"{"TopicPath":"ops"}"#))
                    .expect("request"),
            )
            .await
            .expect("missing name response");
        assert_eq!(missing_name.status(), StatusCode::BAD_REQUEST);
        let body = missing_name
            .into_body()
            .collect()
            .await
            .expect("body")
            .to_bytes();
        let payload: serde_json::Value = serde_json::from_slice(&body).expect("json");
        assert_eq!(payload["detail"], "TopicName and TopicPath are required");

        let generated = app
            .oneshot(
                Request::builder()
                    .method(Method::POST)
                    .uri("/Topic")
                    .header("content-type", "application/json")
                    .body(Body::from(
                        r#"{"TopicName":"Generated","TopicPath":"ops/generated"}"#,
                    ))
                    .expect("request"),
            )
            .await
            .expect("generated response");
        assert_eq!(generated.status(), StatusCode::OK);
        let body = generated
            .into_body()
            .collect()
            .await
            .expect("body")
            .to_bytes();
        let payload: serde_json::Value = serde_json::from_slice(&body).expect("json");
        let topic_id = payload["TopicID"].as_str().expect("topic id");
        assert_eq!(topic_id.len(), 32);
        assert_ne!(topic_id, "ops.generated");
        assert_eq!(payload["TopicName"], "Generated");
        assert_eq!(payload["TopicPath"], "ops/generated");
    }

