    #[tokio::test]
    async fn topic_list_uses_python_pagination_envelope_when_requested() {
        let app = crate::create_app();

        for topic_id in ["alpha", "bravo"] {
            let response = app
                .clone()
                .oneshot(
                    Request::builder()
                        .method(Method::POST)
                        .uri("/Topic")
                        .header("content-type", "application/json")
                        .body(Body::from(
                            json!({
                                "TopicID": topic_id,
                                "TopicName": topic_id,
                                "TopicPath": topic_id,
                                "TopicDescription": ""
                            })
                            .to_string(),
                        ))
                        .expect("request"),
                )
                .await
                .expect("create response");
            assert_eq!(response.status(), StatusCode::OK);
        }

        let listed = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::GET)
                    .uri("/Topic?page=1&per_page=1")
                    .body(Body::empty())
                    .expect("request"),
            )
            .await
            .expect("list response");
        assert_eq!(listed.status(), StatusCode::OK);
        let body = listed.into_body().collect().await.expect("body").to_bytes();
        let payload: serde_json::Value = serde_json::from_slice(&body).expect("json");
        assert_eq!(payload["items"].as_array().expect("items").len(), 1);
        assert_eq!(payload["items"][0]["TopicID"], "alpha");
        assert_eq!(payload["page"], 1);
        assert_eq!(payload["per_page"], 1);
        assert_eq!(payload["total"], 2);
        assert_eq!(payload["total_pages"], 2);
        assert_eq!(payload["has_next"], true);
        assert_eq!(payload["has_previous"], false);

        let empty_second_page = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::GET)
                    .uri("/Topic?page=2&per_page=10")
                    .body(Body::empty())
                    .expect("request"),
            )
            .await
            .expect("empty page response");
        assert_eq!(empty_second_page.status(), StatusCode::OK);
        let body = empty_second_page
            .into_body()
            .collect()
            .await
            .expect("body")
            .to_bytes();
        let payload: serde_json::Value = serde_json::from_slice(&body).expect("json");
        assert_eq!(payload["items"], json!([]));
        assert_eq!(payload["has_previous"], true);

        let oversized = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::GET)
                    .uri("/Topic?per_page=501")
                    .body(Body::empty())
                    .expect("request"),
            )
            .await
            .expect("oversized response");
        assert_eq!(oversized.status(), StatusCode::UNPROCESSABLE_ENTITY);

        let negative_page = app
            .oneshot(
                Request::builder()
                    .method(Method::GET)
                    .uri("/Topic?page=-1")
                    .body(Body::empty())
                    .expect("request"),
            )
            .await
            .expect("negative page response");
        assert_eq!(negative_page.status(), StatusCode::UNPROCESSABLE_ENTITY);
    }

