    #[tokio::test]
    async fn gateway_control_routes_match_python_no_runtime_shapes() {
        let app = crate::create_app_with_state(crate::AppState::default().with_api_key("secret"));

        let missing_auth = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::GET)
                    .uri("/Control/Status")
                    .body(Body::empty())
                    .expect("request"),
            )
            .await
            .expect("missing auth response");
        assert_eq!(missing_auth.status(), StatusCode::UNAUTHORIZED);

        let status = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::GET)
                    .uri("/Control/Status")
                    .header("X-API-Key", "secret")
                    .body(Body::empty())
                    .expect("request"),
            )
            .await
            .expect("status response");
        assert_eq!(status.status(), StatusCode::OK);
        let body = status.into_body().collect().await.expect("body").to_bytes();
        let payload: serde_json::Value = serde_json::from_slice(&body).expect("json");
        assert_eq!(payload["status"], "running");
        assert!(payload["pid"].as_u64().is_some());
        assert!(payload["host"].is_null());
        assert!(payload["port"].is_null());
        assert!(payload["uptime_seconds"].as_u64().is_some());
        assert_eq!(payload["hub_thread_alive"], true);
        assert_eq!(payload["shutdown_requested"], false);
        assert_eq!(payload["reticulumd_rpc_configured"], false);
        let services = payload["services"].as_array().expect("services");
        assert_eq!(services.len(), 4);
        let reticulumd = services
            .iter()
            .find(|service| service["name"] == "reticulumd_rpc")
            .expect("reticulumd service");
        assert_eq!(reticulumd["configured"], false);
        assert_eq!(reticulumd["status"], "not_configured");
        let managed_reticulumd = services
            .iter()
            .find(|service| service["name"] == "reticulumd_managed_process")
            .expect("managed reticulumd service");
        assert_eq!(managed_reticulumd["configured"], false);
        assert_eq!(managed_reticulumd["status"], "not_configured");
        let outbound_worker = services
            .iter()
            .find(|service| service["name"] == "outbound_retry_worker")
            .expect("outbound worker service");
        assert_eq!(outbound_worker["configured"], true);
        assert_eq!(outbound_worker["status"], "stopped");
        let inbound_worker = services
            .iter()
            .find(|service| service["name"] == "reticulumd_inbound_worker")
            .expect("reticulumd inbound worker service");
        assert_eq!(inbound_worker["configured"], false);
        assert_eq!(inbound_worker["status"], "not_configured");
        assert!(payload["started_at"].as_str().is_some());
        assert!(payload["last_start_at"].as_str().is_some());
        assert!(payload["last_stop_at"].is_null());
        assert!(payload["propagation"].is_null());

        let stop = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::POST)
                    .uri("/Control/Stop")
                    .header("X-API-Key", "secret")
                    .body(Body::empty())
                    .expect("request"),
            )
            .await
            .expect("stop response");
        assert_eq!(stop.status(), StatusCode::OK);
        let body = stop.into_body().collect().await.expect("body").to_bytes();
        let payload: serde_json::Value = serde_json::from_slice(&body).expect("json");
        assert_eq!(payload, json!({ "status": "stopping" }));

        let stopped = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::GET)
                    .uri("/Control/Status")
                    .header("X-API-Key", "secret")
                    .body(Body::empty())
                    .expect("request"),
            )
            .await
            .expect("stopped status response");
        assert_eq!(stopped.status(), StatusCode::OK);
        let body = stopped
            .into_body()
            .collect()
            .await
            .expect("body")
            .to_bytes();
        let payload: serde_json::Value = serde_json::from_slice(&body).expect("json");
        assert_eq!(payload["status"], "stopping");
        assert_eq!(payload["shutdown_requested"], true);
        assert_eq!(payload["hub_thread_alive"], false);
        assert!(payload["last_stop_at"].as_str().is_some());

        let start = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::POST)
                    .uri("/Control/Start")
                    .header("X-API-Key", "secret")
                    .body(Body::empty())
                    .expect("request"),
            )
            .await
            .expect("start response");
        assert_eq!(start.status(), StatusCode::OK);
        let body = start.into_body().collect().await.expect("body").to_bytes();
        let payload: serde_json::Value = serde_json::from_slice(&body).expect("json");
        assert_eq!(payload["status"], "running");
        assert_eq!(payload["shutdown_requested"], false);
        assert_eq!(payload["hub_thread_alive"], true);
        assert!(payload["last_start_at"].as_str().is_some());

        for uri in ["/Control/Announce", "/Control/Sync"] {
            let response = app
                .clone()
                .oneshot(
                    Request::builder()
                        .method(Method::POST)
                        .uri(uri)
                        .header("X-API-Key", "secret")
                        .body(Body::empty())
                        .expect("request"),
                )
                .await
                .expect("response");
            assert_eq!(response.status(), StatusCode::SERVICE_UNAVAILABLE);
            let body = response
                .into_body()
                .collect()
                .await
                .expect("body")
                .to_bytes();
            let payload: serde_json::Value = serde_json::from_slice(&body).expect("json");
            assert!(
                payload["detail"]
                    .as_str()
                    .expect("detail")
                    .contains("unavailable")
            );
        }
    }

