    #[test]
    fn live_managed_reticulumd_start_stop_start_cycle_when_configured() {
        let reticulumd_exe = std::env::var_os("R3AKT_RETICULUMD_EXE")
            .map(std::path::PathBuf::from)
            .or_else(|| {
                let documented_path = std::path::PathBuf::from(
                    r"C:\Users\broth\Documents\work\ATAK\src\LXMF-rs\target\debug\reticulumd.exe",
                );
                documented_path.exists().then_some(documented_path)
            });
        let Some(reticulumd_exe) = reticulumd_exe else {
            eprintln!("skipping managed reticulumd lifecycle test: R3AKT_RETICULUMD_EXE is unset");
            return;
        };
        if !reticulumd_exe.exists() {
            eprintln!(
                "skipping managed reticulumd lifecycle test: {} does not exist",
                reticulumd_exe.display()
            );
            return;
        }
        let listener = std::net::TcpListener::bind("127.0.0.1:0").expect("free rpc port");
        let endpoint = listener.local_addr().expect("rpc addr").to_string();
        drop(listener);
        let db_path = std::env::temp_dir().join(format!(
            "r3akt-managed-reticulumd-live-{}.db",
            Uuid::new_v4()
        ));
        let state = crate::AppState::default()
            .with_reticulumd_rpc(endpoint.as_str(), "source-destination")
            .with_managed_reticulumd(
                &reticulumd_exe,
                endpoint.as_str(),
                Some(db_path.to_string_lossy().to_string()),
                None::<&str>,
            );

        let initial_pid = state
            .start_managed_reticulumd()
            .expect("start managed reticulumd")
            .expect("pid");
        let running = crate::runtime_services_payload(&state);
        let managed = running
            .as_array()
            .expect("services")
            .iter()
            .find(|service| service["name"] == "reticulumd_managed_process")
            .expect("managed service");
        assert_eq!(managed["status"], "running");
        assert_eq!(managed["running"], true);
        assert_eq!(managed["pid"], initial_pid);

        state.stop_managed_reticulumd().expect("stop managed");
        let stopped = crate::runtime_services_payload(&state);
        let managed = stopped
            .as_array()
            .expect("services")
            .iter()
            .find(|service| service["name"] == "reticulumd_managed_process")
            .expect("managed service");
        assert_eq!(managed["status"], "stopped");
        assert_eq!(managed["running"], false);
        std::thread::sleep(Duration::from_millis(200));

        let _restarted_pid = state
            .start_managed_reticulumd()
            .expect("restart managed reticulumd")
            .expect("pid");
        state.stop_managed_reticulumd().expect("final stop managed");
        let _ = std::fs::remove_file(&db_path);
        let _ = std::fs::remove_file(format!("{}-shm", db_path.to_string_lossy()));
        let _ = std::fs::remove_file(format!("{}-wal", db_path.to_string_lossy()));
    }

    #[test]
    fn runtime_exit_shutdown_marks_retry_worker_stopped() {
        let state = crate::AppState::default();

        crate::set_outbound_retry_worker_running(&state, true, Duration::from_millis(25));
        crate::shutdown_runtime_for_exit(&state).expect("shutdown");

        let control = state.runtime_control.read().expect("control");
        assert_eq!(control.status, "stopping");
        assert!(control.shutdown_requested);
        assert!(control.last_stop_ts_ms.is_some());
        drop(control);

        let retry_worker = state
            .outbound_retry_worker_stats
            .read()
            .expect("retry worker");
        assert!(!retry_worker.running);
    }

