    #[tokio::test]
    async fn marker_routes_persist_crud_with_python_shapes() {
        let db_path = std::env::temp_dir().join(format!("r3akt-rch-markers-{}.db", Uuid::new_v4()));
        let app = crate::create_app_with_state(
            crate::AppState::from_sqlite_path(&db_path)
                .expect("state")
                .with_api_key("secret"),
        );

        let created = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::POST)
                    .uri("/api/markers")
                    .header("X-API-Key", "secret")
                    .header(axum::http::header::CONTENT_TYPE, "application/json")
                    .body(Body::from(
                        r#"{"type":"marker","symbol":"marker","name":"Alpha","category":"general","lat":45.1,"lon":-63.2,"notes":"note"}"#,
                    ))
                    .expect("request"),
            )
            .await
            .expect("create response");
        assert_eq!(created.status(), StatusCode::CREATED);
        let body = created
            .into_body()
            .collect()
            .await
            .expect("body")
            .to_bytes();
        let payload: serde_json::Value = serde_json::from_slice(&body).expect("json");
        let marker_id = payload["object_destination_hash"]
            .as_str()
            .expect("marker id")
            .to_string();
        assert!(payload["created_at"].as_str().is_some());

        let listed = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::GET)
                    .uri("/api/markers")
                    .header("X-API-Key", "secret")
                    .body(Body::empty())
                    .expect("request"),
            )
            .await
            .expect("list response");
        assert_eq!(listed.status(), StatusCode::OK);
        let body = listed.into_body().collect().await.expect("body").to_bytes();
        let payload: serde_json::Value = serde_json::from_slice(&body).expect("json");
        assert_eq!(payload.as_array().expect("markers").len(), 1);
        assert_eq!(payload[0]["object_destination_hash"], marker_id);
        assert_eq!(payload[0]["name"], "Alpha");
        assert_eq!(payload[0]["position"], json!({"lat": 45.1, "lon": -63.2}));

        let alias_created = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::POST)
                    .uri("/api/markers")
                    .header("X-API-Key", "secret")
                    .header(axum::http::header::CONTENT_TYPE, "application/json")
                    .body(Body::from(
                        r#"{"type":"car","symbol":"uav","name":"Alias","lat":45.2,"lon":-63.3}"#,
                    ))
                    .expect("request"),
            )
            .await
            .expect("alias create response");
        assert_eq!(alias_created.status(), StatusCode::CREATED);
        let listed_alias = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::GET)
                    .uri("/api/markers")
                    .header("X-API-Key", "secret")
                    .body(Body::empty())
                    .expect("request"),
            )
            .await
            .expect("alias list response");
        assert_eq!(listed_alias.status(), StatusCode::OK);
        let body = listed_alias
            .into_body()
            .collect()
            .await
            .expect("body")
            .to_bytes();
        let payload: serde_json::Value = serde_json::from_slice(&body).expect("json");
        let alias = payload
            .as_array()
            .expect("markers")
            .iter()
            .find(|entry| entry["name"] == "Alias")
            .expect("alias marker");
        assert_eq!(alias["type"], "vehicle");
        assert_eq!(alias["symbol"], "drone");
        assert_eq!(alias["category"], "drone");

        let moved = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::PATCH)
                    .uri(format!("/api/markers/{marker_id}/position"))
                    .header("X-API-Key", "secret")
                    .header(axum::http::header::CONTENT_TYPE, "application/json")
                    .body(Body::from(r#"{"lat":46.0,"lon":-64.0}"#))
                    .expect("request"),
            )
            .await
            .expect("position response");
        assert_eq!(moved.status(), StatusCode::OK);
        let body = moved.into_body().collect().await.expect("body").to_bytes();
        let payload: serde_json::Value = serde_json::from_slice(&body).expect("json");
        assert_eq!(payload["status"], "ok");
        assert!(payload["updated_at"].as_str().is_some());

        let renamed = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::PATCH)
                    .uri(format!("/api/markers/{marker_id}"))
                    .header("X-API-Key", "secret")
                    .header(axum::http::header::CONTENT_TYPE, "application/json")
                    .body(Body::from(r#"{"name":"Bravo"}"#))
                    .expect("request"),
            )
            .await
            .expect("rename response");
        assert_eq!(renamed.status(), StatusCode::OK);

        let restarted = crate::create_app_with_state(
            crate::AppState::from_sqlite_path(&db_path)
                .expect("restart state")
                .with_api_key("secret"),
        );
        let persisted = restarted
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::GET)
                    .uri("/api/markers")
                    .header("X-API-Key", "secret")
                    .body(Body::empty())
                    .expect("request"),
            )
            .await
            .expect("persisted response");
        assert_eq!(persisted.status(), StatusCode::OK);
        let body = persisted
            .into_body()
            .collect()
            .await
            .expect("body")
            .to_bytes();
        let payload: serde_json::Value = serde_json::from_slice(&body).expect("json");
        let persisted_marker = payload
            .as_array()
            .expect("markers")
            .iter()
            .find(|entry| entry["object_destination_hash"] == marker_id)
            .expect("persisted marker");
        assert_eq!(persisted_marker["name"], "Bravo");
        assert_eq!(
            persisted_marker["position"],
            json!({"lat": 46.0, "lon": -64.0})
        );

        let deleted = restarted
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::DELETE)
                    .uri(format!("/api/markers/{marker_id}"))
                    .header("X-API-Key", "secret")
                    .body(Body::empty())
                    .expect("request"),
            )
            .await
            .expect("delete response");
        assert_eq!(deleted.status(), StatusCode::OK);
        let body = deleted
            .into_body()
            .collect()
            .await
            .expect("body")
            .to_bytes();
        let payload: serde_json::Value = serde_json::from_slice(&body).expect("json");
        assert_eq!(payload["status"], "ok");
        assert!(payload["deleted_at"].as_str().is_some());

        let events = restarted
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::GET)
                    .uri("/Events")
                    .header("X-API-Key", "secret")
                    .body(Body::empty())
                    .expect("request"),
            )
            .await
            .expect("events response");
        assert_eq!(events.status(), StatusCode::OK);
        let body = events
            .into_body()
            .collect()
            .await
            .expect("events body")
            .to_bytes();
        let payload: serde_json::Value = serde_json::from_slice(&body).expect("events json");
        let event_types = payload
            .as_array()
            .expect("events")
            .iter()
            .map(|event| event["type"].as_str().expect("event type"))
            .collect::<Vec<_>>();
        assert!(event_types.contains(&"marker_created"));
        assert!(event_types.contains(&"marker_updated"));
        assert!(event_types.contains(&"marker_deleted"));
        assert!(event_types.contains(&"marker_telemetry_recorded"));

        let telemetry = restarted
            .oneshot(
                Request::builder()
                    .method(Method::GET)
                    .uri("/Telemetry?since=0")
                    .header("X-API-Key", "secret")
                    .body(Body::empty())
                    .expect("request"),
            )
            .await
            .expect("telemetry response");
        assert_eq!(telemetry.status(), StatusCode::OK);
        let body = telemetry
            .into_body()
            .collect()
            .await
            .expect("telemetry body")
            .to_bytes();
        let payload: serde_json::Value = serde_json::from_slice(&body).expect("telemetry json");
        let entries = payload["entries"].as_array().expect("telemetry entries");
        assert_eq!(
            entries.len(),
            2,
            "Python /Telemetry returns the latest location row per peer"
        );
        assert!(entries.iter().any(|entry| {
            entry["peer_destination"] == marker_id
                && entry["telemetry"]["custom"]["metadata"]["event_type"] == "marker.deleted"
                && entry["telemetry"]["location"]["latitude"] == 46.0
        }));

        let snapshot = RchSqliteStore::open(&db_path)
            .expect("store")
            .load_snapshot()
            .expect("load snapshot")
            .expect("snapshot exists");
        assert_eq!(snapshot.telemetry_records.len(), 5);
        assert!(
            snapshot
                .system_events
                .iter()
                .any(|event| event.event_type == "marker_deleted")
        );

        let _ = std::fs::remove_file(db_path);
    }

    #[tokio::test]
    async fn marker_create_sends_rem_telemetry_command_and_generic_markdown() {
        let (endpoint, rpc_server) = fake_reticulumd_rpc_server_with_results(vec![
            json!({
                "message_id": "message"
            }),
            json!({
                "message_id": "message"
            }),
        ]);
        let db_path =
            std::env::temp_dir().join(format!("r3akt-rch-marker-fanout-{}.db", Uuid::new_v4()));
        let mut store = RchSqliteStore::open(&db_path).expect("sqlite");
        let now = crate::unix_now_ms();
        let mut snapshot = r3akt_rch_core::RchCore::new().snapshot();
        snapshot.clients = vec![
            test_client("aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa", now),
            test_client("bbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbb", now),
        ];
        snapshot.identity_announces = vec![
            r3akt_rch_core::IdentityAnnounceRecord {
                destination_hash: "aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa".to_string(),
                announced_identity_hash: None,
                display_name: Some("REM Phone".to_string()),
                source_interface: Some("identity".to_string()),
                announce_capabilities: vec![
                    "r3akt".to_string(),
                    "emergencymessages".to_string(),
                    "telemetry".to_string(),
                ],
                client_type: "rem".to_string(),
                first_seen_ts_ms: now,
                last_seen_ts_ms: now,
            },
            r3akt_rch_core::IdentityAnnounceRecord {
                destination_hash: "bbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbb".to_string(),
                announced_identity_hash: None,
                display_name: Some("LXMF Peer".to_string()),
                source_interface: Some("identity".to_string()),
                announce_capabilities: vec!["group_chat".to_string()],
                client_type: "generic_lxmf".to_string(),
                first_seen_ts_ms: now,
                last_seen_ts_ms: now,
            },
        ];
        store.save_snapshot(&snapshot).expect("save snapshot");

        let state = crate::AppState::from_sqlite_path(&db_path)
            .expect("state")
            .with_api_key("secret")
            .with_reticulumd_rpc(endpoint, "source-destination");
        let app = crate::create_app_with_state(state.clone());

        let created = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::POST)
                    .uri("/api/markers")
                    .header("X-API-Key", "secret")
                    .header(axum::http::header::CONTENT_TYPE, "application/json")
                    .body(Body::from(
                        r#"{"type":"marker","symbol":"marker","name":"Hostile","category":"hostile","lat":45.5017,"lon":-73.5673,"notes":"red force"}"#,
                    ))
                    .expect("request"),
            )
            .await
            .expect("create response");
        let status = created.status();
        let body = created
            .into_body()
            .collect()
            .await
            .expect("body")
            .to_bytes();
        assert_eq!(
            status,
            StatusCode::CREATED,
            "{}",
            String::from_utf8_lossy(&body)
        );

        let report = crate::process_due_outbound_retry_messages(&state).expect("worker report");
        assert_eq!(report.processed, 1);
        assert_eq!(report.dispatched, 1);
        assert_eq!(report.failed, 0);
        let requests = rpc_server.join().expect("rpc requests");
        let rem = requests
            .iter()
            .find(|request| {
                request.params.as_ref().expect("params")["destination"]
                    .as_str()
                    .is_some_and(|destination| destination == "aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa")
            })
            .expect("rem request");
        assert_eq!(rem.method, "send_message_v2");
        let rem_params = rem.params.as_ref().expect("rem params");
        assert_eq!(rem_params["title"], "");
        assert_eq!(rem_params["content"], crate::REM_COMMAND_PLACEHOLDER_BODY);
        assert_rem_auto_rpc_method(rem_params);
        let command = &rem_params["fields"][crate::FIELD_COMMANDS.to_string()][0];
        assert_eq!(command["command_type"], "mission.registry.telemetry.upsert");
        assert!(command.get("source").is_none());
        assert_eq!(command["args"]["callsign"], "Hostile");
        assert_eq!(command["args"]["lat"], 45.5017);
        assert_eq!(command["args"]["lon"], -73.5673);
        assert_eq!(command["args"]["category"], "hostile");
        assert_eq!(command["args"]["notes"], "red force");

        assert!(!requests.iter().any(|request| {
            request.params.as_ref().expect("params")["destination"]
                .as_str()
                .is_some_and(|destination| destination == "bbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbb")
        }));
        let snapshot = store
            .load_snapshot()
            .expect("load snapshot")
            .expect("snapshot");
        assert!(!snapshot.messages.iter().any(|message| {
            message.destination.as_deref() == Some("bbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbb")
        }));

        let _ = std::fs::remove_file(db_path);
    }

    #[tokio::test]
    #[ignore = "legacy generic markdown southbound compatibility removed for Rust 3.0"]
    async fn mission_zone_link_sends_rem_command_and_generic_markdown() {
        let db_path =
            std::env::temp_dir().join(format!("r3akt-rch-zone-fanout-{}.db", Uuid::new_v4()));
        let mut store = RchSqliteStore::open(&db_path).expect("sqlite");
        let now = crate::unix_now_ms();
        let mut snapshot = r3akt_rch_core::RchCore::new().snapshot();
        snapshot.clients = vec![
            test_client("aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa", now),
            test_client("bbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbb", now),
        ];
        snapshot.identity_announces = vec![
            r3akt_rch_core::IdentityAnnounceRecord {
                destination_hash: "aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa".to_string(),
                announced_identity_hash: None,
                display_name: Some("REM Phone".to_string()),
                source_interface: Some("identity".to_string()),
                announce_capabilities: vec![
                    "r3akt".to_string(),
                    "emergencymessages".to_string(),
                    "telemetry".to_string(),
                ],
                client_type: "rem".to_string(),
                first_seen_ts_ms: now,
                last_seen_ts_ms: now,
            },
            r3akt_rch_core::IdentityAnnounceRecord {
                destination_hash: "bbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbb".to_string(),
                announced_identity_hash: None,
                display_name: Some("LXMF Peer".to_string()),
                source_interface: Some("identity".to_string()),
                announce_capabilities: vec!["group_chat".to_string()],
                client_type: "generic_lxmf".to_string(),
                first_seen_ts_ms: now,
                last_seen_ts_ms: now,
            },
        ];
        store.save_snapshot(&snapshot).expect("save snapshot");

        let state = crate::AppState::from_sqlite_path(&db_path)
            .expect("state")
            .with_api_key("secret");
        let app = crate::create_app_with_state(state.clone());

        let mission = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::POST)
                    .uri("/api/r3akt/missions")
                    .header("X-API-Key", "secret")
                    .header(axum::http::header::CONTENT_TYPE, "application/json")
                    .body(Body::from(
                        r#"{"uid":"zone-mission","mission_name":"Zone Mission"}"#,
                    ))
                    .expect("request"),
            )
            .await
            .expect("mission response");
        assert_eq!(mission.status(), StatusCode::OK);

        let zone = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::POST)
                    .uri("/api/zones")
                    .header("X-API-Key", "secret")
                    .header(axum::http::header::CONTENT_TYPE, "application/json")
                    .body(Body::from(
                        r#"{"name":"Link Zone","points":[{"lat":45.0,"lon":-63.0},{"lat":45.1,"lon":-63.1},{"lat":45.2,"lon":-63.2}]}"#,
                    ))
                    .expect("request"),
            )
            .await
            .expect("zone response");
        assert_eq!(zone.status(), StatusCode::CREATED);
        let body = zone.into_body().collect().await.expect("body").to_bytes();
        let zone_payload: serde_json::Value = serde_json::from_slice(&body).expect("json");
        let zone_id = zone_payload["zone_id"].as_str().expect("zone id");

        let linked = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::PUT)
                    .uri(format!("/api/r3akt/missions/zone-mission/zones/{zone_id}"))
                    .header("X-API-Key", "secret")
                    .body(Body::empty())
                    .expect("request"),
            )
            .await
            .expect("link response");
        let status = linked.status();
        let body = linked.into_body().collect().await.expect("body").to_bytes();
        assert_eq!(status, StatusCode::OK, "{}", String::from_utf8_lossy(&body));

        let snapshot = store
            .load_snapshot()
            .expect("load snapshot")
            .expect("snapshot");
        let rem = snapshot
            .messages
            .iter()
            .find(|message| {
                message.destination.as_deref() == Some("aaaaaaaaaaaaaaaaaaaaaaaaaaaaaaaa")
            })
            .expect("rem message");
        assert_eq!(rem.content, crate::REM_COMMAND_PLACEHOLDER_BODY);
        assert_eq!(
            rem.delivery_metadata["dispatch_status"],
            json!("queued_deferred")
        );
        let command = &rem.delivery_metadata["lxmf_fields"][crate::FIELD_COMMANDS.to_string()][0];
        assert_eq!(
            command["command_type"],
            "mission.registry.mission.zone.link"
        );
        assert_eq!(command["args"]["mission_uid"], "zone-mission");
        assert_eq!(command["args"]["zone_id"], zone_id);

        let generic = snapshot
            .messages
            .iter()
            .find(|message| {
                message.destination.as_deref() == Some("bbbbbbbbbbbbbbbbbbbbbbbbbbbbbbbb")
            })
            .expect("generic message");
        assert_eq!(
            generic.content,
            "### Mission Zone Mission\n- Update: Zone linked\n- Zone: Link Zone"
        );
        assert!(
            generic.delivery_metadata["lxmf_fields"]
                .get(crate::FIELD_COMMANDS.to_string())
                .is_none()
        );
        assert_eq!(
            generic.delivery_metadata["delivery_receipt_required"],
            false
        );
        assert_eq!(generic.delivery_metadata["max_attempts"], 1);

        let _ = std::fs::remove_file(db_path);
    }

