    #[tokio::test]
    async fn r3akt_rights_definitions_include_persona_role_bundles() {
        let app = crate::create_app_with_state(crate::AppState::default().with_api_key("secret"));
        let response = app
            .oneshot(
                Request::builder()
                    .method(Method::GET)
                    .uri("/api/r3akt/rights/definitions")
                    .header("X-API-Key", "secret")
                    .body(Body::empty())
                    .expect("request"),
            )
            .await
            .expect("definitions response");
        assert_eq!(response.status(), StatusCode::OK);
        let body = response
            .into_body()
            .collect()
            .await
            .expect("body")
            .to_bytes();
        let payload: Value = serde_json::from_slice(&body).expect("json");
        let role_bundles = payload["role_bundles"].as_array().expect("role bundles");
        for role in [
            "FIELD_OPERATOR",
            "TEAM_LEAD",
            "INCIDENT_COMMANDER",
            "LOGISTICS_RESOURCE_MANAGER",
            "COMMUNICATIONS_OPERATOR",
            "SYSTEM_ADMIN",
        ] {
            assert!(
                role_bundles.iter().any(|bundle| bundle["role"] == role),
                "{role} bundle missing"
            );
        }
        assert!(
            payload["mission_role_bundles"]["FIELD_OPERATOR"]
                .as_array()
                .expect("field operator mission bundle")
                .iter()
                .any(|operation| operation.as_str() == Some("mission.message.send"))
        );
        assert!(
            payload["operations"]
                .as_array()
                .expect("operations")
                .iter()
                .any(|operation| operation.as_str() == Some("admin.config.write"))
        );
    }

    #[tokio::test]
    async fn r3akt_rights_routes_persist_with_python_shapes() {
        let db_path =
            std::env::temp_dir().join(format!("r3akt-rch-r3akt-rights-{}.db", Uuid::new_v4()));
        let app = crate::create_app_with_state(
            crate::AppState::from_sqlite_path(&db_path)
                .expect("state")
                .with_api_key("secret"),
        );

        for (method, uri, body) in [
            (
                Method::POST,
                "/api/r3akt/missions",
                r#"{"uid":"rights-mission","mission_name":"Rights Mission","default_role":"MISSION_SUBSCRIBER"}"#,
            ),
            (
                Method::POST,
                "/api/r3akt/teams",
                r#"{"uid":"rights-team","mission_uid":"rights-mission","team_name":"Ops"}"#,
            ),
            (
                Method::POST,
                "/api/r3akt/team-members",
                r#"{"uid":"rights-member","team_uid":"rights-team","rns_identity":"PEER-A","display_name":"Peer A"}"#,
            ),
        ] {
            let response = app
                .clone()
                .oneshot(
                    Request::builder()
                        .method(method)
                        .uri(uri)
                        .header("X-API-Key", "secret")
                        .header(axum::http::header::CONTENT_TYPE, "application/json")
                        .body(Body::from(body))
                        .expect("request"),
                )
                .await
                .expect("setup response");
            assert_eq!(response.status(), StatusCode::OK, "{uri}");
        }

        let capability = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::PUT)
                    .uri("/api/r3akt/capabilities/ABCDEF/topic.create")
                    .header("X-API-Key", "secret")
                    .header(axum::http::header::CONTENT_TYPE, "application/json")
                    .body(Body::from(r#"{"granted_by":"admin"}"#))
                    .expect("request"),
            )
            .await
            .expect("capability response");
        assert_eq!(capability.status(), StatusCode::OK);

        let operation_right = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::PUT)
                    .uri("/api/r3akt/rights/grants")
                    .header("X-API-Key", "secret")
                    .header(axum::http::header::CONTENT_TYPE, "application/json")
                    .body(Body::from(
                        r#"{"subject_type":"team_member","subject_id":"rights-member","operation":"mission.registry.log.read","scope_type":"mission","scope_id":"rights-mission","granted_by":"admin"}"#,
                    ))
                    .expect("request"),
            )
            .await
            .expect("operation right response");
        assert_eq!(operation_right.status(), StatusCode::OK);

        let mission_access = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::PUT)
                    .uri("/api/r3akt/rights/mission-access")
                    .header("X-API-Key", "secret")
                    .header(axum::http::header::CONTENT_TYPE, "application/json")
                    .body(Body::from(
                        r#"{"mission_uid":"rights-mission","subject_type":"team_member","subject_id":"rights-member","role":"MISSION_OWNER","assigned_by":"admin"}"#,
                    ))
                    .expect("request"),
            )
            .await
            .expect("mission access response");
        assert_eq!(mission_access.status(), StatusCode::OK);

        let restarted = crate::create_app_with_state(
            crate::AppState::from_sqlite_path(&db_path)
                .expect("restart state")
                .with_api_key("secret"),
        );

        for (uri, expected) in [
            (
                "/api/r3akt/capabilities/ABCDEF",
                json!({
                    "identity": "ABCDEF",
                    "capability": "topic.create",
                }),
            ),
            (
                "/api/r3akt/rights/subjects?mission_uid=rights-mission",
                json!({
                    "subject_id": "rights-member",
                    "rns_identity": "PEER-A",
                }),
            ),
            (
                "/api/r3akt/rights/grants?subject_type=team_member&subject_id=rights-member&scope_type=mission&scope_id=rights-mission",
                json!({
                    "subject_type": "team_member",
                    "subject_id": "rights-member",
                    "operation": "mission.registry.log.read",
                    "scope_type": "mission",
                    "scope_id": "rights-mission",
                    "granted": true,
                }),
            ),
            (
                "/api/r3akt/rights/mission-access?mission_uid=rights-mission",
                json!({
                    "mission_uid": "rights-mission",
                    "subject_type": "team_member",
                    "subject_id": "rights-member",
                    "role": "MISSION_OWNER",
                }),
            ),
        ] {
            let response = restarted
                .clone()
                .oneshot(
                    Request::builder()
                        .method(Method::GET)
                        .uri(uri)
                        .header("X-API-Key", "secret")
                        .body(Body::empty())
                        .expect("request"),
                )
                .await
                .expect("list response");
            assert_eq!(response.status(), StatusCode::OK, "{uri}");
            let body = response
                .into_body()
                .collect()
                .await
                .expect("body")
                .to_bytes();
            let payload: serde_json::Value = serde_json::from_slice(&body).expect("json");
            if uri.contains("capabilities") {
                assert_eq!(payload["identity"], expected["identity"], "{uri}");
                assert!(
                    payload["capabilities"]
                        .as_array()
                        .expect("capabilities")
                        .iter()
                        .any(|item| item == &expected["capability"]),
                    "{uri}"
                );
                assert!(
                    payload["grants"].as_array().expect("grants").iter().any(
                        |grant| grant["identity"] == "abcdef"
                            && grant["capability"] == expected["capability"]
                            && grant["granted"] == true
                    ),
                    "{uri}"
                );
            } else {
                let rows = payload.as_array().expect("list");
                assert!(
                    rows.iter().any(|row| expected
                        .as_object()
                        .expect("expected")
                        .iter()
                        .all(|(key, value)| row[key] == *value)),
                    "{uri}: {payload}"
                );
            }
        }

        for (uri, body, expected_deleted) in [
            (
                "/api/r3akt/rights/mission-access",
                r#"{"mission_uid":"rights-mission","subject_type":"team_member","subject_id":"rights-member"}"#,
                true,
            ),
            (
                "/api/r3akt/rights/grants",
                r#"{"subject_type":"team_member","subject_id":"rights-member","operation":"mission.registry.log.read","scope_type":"mission","scope_id":"rights-mission"}"#,
                false,
            ),
        ] {
            let response = restarted
                .clone()
                .oneshot(
                    Request::builder()
                        .method(Method::DELETE)
                        .uri(uri)
                        .header("X-API-Key", "secret")
                        .header(axum::http::header::CONTENT_TYPE, "application/json")
                        .body(Body::from(body))
                        .expect("request"),
                )
                .await
                .expect("delete response");
            assert_eq!(response.status(), StatusCode::OK, "{uri}");
            let body = response
                .into_body()
                .collect()
                .await
                .expect("body")
                .to_bytes();
            let payload: serde_json::Value = serde_json::from_slice(&body).expect("json");
            assert_eq!(
                payload
                    .get("deleted")
                    .or_else(|| payload.get("granted"))
                    .cloned(),
                Some(json!(expected_deleted)),
                "{uri}"
            );
        }

        let revoked_capability = restarted
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::DELETE)
                    .uri("/api/r3akt/capabilities/ABCDEF/topic.create")
                    .header("X-API-Key", "secret")
                    .header(axum::http::header::CONTENT_TYPE, "application/json")
                    .body(Body::from("{}"))
                    .expect("request"),
            )
            .await
            .expect("capability revoke response");
        assert_eq!(revoked_capability.status(), StatusCode::OK);

        let _ = std::fs::remove_file(db_path);
    }

