    #[tokio::test]
    async fn internal_event_stream_accepts_without_api_key() {
        let listener = TcpListener::bind("127.0.0.1:0").await.expect("bind");
        let addr = listener.local_addr().expect("addr");
        let server = tokio::spawn(async move {
            axum::serve(
                listener,
                crate::create_app_with_state(crate::AppState::default().with_api_key("secret")),
            )
            .await
            .expect("server");
        });

        let (mut socket, _) = connect_async(format!("ws://{addr}/internal/events/stream"))
            .await
            .expect("websocket connect");
        socket
            .send(Message::Text("client-ready".into()))
            .await
            .expect("send client probe");
        let no_immediate_error =
            tokio::time::timeout(std::time::Duration::from_millis(100), socket.next()).await;
        assert!(no_immediate_error.is_err());

        socket.close(None).await.expect("close websocket");
        server.abort();
    }

    #[tokio::test]
    async fn internal_event_stream_fans_out_internal_message_events() {
        let app = crate::create_app_with_state(crate::AppState::default().with_api_key("secret"));
        let listener = TcpListener::bind("127.0.0.1:0").await.expect("bind");
        let addr = listener.local_addr().expect("addr");
        let server_app = app.clone();
        let server = tokio::spawn(async move {
            axum::serve(listener, server_app).await.expect("server");
        });

        let (mut socket, _) = connect_async(format!("ws://{addr}/internal/events/stream"))
            .await
            .expect("websocket connect");

        let accepted = app
            .oneshot(
                Request::builder()
                    .method(Method::POST)
                    .uri("/internal/message")
                    .header(axum::http::header::CONTENT_TYPE, "application/json")
                    .body(Body::from(
                        r#"{"destination":"mission.alpha","text":"hello event"}"#,
                    ))
                    .expect("request"),
            )
            .await
            .expect("message response");
        assert_eq!(accepted.status(), StatusCode::OK);

        let frame = tokio::time::timeout(std::time::Duration::from_secs(2), socket.next())
            .await
            .expect("event frame timeout")
            .expect("event frame")
            .expect("event frame ok");
        let payload: serde_json::Value =
            serde_json::from_str(frame.to_text().expect("text frame")).expect("event json");
        assert_eq!(payload["api_version"], "v1");
        assert_eq!(payload["event_type"], "MessagePublished");
        assert_eq!(payload["origin"], "hub-core");
        assert_eq!(payload["payload"]["topic_path"], "mission.alpha");
        assert_eq!(payload["payload"]["originator"], "internal-adapter");
        assert!(payload["event_id"].as_str().is_some());
        assert!(payload["occurred_at"].as_str().is_some());
        assert!(payload["payload"]["message_id"].as_str().is_some());

        socket.close(None).await.expect("close websocket");
        server.abort();
    }

    #[tokio::test]
