        assert_eq!(payload["identity_hash_hex_length"], 0);
        assert!(payload["supported_interface_types"].as_array().is_some());
        assert!(payload["unsupported_interface_types"].as_array().is_some());
        assert!(payload["discoverable_interface_types"].as_array().is_some());
