    #[tokio::test]
    async fn config_validate_routes_match_python_parser_shape() {
        let app = crate::create_app_with_state(crate::AppState::default().with_api_key("secret"));

        let missing_auth = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::POST)
                    .uri("/Config/Validate")
                    .header(axum::http::header::CONTENT_TYPE, "text/plain")
                    .body(Body::from("[general]\nname = rch\n"))
                    .expect("request"),
            )
            .await
            .expect("missing auth response");
        assert_eq!(missing_auth.status(), StatusCode::UNAUTHORIZED);

        for uri in ["/Config/Validate", "/Reticulum/Config/Validate"] {
            let response = app
                .clone()
                .oneshot(
                    Request::builder()
                        .method(Method::POST)
                        .uri(uri)
                        .header("X-API-Key", "secret")
                        .header(axum::http::header::CONTENT_TYPE, "text/plain")
                        .body(Body::from("[general]\nname = rch\n"))
                        .expect("request"),
                )
                .await
                .expect("response");
            assert_eq!(response.status(), StatusCode::OK);
            let body = response
                .into_body()
                .collect()
                .await
                .expect("body")
                .to_bytes();
            let payload: serde_json::Value = serde_json::from_slice(&body).expect("json");
            assert_eq!(payload, json!({"valid": true, "errors": []}));

            let invalid_response = app
                .clone()
                .oneshot(
                    Request::builder()
                        .method(Method::POST)
                        .uri(uri)
                        .header("X-API-Key", "secret")
                        .header(axum::http::header::CONTENT_TYPE, "text/plain")
                        .body(Body::from("name = rch\n"))
                        .expect("request"),
                )
                .await
                .expect("invalid response");
            assert_eq!(invalid_response.status(), StatusCode::OK);
            let body = invalid_response
                .into_body()
                .collect()
                .await
                .expect("invalid body")
                .to_bytes();
            let payload: serde_json::Value = serde_json::from_slice(&body).expect("json");
            assert_eq!(payload["valid"], false);
            let errors = payload["errors"].as_array().expect("errors");
            assert_eq!(errors.len(), 1);
            assert!(errors[0].as_str().expect("error text").contains("section"));
        }
    }

