    #[tokio::test]
    async fn http_auth_matches_python_local_and_remote_client_rules() {
        let local_addr = SocketAddr::from(([127, 0, 0, 1], 50_000));
        let remote_addr = SocketAddr::from(([198, 51, 100, 10], 50_000));

        let keyed_app =
            crate::create_app_with_state(crate::AppState::default().with_api_key("secret"));
        let local_without_key = keyed_app
            .oneshot(
                Request::builder()
                    .method(Method::GET)
                    .uri("/Status")
                    .extension(ConnectInfo(local_addr))
                    .body(Body::empty())
                    .expect("request"),
            )
            .await
            .expect("local response");
        assert_eq!(local_without_key.status(), StatusCode::OK);

        let local_auth = crate::create_app_with_state(crate::AppState::default())
            .oneshot(
                Request::builder()
                    .method(Method::GET)
                    .uri("/api/v1/auth/validate")
                    .extension(ConnectInfo(local_addr))
                    .body(Body::empty())
                    .expect("request"),
            )
            .await
            .expect("local auth response");
        assert_eq!(local_auth.status(), StatusCode::OK);
        let body = local_auth
            .into_body()
            .collect()
            .await
            .expect("body")
            .to_bytes();
        let payload: serde_json::Value = serde_json::from_slice(&body).expect("json");
        assert_eq!(payload["authenticated"], true);
        assert_eq!(payload["auth_mode"], "local_only");
        assert_eq!(payload["client"]["host"], "127.0.0.1");
        assert_eq!(payload["client"]["local"], true);

        let remote_without_key = crate::create_app_with_state(crate::AppState::default())
            .oneshot(
                Request::builder()
                    .method(Method::GET)
                    .uri("/api/v1/auth/validate")
                    .extension(ConnectInfo(remote_addr))
                    .body(Body::empty())
                    .expect("request"),
            )
            .await
            .expect("remote auth response");
        assert_eq!(remote_without_key.status(), StatusCode::UNAUTHORIZED);
        let body = remote_without_key
            .into_body()
            .collect()
            .await
            .expect("body")
            .to_bytes();
        let payload: serde_json::Value = serde_json::from_slice(&body).expect("json");
        assert_eq!(
            payload["detail"],
            "Remote access requires authentication; set RTH_API_KEY (RCH_API_KEY is also supported)."
        );
    }

    #[test]
    fn websocket_auth_matches_python_local_and_remote_client_rules() {
        let local_addr = Some(SocketAddr::from(([127, 0, 0, 1], 50_000)));
        let remote_addr = Some(SocketAddr::from(([198, 51, 100, 10], 50_000)));

        let open_state = crate::AppState::default();
        assert!(open_state.validate_ws_credentials(None, None, None));
        assert!(open_state.validate_ws_credentials(None, None, local_addr));
        assert!(!open_state.validate_ws_credentials(None, None, remote_addr));
        assert_eq!(
            open_state.ws_auth_failure_detail(remote_addr),
            "Remote access requires authentication; set RTH_API_KEY (RCH_API_KEY is also supported)."
        );

        let keyed_state = crate::AppState::default().with_api_key("secret");
        assert!(keyed_state.validate_ws_credentials(None, None, local_addr));
        assert!(keyed_state.validate_ws_credentials(Some("secret"), None, remote_addr));
        assert!(keyed_state.validate_ws_credentials(None, Some("secret"), remote_addr));
        assert!(!keyed_state.validate_ws_credentials(Some("wrong"), None, remote_addr));
        assert_eq!(
            keyed_state.ws_auth_failure_detail(remote_addr),
            "Unauthorized"
        );
    }

