    #[tokio::test]
    async fn runtime_metrics_count_lagged_websocket_drops_like_python_queue() {
        let state = crate::AppState::default();
        let mut receiver = state.system_event_broadcast.subscribe();

        for index in 0..300 {
            let message = format!("test event {index}");
            crate::record_system_event(&state, "test", &message, json!({ "index": index }))
                .expect("event");
        }

        let dropped = match receiver.recv().await {
            Err(tokio::sync::broadcast::error::RecvError::Lagged(dropped)) => dropped,
            other => panic!("expected lagged websocket receiver, got {other:?}"),
        };
        crate::record_ws_dropped_oldest(&state, crate::WsBroadcastKind::System, dropped);

        let diagnostics = crate::runtime_diagnostics_payload(&state).expect("diagnostics");
        assert!(dropped > 0);
        assert_eq!(
            diagnostics["counters"]["ws_dropped_oldest_total"],
            json!(dropped)
        );
        assert_eq!(
            diagnostics["counters"]["ws_event_dropped_oldest_total"],
            json!(dropped)
        );
        assert_eq!(
            diagnostics["counters"]["ws_telemetry_dropped_oldest_total"],
            0
        );
        assert_eq!(
            diagnostics["counters"]["ws_message_dropped_oldest_total"],
            0
        );
    }

    async fn wait_for_ws_subscriber_gauges(
        state: &crate::AppState,
        expected_event: u64,
        expected_telemetry: u64,
        expected_message: u64,
    ) {
        let deadline = tokio::time::Instant::now() + Duration::from_secs(2);
        loop {
            let diagnostics = crate::runtime_diagnostics_payload(state).expect("diagnostics");
            let event = diagnostics["gauges"]["ws_event_subscribers"]
                .as_u64()
                .expect("event gauge");
            let telemetry = diagnostics["gauges"]["ws_telemetry_subscribers"]
                .as_u64()
                .expect("telemetry gauge");
            let message = diagnostics["gauges"]["ws_message_subscribers"]
                .as_u64()
                .expect("message gauge");
            if event == expected_event
                && telemetry == expected_telemetry
                && message == expected_message
            {
                return;
            }
            assert!(
                tokio::time::Instant::now() < deadline,
                "websocket gauges stayed at event={event}, telemetry={telemetry}, message={message}"
            );
            tokio::time::sleep(Duration::from_millis(25)).await;
        }
    }

    #[tokio::test]
    async fn websocket_disconnects_cleanup_subscriber_gauges_like_python_unsubscribe() {
        let listener = TcpListener::bind("127.0.0.1:0").await.expect("bind");
        let addr = listener.local_addr().expect("addr");
        let state = crate::AppState::default().with_api_key("secret");
        let server_state = state.clone();
        let server = tokio::spawn(async move {
            axum::serve(listener, crate::create_app_with_state(server_state))
                .await
                .expect("server");
        });

        let (mut system, _) = connect_async(format!("ws://{addr}/events/system"))
            .await
            .expect("system connect");
        system
            .send(Message::Text(
                json!({"type":"auth","data":{"api_key":"secret"}})
                    .to_string()
                    .into(),
            ))
            .await
            .expect("system auth");
        let _ = system.next().await.expect("system auth frame");

        let (mut telemetry, _) = connect_async(format!("ws://{addr}/telemetry/stream"))
            .await
            .expect("telemetry connect");
        telemetry
            .send(Message::Text(
                json!({"type":"auth","data":{"api_key":"secret"}})
                    .to_string()
                    .into(),
            ))
            .await
            .expect("telemetry auth");
        let _ = telemetry.next().await.expect("telemetry auth frame");
        telemetry
            .send(Message::Text(
                json!({"type":"telemetry.subscribe","data":{"since":0,"follow":true}})
                    .to_string()
                    .into(),
            ))
            .await
            .expect("telemetry subscribe");
        let _ = telemetry.next().await.expect("telemetry snapshot frame");

        let (mut messages, _) = connect_async(format!("ws://{addr}/messages/stream"))
            .await
            .expect("message connect");
        messages
            .send(Message::Text(
                json!({"type":"auth","data":{"api_key":"secret"}})
                    .to_string()
                    .into(),
            ))
            .await
            .expect("message auth");
        let _ = messages.next().await.expect("message auth frame");
        messages
            .send(Message::Text(
                json!({"type":"message.subscribe","data":{"follow":true}})
                    .to_string()
                    .into(),
            ))
            .await
            .expect("message subscribe");
        let _ = messages.next().await.expect("message subscribed frame");

        wait_for_ws_subscriber_gauges(&state, 1, 1, 1).await;

        drop(messages);
        drop(telemetry);
        drop(system);

        wait_for_ws_subscriber_gauges(&state, 0, 0, 0).await;
        server.abort();
    }

