    #[tokio::test]
    async fn help_and_examples_routes_return_plain_text_like_python() {
        let app = crate::create_app_with_state(crate::AppState::default().with_api_key("secret"));

        for (uri, expected_texts, rejected_texts) in [
            (
                "/Help",
                vec![
                    "# Command list",
                    "FIELD_COMMANDS",
                    "mission.registry.eam.upsert",
                    "checklist.template.list",
                    "rem.registry.mode.set",
                    "TelemetryRequest",
                ],
                vec!["migration slice"],
            ),
            (
                "/Examples",
                vec![
                    "# Supported LXMF Southbound Commands",
                    "Mission-style envelope example",
                    "mission.registry.mission.list",
                    "checklist.task.status.set",
                    "rem.registry.peers.list",
                ],
                vec!["Topic create example:"],
            ),
        ] {
            let response = app
                .clone()
                .oneshot(
                    Request::builder()
                        .method(Method::GET)
                        .uri(uri)
                        .body(Body::empty())
                        .expect("request"),
                )
                .await
                .expect("response");
            assert_eq!(response.status(), StatusCode::OK);
            let content_type = response
                .headers()
                .get("content-type")
                .and_then(|value| value.to_str().ok())
                .expect("content type");
            assert!(content_type.starts_with("text/plain"));
            let body = response
                .into_body()
                .collect()
                .await
                .expect("body")
                .to_bytes();
            let text = std::str::from_utf8(&body).expect("utf8");
            for expected_text in expected_texts {
                assert!(text.contains(expected_text), "{uri} body was {text}");
            }
            for rejected_text in rejected_texts {
                assert!(
                    !text.contains(rejected_text),
                    "{uri} still contains placeholder text: {text}"
                );
            }
        }
    }

    #[tokio::test]
    async fn message_stream_authenticates_and_confirms_subscription() {
        let listener = TcpListener::bind("127.0.0.1:0").await.expect("bind");
        let addr = listener.local_addr().expect("addr");
        let server = tokio::spawn(async move {
            axum::serve(listener, crate::create_app())
                .await
                .expect("server");
        });

        let (mut socket, _) = connect_async(format!("ws://{addr}/messages/stream"))
            .await
            .expect("websocket connect");

        socket
            .send(Message::Text(
                json!({"type":"auth","data":{"api_key":"test"}})
                    .to_string()
                    .into(),
            ))
            .await
            .expect("send auth");
        let auth_reply = socket
            .next()
            .await
            .expect("auth frame")
            .expect("auth reply");
        let auth_payload: serde_json::Value =
            serde_json::from_str(auth_reply.to_text().expect("auth text")).expect("auth json");
        assert_eq!(auth_payload["type"], "auth.ok");
        assert!(auth_payload["ts"].as_str().is_some());
        assert_eq!(auth_payload["data"], json!({}));

        socket
            .send(Message::Text(
                json!({
                    "type":"message.subscribe",
                    "data":{"topic_id":"ops","source_hash":"abc123","follow":false}
                })
                .to_string()
                .into(),
            ))
            .await
            .expect("send subscribe");
        let subscribe_reply = socket
            .next()
            .await
            .expect("subscribe frame")
            .expect("subscribe reply");
        let subscribe_payload: serde_json::Value =
            serde_json::from_str(subscribe_reply.to_text().expect("subscribe text"))
                .expect("subscribe json");
        assert_eq!(subscribe_payload["type"], "message.subscribed");
        assert!(subscribe_payload["ts"].as_str().is_some());
        assert_eq!(subscribe_payload["data"]["topic_id"], "ops");
        assert_eq!(subscribe_payload["data"]["source_hash"], "abc123");
        assert_eq!(subscribe_payload["data"]["follow"], false);

        server.abort();
    }

    #[tokio::test]
    async fn message_stream_send_persists_and_fans_out_python_shape() {
        let db_path =
            std::env::temp_dir().join(format!("r3akt-rch-ws-message-{}.db", Uuid::new_v4()));
        let listener = TcpListener::bind("127.0.0.1:0").await.expect("bind");
        let addr = listener.local_addr().expect("addr");
        let state = crate::AppState::from_sqlite_path(&db_path)
            .expect("state")
            .with_api_key("secret");
        let server = tokio::spawn(async move {
            axum::serve(listener, crate::create_app_with_state(state))
                .await
                .expect("server");
        });

        let (mut subscriber, _) = connect_async(format!("ws://{addr}/messages/stream"))
            .await
            .expect("subscriber connect");
        subscriber
            .send(Message::Text(
                json!({"type":"auth","data":{"api_key":"secret"}})
                    .to_string()
                    .into(),
            ))
            .await
            .expect("subscriber auth");
        let _ = subscriber.next().await.expect("subscriber auth frame");
        subscriber
            .send(Message::Text(
                json!({"type":"message.subscribe","data":{"topic_id":"ops","follow":true}})
                    .to_string()
                    .into(),
            ))
            .await
            .expect("subscriber subscribe");
        let subscribe_reply = subscriber
            .next()
            .await
            .expect("subscribe frame")
            .expect("subscribe reply");
        let subscribe_payload: serde_json::Value =
            serde_json::from_str(subscribe_reply.to_text().expect("subscribe text"))
                .expect("subscribe json");
        assert_eq!(subscribe_payload["type"], "message.subscribed");
        assert_eq!(subscribe_payload["data"]["topic_id"], "ops");
        assert_eq!(subscribe_payload["data"]["follow"], true);

        let (mut sender, _) = connect_async(format!("ws://{addr}/messages/stream"))
            .await
            .expect("sender connect");
        sender
            .send(Message::Text(
                json!({"type":"auth","data":{"api_key":"secret"}})
                    .to_string()
                    .into(),
            ))
            .await
            .expect("sender auth");
        let _ = sender.next().await.expect("sender auth frame");
        sender
            .send(Message::Text(
                json!({"type":"message.send","data":{"content":"WS outbound","topic_id":"ops"}})
                    .to_string()
                    .into(),
            ))
            .await
            .expect("sender send");

        let sent_reply = sender
            .next()
            .await
            .expect("sent frame")
            .expect("sent reply");
        let sent_payload: serde_json::Value =
            serde_json::from_str(sent_reply.to_text().expect("sent text")).expect("sent json");
        assert_eq!(sent_payload["type"], "message.sent");
        assert_eq!(sent_payload["data"]["ok"], true);

        let receive_reply = subscriber
            .next()
            .await
            .expect("receive frame")
            .expect("receive reply");
        let receive_payload: serde_json::Value =
            serde_json::from_str(receive_reply.to_text().expect("receive text"))
                .expect("receive json");
        assert_eq!(receive_payload["type"], "message.receive");
        assert_eq!(receive_payload["data"]["entry"]["Direction"], "outbound");
        assert_eq!(receive_payload["data"]["entry"]["Content"], "WS outbound");
        assert_eq!(receive_payload["data"]["entry"]["TopicID"], "ops");
        assert_eq!(receive_payload["data"]["entry"]["State"], "queued");
        assert!(
            receive_payload["data"]["entry"]["MessageID"]
                .as_str()
                .is_some()
        );

        drop(sender);
        drop(subscriber);
        server.abort();

        let store = RchSqliteStore::open(&db_path).expect("open sqlite");
        let snapshot = store
            .load_snapshot()
            .expect("load snapshot")
            .expect("snapshot exists");
        assert_eq!(snapshot.messages.len(), 1);
        assert_eq!(snapshot.messages[0].content, "WS outbound");
        assert_eq!(snapshot.messages[0].topic_id.as_deref(), Some("ops"));
    }

    #[tokio::test]
    async fn message_stream_rejects_non_string_destination_like_python() {
        let listener = TcpListener::bind("127.0.0.1:0").await.expect("bind");
        let addr = listener.local_addr().expect("addr");
        let server = tokio::spawn(async move {
            axum::serve(
                listener,
                crate::create_app_with_state(crate::AppState::default().with_api_key("secret")),
            )
            .await
            .expect("server");
        });

        let (mut socket, _) = connect_async(format!("ws://{addr}/messages/stream"))
            .await
            .expect("websocket connect");
        socket
            .send(Message::Text(
                json!({"type":"auth","data":{"api_key":"secret"}})
                    .to_string()
                    .into(),
            ))
            .await
            .expect("send auth");
        let _ = socket.next().await.expect("auth frame");
        socket
            .send(Message::Text(
                json!({"type":"message.send","data":{"content":"bad destination","destination":42}})
                    .to_string()
                    .into(),
            ))
            .await
            .expect("send message");

        let error_reply = socket
            .next()
            .await
            .expect("error frame")
            .expect("error reply");
        let error_payload: serde_json::Value =
            serde_json::from_str(error_reply.to_text().expect("error text")).expect("error json");
        assert_eq!(error_payload["type"], "error");
        assert_eq!(error_payload["data"]["code"], "bad_request");
        assert_eq!(
            error_payload["data"]["message"],
            "Message destination must be a string"
        );

        drop(socket);
        server.abort();
    }

