    #[tokio::test]
    async fn chat_broadcast_sends_to_all_clients() {
        let state = crate::AppState::default()
            .with_api_key("secret")
            .with_reticulumd_rpc("127.0.0.1:1", "source-destination");
        for identity in [
            "4bede2a6ecab26f234aac9bb894a441a",
            "6521979f1165965b24731061ef4a6906",
        ] {
            state.clients.write().expect("clients").insert(
                identity.to_string(),
                crate::ClientRecord::new(identity.to_string(), crate::unix_now_ms()),
            );
        }
        let app = crate::create_app_with_state(state.clone());

        let response = app
            .oneshot(
                Request::builder()
                    .method(Method::POST)
                    .uri("/Chat/Message")
                    .header("X-API-Key", "secret")
                    .header(axum::http::header::CONTENT_TYPE, "application/json")
                    .body(Body::from(
                        json!({
                            "scope": "broadcast",
                            "content": "broadcast from rust"
                        })
                        .to_string(),
                    ))
                    .expect("request"),
            )
            .await
            .expect("broadcast response");
        assert_eq!(response.status(), StatusCode::OK);

        let message = state
            .messages
            .read()
            .expect("messages")
            .first()
            .cloned()
            .expect("queued message");
        assert_eq!(message.content, "broadcast from rust");
        assert_eq!(message.delivery_state, "queued");
        assert_eq!(
            message.delivery_metadata["dispatch_status"],
            json!("queued_deferred")
        );
        let mut destinations =
            crate::outbound_destinations(&state, &message).expect("broadcast destinations");
        destinations.sort();
        assert_eq!(
            destinations,
            vec![
                "4bede2a6ecab26f234aac9bb894a441a",
                "6521979f1165965b24731061ef4a6906"
            ]
        );
    }

    #[tokio::test]
    #[ignore = "deferred outbound sends no longer emit message_sent during the request"]
    async fn events_route_persists_northbound_events_with_python_shape() {
        let db_path =
            std::env::temp_dir().join(format!("r3akt-rch-system-events-{}.db", Uuid::new_v4()));
        let app = crate::create_app_with_state(
            crate::AppState::from_sqlite_path(&db_path)
                .expect("state")
                .with_api_key("secret"),
        );

        let send_response = app
            .clone()
            .oneshot(
                Request::builder()
                    .method(Method::POST)
                    .uri("/Message")
                    .header("X-API-Key", "secret")
                    .header("content-type", "application/json")
                    .body(Body::from(
                        json!({"content":"event-backed send","topic_id":"events"}).to_string(),
                    ))
                    .expect("request"),
            )
            .await
            .expect("send response");
        assert_eq!(send_response.status(), StatusCode::OK);

        let events_response = app
            .oneshot(
                Request::builder()
                    .method(Method::GET)
                    .uri("/Events")
                    .header("X-API-Key", "secret")
                    .body(Body::empty())
                    .expect("request"),
            )
            .await
            .expect("events response");
        assert_eq!(events_response.status(), StatusCode::OK);
        let body = events_response
            .into_body()
            .collect()
            .await
            .expect("events body")
            .to_bytes();
        let events: serde_json::Value = serde_json::from_slice(&body).expect("events json");
        assert_eq!(events[0]["type"], "message_sent");
        assert_eq!(events[0]["message"], "Message sent from Rust northbound");
        assert_eq!(events[0]["metadata"]["topic_id"], "events");
        assert_eq!(events[0]["origin"], "rust");
        assert!(events[0]["timestamp"].as_str().is_some());

        let restarted = crate::create_app_with_state(
            crate::AppState::from_sqlite_path(&db_path)
                .expect("restart state")
                .with_api_key("secret"),
        );
        let restart_response = restarted
            .oneshot(
                Request::builder()
                    .method(Method::GET)
                    .uri("/Events")
                    .header("X-API-Key", "secret")
                    .body(Body::empty())
                    .expect("request"),
            )
            .await
            .expect("restart events response");
        let body = restart_response
            .into_body()
            .collect()
            .await
            .expect("restart body")
            .to_bytes();
        let restarted_events: serde_json::Value =
            serde_json::from_slice(&body).expect("restart events json");
        assert_eq!(restarted_events[0]["type"], "message_sent");
        assert_eq!(restarted_events[0]["metadata"]["topic_id"], "events");
    }

    #[tokio::test]
    async fn system_stream_fans_out_persisted_event_entries() {
        let db_path =
            std::env::temp_dir().join(format!("r3akt-rch-ws-events-{}.db", Uuid::new_v4()));
        let listener = TcpListener::bind("127.0.0.1:0").await.expect("bind");
        let addr = listener.local_addr().expect("addr");
        let state = crate::AppState::from_sqlite_path(&db_path)
            .expect("state")
            .with_api_key("secret");
        let server = tokio::spawn(async move {
            axum::serve(listener, crate::create_app_with_state(state))
                .await
                .expect("server");
        });

        let (mut system, _) = connect_async(format!("ws://{addr}/events/system"))
            .await
            .expect("system connect");
        system
            .send(Message::Text(
                json!({"type":"auth","data":{"api_key":"secret"}})
                    .to_string()
                    .into(),
            ))
            .await
            .expect("system auth");
        let _ = system.next().await.expect("system auth frame");
        system
            .send(Message::Text(
                json!({"type":"system.subscribe","data":{"include_status":false,"include_events":true,"events_limit":50}})
                    .to_string()
                    .into(),
            ))
            .await
            .expect("system subscribe");

        let (mut messages, _) = connect_async(format!("ws://{addr}/messages/stream"))
            .await
            .expect("message connect");
        messages
            .send(Message::Text(
                json!({"type":"auth","data":{"api_key":"secret"}})
                    .to_string()
                    .into(),
            ))
            .await
            .expect("message auth");
        let _ = messages.next().await.expect("message auth frame");
        messages
            .send(Message::Text(
                json!({"type":"message.send","data":{"content":"system fanout","topic_id":"ops"}})
                    .to_string()
                    .into(),
            ))
            .await
            .expect("message send");
        let sent_reply = messages
            .next()
            .await
            .expect("sent frame")
            .expect("sent reply");
        let sent_payload: serde_json::Value =
            serde_json::from_str(sent_reply.to_text().expect("sent text")).expect("sent json");
        assert_eq!(sent_payload["type"], "message.sent");

        let event_reply = system
            .next()
            .await
            .expect("event frame")
            .expect("event reply");
        let event_payload: serde_json::Value =
            serde_json::from_str(event_reply.to_text().expect("event text")).expect("event json");
        assert_eq!(event_payload["type"], "system.event");
        assert_eq!(event_payload["data"]["type"], "message_sent");
        assert_eq!(event_payload["data"]["metadata"]["topic_id"], "ops");

        drop(messages);
        drop(system);
        server.abort();

        let store = RchSqliteStore::open(&db_path).expect("open sqlite");
        let snapshot = store
            .load_snapshot()
            .expect("load snapshot")
            .expect("snapshot exists");
        assert_eq!(snapshot.system_events.len(), 1);
        assert_eq!(snapshot.system_events[0].event_type, "message_sent");
    }

