    #[tokio::test]
    async fn local_telemetry_sampler_records_time_snapshots() {
        let db_path = std::env::temp_dir().join(format!(
            "r3akt-rch-local-telemetry-sampler-{}.db",
            Uuid::new_v4()
        ));
        let state = crate::AppState::from_sqlite_path(&db_path).expect("state");

        let sampler = crate::spawn_local_telemetry_sampler_with_interval(
            state.clone(),
            "local-destination",
            Duration::from_millis(10),
        );
        tokio::time::sleep(Duration::from_millis(35)).await;
        sampler.abort();

        let records = state
            .telemetry_records
            .read()
            .expect("telemetry records")
            .clone();
        assert!(!records.is_empty());
        let record = records.last().expect("latest telemetry");
        assert_eq!(record.peer_destination, "local-destination");
        assert!(record.telemetry["time"]["timestamp"].as_i64().unwrap_or(0) > 0);
        assert!(record.telemetry["time"]["iso"].as_str().is_some());

        let restored = crate::AppState::from_sqlite_path(&db_path).expect("restored");
        assert!(
            !restored
                .telemetry_records
                .read()
                .expect("restored telemetry")
                .is_empty()
        );
    }

